/// Replay durable Fleet intents before the control listener accepts requests.
/// External effects are idempotent, and each handler verifies the exact persisted
/// operation identity again before committing its post-state.
pub fn recover_pending_fleet_operations(ctx: &ControlContext) {
    let pending = ctx.captains.snapshot().pending_fleet_operations;
    for operation in pending {
        match &operation.payload {
            PendingFleetOperationPayload::CloseTerminal { terminal_id, .. } => {
                if let Err(error) = close_terminal_with_policy(
                    ctx,
                    &json!({"sessionId": terminal_id, "force": true}),
                    false,
                    None,
                ) {
                    eprintln!(
                        "t-hub-fleet: pending close operation '{}' remains for retry: {error}",
                        operation.operation_id
                    );
                }
            }
            PendingFleetOperationPayload::CommissionCaptain {
                terminal_id,
                identity_id,
                ..
            } => {
                let _ = tmux::kill_session_tree(&tmux_target(terminal_id));
                if let Some(identity_id) = identity_id {
                    let _ = ctx.identity.retire(identity_id);
                }
                if let Err(error) = ctx
                    .captains
                    .abort_close_terminal_operation(&operation.operation_id)
                {
                    eprintln!(
                        "t-hub-fleet: pending commission operation '{}' remains for retry: {error}",
                        operation.operation_id
                    );
                }
            }
        }
    }
}

/// Reuse a resolved Powder profile across event polls. A profile command may
/// cross the Windows-to-WSL boundary to retrieve a credential, so rebuilding a
/// client every 15 seconds creates needless process churn. Entries expire to
/// observe healthy profile changes, and callers invalidate immediately after an
/// upstream or authorization failure so rotated credentials recover next poll.
#[cfg(test)]
struct TimedProfileCache<T> {
    entries: std::collections::HashMap<String, (Instant, T)>,
    ttl: Duration,
}

#[cfg(test)]
impl<T> TimedProfileCache<T> {
    fn new(ttl: Duration) -> Self {
        Self {
            entries: std::collections::HashMap::new(),
            ttl,
        }
    }

    fn get_or_try_insert_with<F>(
        &mut self,
        profile: &str,
        now: Instant,
        load: F,
    ) -> Result<&T, String>
    where
        F: FnOnce() -> Result<T, String>,
    {
        let expired = self
            .entries
            .get(profile)
            .is_some_and(|(loaded_at, _)| now.saturating_duration_since(*loaded_at) >= self.ttl);
        if expired {
            self.entries.remove(profile);
        }
        if !self.entries.contains_key(profile) {
            self.entries.insert(profile.to_string(), (now, load()?));
        }
        Ok(&self
            .entries
            .get(profile)
            .expect("profile was inserted before lookup")
            .1)
    }

    fn invalidate(&mut self, profile: &str) {
        self.entries.remove(profile);
    }
}

#[cfg(test)]
#[allow(dead_code)]
fn powder_event_poll_interval() -> Duration {
    let seconds = std::env::var("T_HUB_POWDER_EVENT_POLL_SECS")
        .ok()
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(15)
        .max(5);
    Duration::from_secs(seconds)
}

/// Reconcile trusted dispatch releases from their frozen original scope.
///
/// This intentionally never resolves a Crew Powder scope from the current
/// Captain or Project.  A release-reclaim ABA can replace that binding while the
/// original release response is ambiguous, and recovery must not touch the
/// replacement's profile or repository.
#[cfg(test)]
fn recover_pending_dispatch_release(
    ctx: &ControlContext,
    recovery: &PendingDispatchRelease,
) -> Result<(), String> {
    let _operation_guard = ctx.captains.serialize_crew_powder_operation(
        &recovery.crew_session_id,
        CrewPowderOperationKind::Cleanup,
    );
    let current = ctx
        .captains
        .pending_dispatch_release(&recovery.crew_session_id)
        .ok_or("the exact durable release recovery no longer exists")?;
    if current != *recovery {
        return Err("the exact durable release recovery changed while waiting for cleanup".into());
    }
    recover_pending_dispatch_release_guarded(ctx, &current)
}

#[cfg(test)]
fn ensure_recovery_terminal_gone(crew_session_id: &str) -> Result<(), String> {
    let target = tmux_target(crew_session_id);
    match tmux::session_liveness(&target) {
        tmux::SessionLiveness::Gone => Ok(()),
        tmux::SessionLiveness::Alive => {
            tmux::kill_session_tree(&target).map_err(|error| {
                format!("trusted release recovery could not stop Crew terminal '{crew_session_id}': {error}")
            })?;
            match tmux::session_liveness(&target) {
                tmux::SessionLiveness::Gone => Ok(()),
                tmux::SessionLiveness::Alive => Err(format!(
                    "trusted release recovery refuses Powder release while Crew terminal '{crew_session_id}' remains alive"
                )),
                tmux::SessionLiveness::Unknown => Err(format!(
                    "trusted release recovery cannot verify Crew terminal '{crew_session_id}' is gone"
                )),
            }
        }
        tmux::SessionLiveness::Unknown => Err(format!(
            "trusted release recovery cannot verify Crew terminal '{crew_session_id}' is gone"
        )),
    }
}

#[cfg(test)]
fn clear_confirmed_dispatch_release_and_retire(
    ctx: &ControlContext,
    recovery: &PendingDispatchRelease,
) -> Result<(), String> {
    commit_trusted_dispatch_cleanup(ctx, &recovery.crew_session_id, Some(recovery)).map_err(
        |error| {
            format!(
                "the exact durable release recovery could not remove its transaction-owned Crew binding: {error}"
            )
        },
    )?;
    let _ = captains_sync_apply(ctx);
    Ok(())
}

#[cfg(test)]
fn recover_pending_dispatch_release_guarded(
    ctx: &ControlContext,
    recovery: &PendingDispatchRelease,
) -> Result<(), String> {
    apply_pending_dispatch_release_effect_guarded(ctx, recovery)?;
    clear_confirmed_dispatch_release_and_retire(ctx, recovery)
}

#[cfg(test)]
fn apply_pending_dispatch_release_effect_guarded(
    ctx: &ControlContext,
    recovery: &PendingDispatchRelease,
) -> Result<(), String> {
    let mut durable_recovery = ctx
        .captains
        .pending_dispatch_release(&recovery.crew_session_id)
        .ok_or("the exact durable release recovery no longer exists")?;
    let client = powder::Client::from_profile(&recovery.connection_profile)?;
    if client.configured_agent() != recovery.agent {
        return Err("the frozen profile agent changed".into());
    }
    match client.verify_endpoint_identity(&recovery.connection_endpoint_identity) {
        Ok(()) => {}
        Err(powder::EndpointIdentityVerificationError::Mismatch) => {
            return Err("the frozen profile endpoint changed before release recovery".into());
        }
        Err(powder::EndpointIdentityVerificationError::MalformedIdentity) => {
            return Err(
                "the frozen profile endpoint identity is malformed before release recovery".into(),
            );
        }
        Err(powder::EndpointIdentityVerificationError::MissingCredential) => {
            return Err(
                "the frozen profile endpoint identity cannot be verified before release recovery"
                    .into(),
            );
        }
    }
    let mut expected_recovery = recovery.clone();
    expected_recovery.state = durable_recovery.state;
    if durable_recovery != expected_recovery {
        return Err("the exact durable release recovery changed before its external effect".into());
    }
    let repository = client
        .get_repository(&recovery.repository)
        .map_err(|error| format!("the frozen repository cannot be reconciled: {error}"))?;
    if repository.get("name").and_then(Value::as_str) != Some(recovery.repository.as_str()) {
        return Err("the frozen repository identity changed before release recovery".into());
    }
    let card = client
        .card_evidence(&recovery.card_id)
        .map_err(|error| format!("the frozen card cannot be reconciled: {error}"))?;
    if card.repository.as_deref() != Some(recovery.repository.as_str()) {
        return Err("the frozen card repository changed before release recovery".into());
    }
    let evidence = client
        .run_evidence(&recovery.run_id)
        .map_err(|error| format!("the exact release cannot be reconciled: {error}"))?;
    if evidence.repository.as_deref() != Some(recovery.repository.as_str())
        || evidence.run.card_id != recovery.card_id
        || evidence.run.agent != recovery.agent
    {
        return Err("the authoritative run identity changed before release recovery".into());
    }
    if evidence.run.state == "released" {
        if card.status != "ready" || card.claim.is_some() {
            return Err(
                "the released run does not have an exact ready card with no current claim".into(),
            );
        }
        ensure_recovery_terminal_gone(&recovery.crew_session_id)?;
        if durable_recovery.state == PendingDispatchReleaseState::Prepared {
            ctx.captains.transition_dispatch_release(
                &durable_recovery,
                PendingDispatchReleaseState::Prepared,
                PendingDispatchReleaseState::InFlight,
            )?;
            durable_recovery.state = PendingDispatchReleaseState::InFlight;
        }
        return Ok(());
    }
    if evidence.run.state != "active" {
        return Err(format!(
            "the authoritative run is '{}' rather than active or released",
            evidence.run.state
        ));
    }
    if !card
        .claim
        .as_ref()
        .is_some_and(|claim| claim.run_id == recovery.run_id && claim.agent == recovery.agent)
    {
        return Err("the active card claim no longer matches the exact release ownership".into());
    }
    ensure_recovery_terminal_gone(&recovery.crew_session_id)?;
    if durable_recovery.state == PendingDispatchReleaseState::Prepared {
        ctx.captains.transition_dispatch_release(
            &durable_recovery,
            PendingDispatchReleaseState::Prepared,
            PendingDispatchReleaseState::InFlight,
        )?;
        durable_recovery.state = PendingDispatchReleaseState::InFlight;
    }
    let claim = powder::Claim {
        card_id: recovery.card_id.clone(),
        run_id: recovery.run_id.clone(),
        agent: recovery.agent.clone(),
        expires_at: 0,
    };
    client.release(&claim)?;
    Ok(())
}

#[cfg(test)]
fn reconcile_pending_dispatch_releases(ctx: &ControlContext) {
    for recovery in ctx.captains.snapshot().pending_dispatch_releases {
        if ctx
            .captains
            .close_operation_owns_dispatch_release(&recovery)
        {
            if let Err(error) = close_terminal_with_policy(
                ctx,
                &json!({"sessionId": recovery.crew_session_id, "force": true}),
                false,
                None,
            ) {
                eprintln!(
                    "t-hub-control: Fleet-owned terminal close recovery for '{}' remains pending: {error}",
                    recovery.crew_session_id
                );
            }
            continue;
        }
        if let Err(error) = recover_pending_dispatch_release(ctx, &recovery) {
            eprintln!(
                "t-hub-control: trusted dispatch release recovery for '{}' remains pending: {error}",
                recovery.crew_session_id
            );
        }
    }
}

#[cfg(test)]
fn reconcile_powder_leases(ctx: &ControlContext) {
    reconcile_pending_dispatch_releases(ctx);
    let snapshot = ctx.captains.snapshot();
    let mut work = Vec::new();
    for captain in &snapshot.captains {
        let Some(project_id) = captain.project_id.as_deref() else {
            continue;
        };
        let Some(_binding) = snapshot
            .projects
            .iter()
            .find(|project| project.project_id == project_id)
            .and_then(|project| project.powder.as_ref())
        else {
            continue;
        };
        for crew in &captain.crew {
            if snapshot
                .pending_dispatch_releases
                .iter()
                .any(|recovery| recovery.crew_session_id == crew.terminal_id)
            {
                continue;
            }
            if !matches!(
                crew.state,
                CrewState::Active | CrewState::CleanupPending { .. }
            ) {
                continue;
            }
            if let Some(powder_work) = crew.powder_work.clone() {
                let Some(harness) = crew.harness.clone() else {
                    continue;
                };
                work.push((crew.terminal_id.clone(), harness, powder_work));
            }
        }
    }
    for (crew_session_id, harness, work) in work {
        let claim = powder::Claim {
            card_id: work.card_id,
            run_id: work.run_id,
            agent: String::new(),
            expires_at: work.claim_expires_at.unwrap_or_default(),
        };
        match tmux::harness_liveness(&tmux_target(&crew_session_id), &harness) {
            tmux::SessionLiveness::Alive => {
                if !matches!(work.state, PowderWorkState::Active) {
                    continue;
                }
                let result = renew_crew_powder_binding(ctx, &crew_session_id, Some(3600));
                match result {
                    Ok((renewed, _)) => {
                        ctx.fanout.emit_event(
                            "control://powder",
                            &json!({
                                "event": "claim-renewed",
                                "crewSessionId": crew_session_id,
                                "cardId": renewed.card_id,
                                "runId": renewed.run_id,
                                "expiresAt": renewed.expires_at,
                            }),
                        );
                    }
                    Err(error) => {
                        ctx.fanout.emit_event(
                            "control://powder",
                            &json!({
                                "event": "claim-renew-failed",
                                "crewSessionId": crew_session_id,
                                "cardId": claim.card_id,
                                "runId": claim.run_id,
                                "error": error,
                            }),
                        );
                    }
                }
            }
            tmux::SessionLiveness::Gone => {
                let cleanup = finalize_crew_powder_cleanup(ctx, &crew_session_id, false);
                let (release, released, error) = match cleanup {
                    Ok((release, _, _)) => {
                        let released = release
                            .as_ref()
                            .is_some_and(|value| value["released"].as_bool() == Some(true));
                        let error = release
                            .as_ref()
                            .and_then(|value| value["error"].as_str())
                            .map(str::to_string);
                        (release, released, error)
                    }
                    Err(error) => {
                        eprintln!(
                            "t-hub-control: dead Crew registry reconciliation failed for \
                             '{crew_session_id}': {error}"
                        );
                        (None, false, Some(error))
                    }
                };
                let _ = captains_sync_apply(ctx);
                ctx.fanout.emit_event(
                    "control://powder",
                    &json!({
                        "event": "dead-crew-reconciled",
                        "crewSessionId": crew_session_id,
                        "cardId": claim.card_id,
                        "runId": claim.run_id,
                        "released": released,
                        "error": error,
                        "powderRelease": release,
                    }),
                );
            }
            tmux::SessionLiveness::Unknown => {}
        }
    }
}

#[cfg(test)]
#[allow(dead_code)]
fn reconcile_powder_events(ctx: &ControlContext, clients: &mut TimedProfileCache<powder::Client>) {
    let snapshot = ctx.captains.snapshot();
    for project in &snapshot.projects {
        let Some(binding) = project.powder.as_ref() else {
            continue;
        };
        let captain = snapshot.captains.iter().find(|captain| {
            captain.project_id.as_deref() == Some(&project.project_id)
                && matches!(captain.state, ClaimState::Active)
                && captain.terminal_id.is_some()
        });
        let client = match clients.get_or_try_insert_with(
            &binding.connection_profile,
            Instant::now(),
            || powder::Client::from_profile(&binding.connection_profile),
        ) {
            Ok(client) => client,
            Err(error) => {
                emit_powder_event_sync_error(ctx, project, error);
                continue;
            }
        };
        let events = match client.tail_events(binding.event_cursor, 1000) {
            Ok(events) => events,
            Err(error) => {
                clients.invalidate(&binding.connection_profile);
                emit_powder_event_sync_error(ctx, project, error);
                continue;
            }
        };
        let cursor = apply_powder_events(ctx, project, binding, captain, &events);
        if cursor > binding.event_cursor {
            if let Err(error) = ctx.captains.advance_project_powder_cursor(
                &project.project_id,
                &binding.connection_profile,
                &binding.repository,
                cursor,
            ) {
                emit_powder_event_sync_error(ctx, project, error);
            }
        }
    }
}

#[allow(dead_code)]
fn apply_powder_events(
    ctx: &ControlContext,
    project: &ProjectRecord,
    binding: &PowderProjectBinding,
    captain: Option<&CaptainRecord>,
    events: &[powder::CardEvent],
) -> i64 {
    let mut cursor = binding.event_cursor;
    for event in events {
        if event.repository.as_deref() != Some(binding.repository.as_str()) {
            cursor = event.sequence;
            continue;
        }
        let Some(captain) = captain else {
            break;
        };
        let Some(captain_session_id) = captain.terminal_id.as_deref() else {
            break;
        };
        let recipient = format!("ship:{}", captain.ship_slug);
        let body = format!(
            "Powder event '{}' ({}) for card '{}' - {}. Status: '{}'. Re-read the authoritative card and update the durable Captain resume point before acting.",
            event.event_type,
            event.event_id,
            event.card_id,
            event.card_title,
            event.card_status,
        );
        if let Err(error) = ctx.inbox.enqueue(
            &recipient,
            &format!("powder:{}", binding.repository),
            crate::inbox::Priority::Standard,
            &body,
            true,
        ) {
            ctx.fanout.emit_event(
                "control://powder",
                &json!({
                    "event": "event-delivery-failed",
                    "projectId": project.project_id,
                    "captainSessionId": captain_session_id,
                    "shipSlug": captain.ship_slug,
                    "powderEventId": event.event_id,
                    "error": error.to_string(),
                }),
            );
            break;
        }
        ctx.fanout.emit_event(
            "control://powder",
            &json!({
                "event": "card-event",
                "projectId": project.project_id,
                "repository": binding.repository,
                "captainSessionId": captain_session_id,
                "shipSlug": captain.ship_slug,
                "sequence": event.sequence,
                "powderEventId": event.event_id,
                "eventType": event.event_type,
                "occurredAt": event.occurred_at,
                "cardId": event.card_id,
                "cardTitle": event.card_title,
                "cardStatus": event.card_status,
                "change": event.change,
            }),
        );
        cursor = event.sequence;
    }
    cursor
}

#[cfg(test)]
#[allow(dead_code)]
fn emit_powder_event_sync_error(ctx: &ControlContext, project: &ProjectRecord, error: String) {
    ctx.fanout.emit_event(
        "control://powder",
        &json!({
            "event": "event-sync-failed",
            "projectId": project.project_id,
            "error": error,
        }),
    );
}

/// `report_workspace_tabs` (T12 / headless-org): a UI client up-syncs its live tab
/// layout - the control-socket twin of the Tauri command of the same name (the
/// native cockpit is a socket client and cannot call Tauri). Consistency model
/// (headless-org): the SERVER registry is authoritative; a report carrying
/// `baseSeq` is accepted only when it matches the current revision, otherwise it
/// is rejected as stale and answered with the authoritative snapshot so the
/// reporter converges instead of clobbering a server-side mutation it has not
/// applied yet. A report WITHOUT `baseSeq` (legacy reporter) is accepted
/// unconditionally. Args: `tabs`: `[{id, name, tileIds}]`; `activeTabId`
/// (optional); `baseSeq` (optional).
fn report_workspace_tabs(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    if !matches!(
        workspace_mutation_authority(ctx, caller, trusted_internal, "report_workspace_tabs")?,
        WorkspaceMutationAuthority::Apex
    ) {
        return Err(
            "acl: report_workspace_tabs is a full-layout mutation restricted to General/Cortana or the trusted host"
                .into(),
        );
    }
    let tabs: Vec<TabRecord> = serde_json::from_value(
        args.get("tabs")
            .cloned()
            .ok_or("report_workspace_tabs requires a 'tabs' array")?,
    )
    .map_err(|e| format!("report_workspace_tabs: bad 'tabs' shape: {e}"))?;
    let count = tabs.len();
    let active = arg_str(args, "activeTabId").or_else(|| arg_str(args, "active_tab_id"));
    let base_seq = args
        .get("baseSeq")
        .or_else(|| args.get("base_seq"))
        .and_then(|v| v.as_u64());

    match apply_workspace_report(&ctx.tabs, &ctx.captains, tabs, active, base_seq)? {
        (ReportOutcome::Accepted { seq, .. }, captains_changed, reconciled) => {
            if captains_changed {
                let _ = captains_sync_apply(ctx);
            }
            let snapshot = ctx.tabs.snapshot_full();
            Ok(json!({
                "reported": count,
                "seq": seq,
                "stale": reconciled,
                "activeTabId": reconciled.then_some(snapshot.active_tab_id).flatten(),
                "tabs": reconciled.then_some(snapshot.tabs),
            }))
        }
        (ReportOutcome::Stale(snapshot), _, _) => Ok(json!({
            "stale": true,
            "seq": snapshot.seq,
            "activeTabId": snapshot.active_tab_id,
            "tabs": snapshot.tabs,
            "note": "report based on a stale revision; adopt the returned snapshot \
                     and re-report on the next local change.",
        })),
    }
}

/// `read_terminal` / `capture_pane`: return a session's recent visible output as
/// plain text so an external Claude can SEE what the session shows. Talks to tmux
/// directly (`tmux -L t-hub capture-pane -p [-S -N] -t th_<id>`), no UI round
/// trip. Args: `sessionId` (required), `historyLines` (optional, default 0 =
/// visible screen only; clamped to keep responses bounded).
/// Comms-plane Phase 2: `inbox_ack` - the recipient confirms intake of a delivered
/// inbox message (`delivered -> processed`, §2.4 M2). `sessionId` is the recipient's
/// own tile id (the inbox key the wake enqueued under); `seq` the message. The ACK is
/// idempotent + safe: a lost or duplicate ack never triggers a re-write, and acking
/// before delivery / an unknown seq is reported honestly rather than silently
/// advancing state. Phase 2 does NOT authorize the caller (no ACLs) - Phase 3's
/// ownership ACL gates a cross-session ack.
fn inbox_ack(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "inbox_ack")?;
    let recipient = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("inbox_ack requires a 'sessionId' argument")?;
    let seq = args
        .get("seq")
        .and_then(|v| v.as_u64())
        .ok_or("inbox_ack requires a numeric 'seq' argument")?;
    // Phase 3 (§2.4.1): the ownership ACL. A session self-acks ONLY its OWN inbox (its
    // tile == the recipient key); a control-capable HOST/RELAY (Full) may ack on behalf
    // (the interim relay path, still supported). A read-token session acking a DIFFERENT
    // recipient is refused - the cross-session spoof the interim Organization gate feared
    // is closed by the per-session identity, not re-opened.
    // A session identity that is NOT the recipient itself may only ack with the control
    // capability does not override self-scope; only a proven in-process host may ack
    // without a session identity.
    if let Some(id) = caller {
        if let Err(d) = crate::acl::can_ack(&acl_actor(id), &recipient) {
            ctx.fanout.emit_event(
                "control://acl",
                &json!({
                    "cell": "inbox-ack-self-scope",
                    "decision": "refused",
                    "session": id.session_id.as_str(),
                    "recipient": recipient.as_str(),
                    "reason": d.reason.as_str(),
                }),
            );
            return Err(format!("acl: {}", d.reason));
        }
    }
    let outcome = ctx.inbox.ack(&recipient, seq);
    let state = match outcome {
        crate::inbox::AckOutcome::Processed { .. } => "processed",
        crate::inbox::AckOutcome::AlreadyProcessed { .. } => "alreadyProcessed",
        crate::inbox::AckOutcome::NotDelivered { .. } => "notDelivered",
        crate::inbox::AckOutcome::Unknown { .. } => "unknown",
    };
    Ok(json!({
        "accepted": "inbox_ack",
        "sessionId": recipient,
        "seq": seq,
        "state": state,
    }))
}

/// Comms-plane Phase 2: `inbox_status` - per-recipient observability (§2.8). With a
/// `sessionId` it returns that recipient's depth snapshot; without one, every
/// recipient's. Counts + cursors + oldest-un-drained age only, never message content.
fn inbox_status(ctx: &ControlContext, args: &Value) -> Result<Value, String> {
    if let Some(recipient) = arg_str(args, "sessionId").or_else(|| arg_str(args, "session_id")) {
        Ok(json!({ "recipient": ctx.inbox.depth(&recipient) }))
    } else {
        Ok(json!({ "recipients": ctx.inbox.depth_all() }))
    }
}

/// The attributed `sender` label for a plane message from a resolved identity: the same
/// `role:id` shape `identity::SessionIdentity::sender_label` produces, so the inbox's
/// attribution stamp is per-session (not the coarse tier). A host (no session) stamps
/// the coarse source label.
fn caller_sender_label(caller: Option<&ResolvedIdentity>) -> String {
    match caller {
        Some(id) => format!("{}:{}", acl_actor(id).role.label(), id.session_id),
        None => "control-host".to_string(),
    }
}

/// Parse the requested plane priority. Absent / `"standard"` => Standard; `"emergency"`
/// => Emergency (the authority to actually SET it is checked separately by
/// [`crate::acl::can_flag_emergency`] - the field is a REQUEST, the role is the grant).
fn parse_priority(args: &Value) -> Result<crate::inbox::Priority, String> {
    match arg_str(args, "priority").as_deref() {
        None | Some("standard") | Some("Standard") => Ok(crate::inbox::Priority::Standard),
        Some("emergency") | Some("Emergency") => Ok(crate::inbox::Priority::Emergency),
        Some(other) => Err(format!(
            "plane_send: unknown priority '{other}' (expected 'standard' or 'emergency')"
        )),
    }
}

/// Comms-plane Phase 3: the agent-to-agent plane SEND. Enforces the settled matrix
/// message rows (`can_message`) at enqueue time and the EMERGENCY-flag authority
/// (`can_flag_emergency`), then enqueues a durable, attributed message. A denied send is
/// REFUSED + attributed on `control://acl`, never a silent drop. An identified session is
/// REQUIRED (or a proven in-process host) - a token with no session cannot
/// enqueue as anyone.
fn plane_send(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "plane_send")?;
    let recipient = arg_str(args, "recipient")
        .or_else(|| arg_str(args, "sessionId"))
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("plane_send requires a 'recipient' (recipient tile id) argument")?;
    let body = arg_str(args, "text")
        .or_else(|| arg_str(args, "body"))
        .ok_or("plane_send requires a 'text' argument")?;
    let enter = args.get("enter").and_then(|v| v.as_bool()).unwrap_or(true);
    let priority = parse_priority(args)?;

    let refuse = |ctx: &ControlContext, cell: &str, who: &str, reason: &str| -> String {
        ctx.fanout.emit_event(
            "control://acl",
            &json!({
                "cell": cell,
                "decision": "refused",
                "session": who,
                "recipient": recipient.as_str(),
                "reason": reason,
            }),
        );
        format!("acl: {reason}")
    };

    if let Some(id) = caller {
        let actor = acl_actor(id);
        let target = message_target(ctx, &recipient);
        if let Err(d) = crate::acl::can_message(&actor, &target) {
            return Err(refuse(ctx, "message-send", &actor.session_id, &d.reason));
        }
        if priority == crate::inbox::Priority::Emergency {
            if let Err(d) = crate::acl::can_flag_emergency(&actor) {
                return Err(refuse(ctx, "emergency-flag", &actor.session_id, &d.reason));
            }
        }
    }

    let sender = caller_sender_label(caller);
    match ctx
        .inbox
        .enqueue(&recipient, &sender, priority, &body, enter)
    {
        Ok(outcome) => Ok(json!({
            "accepted": "plane_send",
            "recipient": recipient,
            "seq": outcome.seq,
            "priority": priority,
            "sender": sender,
        })),
        Err(e) => Err(e.to_string()),
    }
}

/// Comms-plane Phase 3: the ABORT/interrupt-subordinate primitive. Delivers an Escape
/// interrupt (the claude turn-interrupt; the Escape/C-c equivalent) to the target's
/// runtime - a preempt signal, NOT a queued input message, so it cannot be typed over or
/// corrupt a human draft. Gated by `can_abort`; an identified caller must own the target
/// (Cortana->captain, captain->own crew, general->anyone), cross-ship/sibling is DENIED,
/// and crew have no subordinate to abort. A proven in-process host acts as the apex.
fn abort_session(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "abort_session")?;
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .or_else(|| arg_str(args, "target"))
        .ok_or("abort_session requires a 'sessionId' (target tile id) argument")?;

    if let Some(id) = caller {
        let actor = acl_actor(id);
        let target = target_ship_ref(ctx, &session_id);
        if let Err(d) = crate::acl::can_abort(&actor, &target) {
            ctx.fanout.emit_event(
                "control://acl",
                &json!({
                    "cell": "abort",
                    "decision": "refused",
                    "session": actor.session_id.as_str(),
                    "role": actor.role.label(),
                    "target": session_id.as_str(),
                    "reason": d.reason.as_str(),
                }),
            );
            return Err(format!("acl: {}", d.reason));
        }
    }
    // A caller without a session identity reached this point only with in-process host proof.

    let target = tmux_target(&session_id);
    writer_liveness_gate(
        "abort_session",
        &session_id,
        &target,
        tmux::session_liveness(&target),
    )?;
    // Escape interrupts the current turn (claude's in-turn interrupt) WITHOUT killing the
    // session or its in-flight state - the C4-safe abort the design calls for.
    tmux::send_keys(&target, &["Escape"])
        .map_err(|e| format!("failed to deliver abort interrupt to '{session_id}': {e}"))?;
    Ok(json!({
        "accepted": "abort_session",
        "sessionId": session_id,
        "target": target,
        "signal": "Escape",
        "audited": true,
    }))
}

/// Comms-plane Phase 3: record a durable general-authorization artifact (the delegation-
/// gate carrier, M1). Only the GENERAL may ORIGINATE (`can_originate_authorization`);
/// Cortana may relay by reference but never originate. The origin is APP-STAMPED from the
/// resolved identity's role (never sender-supplied), so a captain/crew with a Full token
/// but a non-general session cannot forge a general authorization.
fn authorize(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
) -> Result<Value, String> {
    let Some(id) = caller else {
        return Err(
            "authorize requires a per-session identity resolving to the GENERAL role \
             (only the general originates an authorization)"
                .to_string(),
        );
    };
    let actor = acl_actor(id);
    if let Err(d) = crate::acl::can_originate_authorization(&actor) {
        ctx.fanout.emit_event(
            "control://acl",
            &json!({
                "cell": "authorization-originate",
                "decision": "refused",
                "session": actor.session_id.as_str(),
                "role": actor.role.label(),
                "reason": d.reason.as_str(),
            }),
        );
        return Err(format!("acl: {}", d.reason));
    }
    let action = arg_str(args, "action")
        .ok_or("authorize requires an 'action' (the authorized scope, e.g. 'spend'/'publish')")?;
    let target_ship = arg_str(args, "targetShip").or_else(|| arg_str(args, "target_ship"));
    // Origin role is app-stamped GENERAL (the ACL above proved it); origin_session is the
    // unforgeable attribution root. Direct authorization => no relay reference.
    let auth = ctx.authz.record(
        crate::authz::ORIGIN_GENERAL,
        &actor.session_id,
        &action,
        target_ship,
        None,
    );
    Ok(json!({
        "accepted": "authorize",
        "id": auth.id,
        "action": auth.action,
        "targetShip": auth.target_ship,
    }))
}

/// Comms-plane Phase 3: the resolve-and-verify GATE a captain's money/publish gate
/// consults (`general_authorization_present`). Resolves the referenced artifact by id and
/// verifies its app-stamped origin == general, it is not revoked, and (under STATE 2) it
/// is not a relayed reference. Read-only.
fn check_authorization(ctx: &ControlContext, args: &Value) -> Result<Value, String> {
    let id = arg_str(args, "id")
        .or_else(|| arg_str(args, "authorizationId"))
        .ok_or("check_authorization requires an 'id' (the authorization reference)")?;
    let verdict = ctx
        .authz
        .present(&id, crate::authz::accept_relayed_authorization());
    Ok(json!({
        "id": id,
        "present": verdict.is_present(),
        "verdict": verdict.label(),
    }))
}

fn stable_supervisor_generation(parts: &[&str]) -> u64 {
    use sha2::{Digest, Sha256};
    let mut hasher = Sha256::new();
    for part in parts {
        hasher.update((part.len() as u64).to_be_bytes());
        hasher.update(part.as_bytes());
    }
    let digest = hasher.finalize();
    u64::from_be_bytes(
        digest[..8]
            .try_into()
            .expect("SHA-256 prefix is eight bytes"),
    )
    .max(1)
}

fn supervisor_authority_for_caller(
    ctx: &ControlContext,
    caller: &ResolvedIdentity,
) -> Result<crate::delegated_admin::SupervisorAuthority, String> {
    match caller.fleet_role {
        Some(FleetRole::Cortana) => {
            let durable = ctx.captains.cortana_identity();
            let authoritative = ctx
                .identity
                .get(&caller.session_id)
                .is_some_and(|identity| authoritative_cortana_identity(ctx, &identity));
            if !authoritative || durable.identity_id.as_deref() != Some(caller.session_id.as_str())
            {
                return Err("delegated admin: caller is not the durable Cortana identity".into());
            }
            Ok(crate::delegated_admin::SupervisorAuthority {
                identity_id: caller.session_id.clone(),
                role: crate::delegated_admin::DelegatingSupervisorRole::Cortana,
                ship_slug: None,
                authority_generation: durable.generation,
                active: true,
            })
        }
        Some(FleetRole::Captain) => {
            let tile = caller
                .tile
                .as_deref()
                .ok_or("delegated admin: Captain identity has no terminal")?;
            let captain = ctx
                .captains
                .captain_for_session(tile)
                .filter(|captain| captain.role == FleetRole::Captain)
                .ok_or("delegated admin: caller is not an active Captain")?;
            Ok(crate::delegated_admin::SupervisorAuthority {
                identity_id: caller.session_id.clone(),
                role: crate::delegated_admin::DelegatingSupervisorRole::Captain,
                ship_slug: Some(captain.ship_slug.clone()),
                authority_generation: stable_supervisor_generation(&[
                    &captain.assignment_id,
                    &captain.ship_slug,
                ]),
                active: captain.state == ClaimState::Active,
            })
        }
        None => Err("delegated admin: only Cortana or a Captain may grant roles".into()),
    }
}

fn current_delegating_supervisor(
    ctx: &ControlContext,
    grant: &crate::delegated_admin::DelegatedAdminGrant,
) -> crate::delegated_admin::SupervisorAuthority {
    match grant.delegator.role {
        crate::delegated_admin::DelegatingSupervisorRole::Cortana => {
            let durable = ctx.captains.cortana_identity();
            let active = durable
                .identity_id
                .as_deref()
                .and_then(|identity_id| ctx.identity.get(identity_id))
                .is_some_and(|identity| authoritative_cortana_identity(ctx, &identity));
            crate::delegated_admin::SupervisorAuthority {
                identity_id: durable
                    .identity_id
                    .unwrap_or_else(|| grant.delegator.identity_id.clone()),
                role: crate::delegated_admin::DelegatingSupervisorRole::Cortana,
                ship_slug: None,
                authority_generation: durable.generation,
                active,
            }
        }
        crate::delegated_admin::DelegatingSupervisorRole::Captain => {
            let captain = grant.delegator.ship_slug.as_deref().and_then(|ship_slug| {
                let matches = ctx
                    .captains
                    .snapshot()
                    .captains
                    .into_iter()
                    .filter(|captain| {
                        captain.role == FleetRole::Captain && captain.ship_slug == ship_slug
                    })
                    .collect::<Vec<_>>();
                (matches.len() == 1).then(|| matches.into_iter().next().unwrap())
            });
            let current_identity = captain
                .as_ref()
                .and_then(|captain| captain.terminal_id.as_deref())
                .and_then(|terminal_id| ctx.identity.for_tile(terminal_id));
            let authority_generation = captain
                .as_ref()
                .map(|captain| {
                    stable_supervisor_generation(&[&captain.assignment_id, &captain.ship_slug])
                })
                .unwrap_or_default();
            crate::delegated_admin::SupervisorAuthority {
                identity_id: current_identity
                    .map(|identity| identity.id)
                    .unwrap_or_else(|| grant.delegator.identity_id.clone()),
                role: crate::delegated_admin::DelegatingSupervisorRole::Captain,
                ship_slug: grant.delegator.ship_slug.clone(),
                authority_generation,
                active: captain
                    .as_ref()
                    .is_some_and(|captain| captain.state == ClaimState::Active),
            }
        }
    }
}

fn current_admin_actor_for_identity(
    ctx: &ControlContext,
    actor_identity_id: &str,
) -> crate::delegated_admin::AdminActor {
    let identity = ctx.identity.get(actor_identity_id);
    let session_tile = identity
        .as_ref()
        .and_then(|identity| identity.session_tile.clone());
    let memberships = session_tile
        .as_deref()
        .map(|terminal_id| {
            ctx.captains
                .snapshot()
                .captains
                .into_iter()
                .filter(|captain| {
                    captain.state == ClaimState::Active
                        && captain.crew.iter().any(|crew| {
                            crew.terminal_id == terminal_id
                                && matches!(crew.state, CrewState::Active)
                        })
                })
                .map(|captain| captain.ship_slug)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let current_ship_slug = match memberships.as_slice() {
        [ship_slug] => Some(ship_slug.clone()),
        _ => None,
    };
    let is_current_crew = identity.as_ref().is_some_and(|identity| {
        identity.role == crate::identity::Role::Crew
            && !ctx.identity.is_revoked(&identity.id)
            && memberships.len() == 1
    });
    let runtime_active = session_tile.as_deref().is_some_and(|terminal_id| {
        tmux::session_liveness(&tmux_target(terminal_id)) == tmux::SessionLiveness::Alive
    });
    crate::delegated_admin::AdminActor {
        identity_id: actor_identity_id.to_string(),
        session_tile,
        current_ship_slug,
        is_current_crew,
        runtime_active,
    }
}

fn current_admin_actor(
    ctx: &ControlContext,
    grant: &crate::delegated_admin::DelegatedAdminGrant,
) -> crate::delegated_admin::AdminActor {
    current_admin_actor_for_identity(ctx, &grant.actor_identity_id)
}

fn parse_admin_role(value: &str) -> Result<crate::delegated_admin::DelegatedAdminRole, String> {
    match value.trim().to_ascii_lowercase().as_str() {
        "shipadmin" | "ship-admin" | "ship_admin" => {
            Ok(crate::delegated_admin::DelegatedAdminRole::ShipAdmin)
        }
        "fleetadmin" | "fleet-admin" | "fleet_admin" => {
            Ok(crate::delegated_admin::DelegatedAdminRole::FleetAdmin)
        }
        _ => Err("appoint_admin role must be 'shipAdmin' or 'fleetAdmin'".into()),
    }
}

fn parse_admin_operations(
    args: &Value,
) -> Result<std::collections::BTreeSet<crate::delegated_admin::AdminOperation>, String> {
    let values = args
        .get("permittedOperations")
        .or_else(|| args.get("permitted_operations"))
        .and_then(Value::as_array)
        .ok_or("appoint_admin requires a permittedOperations array")?;
    values
        .iter()
        .map(|value| {
            serde_json::from_value(value.clone()).map_err(|error| {
                format!("appoint_admin contains an unknown permitted operation: {error}")
            })
        })
        .collect()
}

fn appoint_admin(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    // Hold the registry's common mutation transaction across authority
    // validation and grant commit.  Captain/Cortana claim or promotion cannot
    // interleave between these two steps and invalidate the decision.
    let _authorization_transaction = ctx.tabs.identity_transaction();
    require_exact_args(
        args,
        "appoint_admin",
        &["actorSessionId", "role", "permittedOperations"],
    )?;
    require_socket_identity(caller, trusted_internal, "appoint_admin")?;
    let caller = caller.ok_or("appoint_admin requires a supervisor session identity")?;
    if ctx
        .delegated_admin
        .grants_for_actor(&caller.session_id)
        .iter()
        .any(|grant| grant.state.is_active())
    {
        return Err("appoint_admin: delegated administrators cannot re-delegate authority".into());
    }
    let supervisor = supervisor_authority_for_caller(ctx, caller)?;
    if !supervisor.active {
        return Err("appoint_admin requires an active supervisor".into());
    }
    if supervisor.role == crate::delegated_admin::DelegatingSupervisorRole::Cortana
        && !matches!(
            ctx.captains.snapshot().cortana.recovery,
            crate::cortana_reconcile::CortanaRecoveryState::Healthy { .. }
        )
    {
        return Err("appoint_admin requires Cortana recovery to be healthy".into());
    }
    let actor_session_id = arg_str(args, "actorSessionId")
        .or_else(|| arg_str(args, "actor_session_id"))
        .ok_or("appoint_admin requires an actorSessionId")?;
    let actor = ctx
        .identity
        .for_tile(&actor_session_id)
        .ok_or_else(|| format!("appoint_admin cannot resolve Crew '{actor_session_id}'"))?;
    if actor.role != crate::identity::Role::Crew {
        return Err("appoint_admin may appoint only a Crew identity".into());
    }
    let actor_authority = current_admin_actor_for_identity(ctx, &actor.id);
    if !actor_authority.is_current_crew || !actor_authority.runtime_active {
        return Err("appoint_admin requires one live, authoritative Crew membership".into());
    }
    let role = parse_admin_role(&arg_str(args, "role").ok_or("appoint_admin requires a role")?)?;
    let scope = match role {
        crate::delegated_admin::DelegatedAdminRole::ShipAdmin => {
            if supervisor.role != crate::delegated_admin::DelegatingSupervisorRole::Captain {
                return Err("appoint_admin Ship Admin requires the owning Captain".into());
            }
            let ship_slug = supervisor
                .ship_slug
                .clone()
                .ok_or("appoint_admin Captain has no ship scope")?;
            let actor_is_crew = ctx.captains.snapshot().captains.iter().any(|captain| {
                captain.ship_slug == ship_slug
                    && captain
                        .crew
                        .iter()
                        .any(|crew| crew.terminal_id == actor_session_id)
            });
            if !actor_is_crew {
                return Err(format!(
                    "appoint_admin Crew '{actor_session_id}' is not owned by ship '{ship_slug}'"
                ));
            }
            if actor_authority.current_ship_slug.as_deref() != Some(ship_slug.as_str()) {
                return Err(format!(
                    "appoint_admin Crew '{actor_session_id}' does not have one active membership in ship '{ship_slug}'"
                ));
            }
            crate::delegated_admin::AdminScope::Ship { ship_slug }
        }
        crate::delegated_admin::DelegatedAdminRole::FleetAdmin => {
            if supervisor.role != crate::delegated_admin::DelegatingSupervisorRole::Cortana {
                return Err("appoint_admin Fleet Admin requires Cortana".into());
            }
            crate::delegated_admin::AdminScope::Fleet
        }
    };
    let grant = ctx
        .delegated_admin
        .appoint(crate::delegated_admin::AppointmentRequest {
            actor_identity_id: actor.id,
            role,
            delegator: supervisor,
            scope,
            permitted_operations: parse_admin_operations(args)?,
        })
        .map_err(|error| format!("{}: {error}", error.code()))?;
    Ok(json!({
        "accepted": "appoint_admin",
        "grant": grant,
        "audited": true,
    }))
}

fn revoke_admin(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_exact_args(args, "revoke_admin", &["grantId", "reason"])?;
    require_socket_identity(caller, trusted_internal, "revoke_admin")?;
    let caller = caller.ok_or("revoke_admin requires a supervisor session identity")?;
    let supervisor = supervisor_authority_for_caller(ctx, caller)?;
    let grant_id = arg_str(args, "grantId")
        .or_else(|| arg_str(args, "grant_id"))
        .ok_or("revoke_admin requires a grantId")?;
    let grant = ctx
        .delegated_admin
        .revoke(&grant_id, &supervisor, arg_str(args, "reason"))
        .map_err(|error| format!("{}: {error}", error.code()))?;
    Ok(json!({
        "accepted": "revoke_admin",
        "grant": grant,
        "audited": true,
    }))
}

fn approve_admin_action(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_exact_args(
        args,
        "approve_admin_action",
        &["grantId", "operation", "sessionId", "target"],
    )?;
    require_socket_identity(caller, trusted_internal, "approve_admin_action")?;
    let caller = caller.ok_or("approve_admin_action requires a supervisor session identity")?;
    let supervisor = supervisor_authority_for_caller(ctx, caller)?;
    if !supervisor.active {
        return Err("approve_admin_action requires an active supervisor".into());
    }
    let grant_id = arg_str(args, "grantId")
        .filter(|grant_id| !grant_id.trim().is_empty())
        .ok_or("approve_admin_action requires a non-empty grantId")?;
    let operation = serde_json::from_value::<crate::delegated_admin::AdminOperation>(
        args.get("operation")
            .cloned()
            .ok_or("approve_admin_action requires an operation")?,
    )
    .map_err(|error| format!("approve_admin_action operation is invalid: {error}"))?;
    let target = match operation {
        crate::delegated_admin::AdminOperation::CleanupSession => {
            if args.get("target").is_some() {
                return Err(
                    "approve_admin_action cleanupSession accepts sessionId only; target kind and ownership are resolved authoritatively"
                        .into(),
                );
            }
            let session_id = arg_str(args, "sessionId")
                .filter(|session_id| !session_id.trim().is_empty())
                .ok_or("approve_admin_action cleanupSession requires a non-empty sessionId")?;
            delegated_admin_target_for_terminal(ctx, &session_id)?
        }
        crate::delegated_admin::AdminOperation::CleanupWorktree => {
            if args.get("sessionId").is_some() {
                return Err(
                    "approve_admin_action cleanupWorktree accepts an exact worktree target only"
                        .into(),
                );
            }
            let target = serde_json::from_value::<crate::delegated_admin::AdminTarget>(
                args.get("target")
                    .cloned()
                    .ok_or("approve_admin_action cleanupWorktree requires a target")?,
            )
            .map_err(|error| format!("approve_admin_action target is invalid: {error}"))?;
            if !matches!(target, crate::delegated_admin::AdminTarget::Worktree { .. }) {
                return Err(
                    "approve_admin_action cleanupWorktree requires a worktree target".into(),
                );
            }
            target
        }
        _ => {
            return Err(
                "approve_admin_action supports only cleanupSession or cleanupWorktree".into(),
            );
        }
    };
    let approval = ctx
        .delegated_admin
        .get(&grant_id)
        .ok_or_else(|| format!("grantNotFound: grant '{grant_id}' was not found"))?;
    let actor = current_admin_actor(ctx, &approval);
    let approval = ctx
        .delegated_admin
        .issue_exact_approval(&grant_id, &actor, &supervisor, operation, &target)
        .map_err(|error| format!("{}: {error}", error.code()))?;
    Ok(json!({
        "accepted": "approve_admin_action",
        "approval": approval,
        "audited": true,
    }))
}

fn list_admin_grants(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let grants = if let Some(caller) = caller {
        if caller.fleet_role.is_some() {
            ctx.delegated_admin.grants_delegated_by(&caller.session_id)
        } else {
            ctx.delegated_admin.grants_for_actor(&caller.session_id)
        }
    } else if trusted_internal {
        let actor_identity_id = arg_str(args, "actorIdentityId")
            .or_else(|| arg_str(args, "actor_identity_id"))
            .ok_or("list_admin_grants trusted host requires actorIdentityId")?;
        ctx.delegated_admin.grants_for_actor(&actor_identity_id)
    } else {
        return Err("list_admin_grants requires a session identity".into());
    };
    Ok(json!({
        "count": grants.len(),
        "grants": grants,
    }))
}

#[derive(Debug, Clone, Deserialize)]
#[serde(tag = "kind", rename_all = "camelCase", deny_unknown_fields)]
enum AdminExecutionTargetInput {
    Fleet,
    Ship {
        #[serde(rename = "shipSlug")]
        ship_slug: String,
    },
    Session {
        #[serde(rename = "sessionId")]
        session_id: String,
    },
    Worktree {
        path: String,
    },
    GeneralReserved {
        action: String,
    },
    Implementation {
        #[serde(rename = "shipSlug")]
        ship_slug: String,
        #[serde(rename = "assignmentId")]
        assignment_id: String,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum AdminExecutionResource {
    Fleet,
    Ship(String),
    Session(String),
    Worktree(String),
    Forbidden,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ResolvedAdminExecutionTarget {
    authorization_target: crate::delegated_admin::AdminTarget,
    resource: AdminExecutionResource,
}

fn exact_active_captain_for_ship(
    ctx: &ControlContext,
    ship_slug: &str,
) -> Result<CaptainRecord, String> {
    if ship_slug.trim().is_empty() {
        return Err("execute_admin_operation shipSlug must not be empty".into());
    }
    let matching = ctx
        .captains
        .snapshot()
        .captains
        .into_iter()
        .filter(|captain| {
            captain.role == FleetRole::Captain
                && captain.state == ClaimState::Active
                && captain.ship_slug == ship_slug
        })
        .collect::<Vec<_>>();
    match matching.as_slice() {
        [captain] => Ok(captain.clone()),
        [] => Err(format!(
            "execute_admin_operation ship '{ship_slug}' has no active authoritative Captain"
        )),
        _ => Err(format!(
            "execute_admin_operation ship '{ship_slug}' has ambiguous Captain ownership"
        )),
    }
}

fn resolve_admin_worktree_target(
    ctx: &ControlContext,
    requested_path: &str,
) -> Result<ResolvedAdminExecutionTarget, String> {
    let requested_path = files::posix_form(requested_path.trim());
    if requested_path.is_empty() || !requested_path.starts_with('/') {
        return Err("execute_admin_operation worktree path must be absolute".into());
    }
    let snapshot = ctx.captains.snapshot();
    let mut matches = Vec::new();
    for project in &snapshot.projects {
        if project.vcs_capability.as_deref() == Some("none") {
            require_registered_git_capability(ctx, "admin_worktree", &requested_path)?;
            continue;
        }
        let worktrees = git::worktree_list(&files::posix_form(&project.repo_root))?;
        if let Some(worktree) = worktrees
            .into_iter()
            .find(|worktree| files::posix_form(&worktree.path) == requested_path)
        {
            for captain in snapshot.captains.iter().filter(|captain| {
                captain.role == FleetRole::Captain
                    && captain.state == ClaimState::Active
                    && captain.project_id.as_deref() == Some(project.project_id.as_str())
            }) {
                matches.push((captain.ship_slug.clone(), worktree.path.clone()));
            }
        }
    }
    matches.sort();
    matches.dedup();
    match matches.as_slice() {
        [(ship_slug, path)] => Ok(ResolvedAdminExecutionTarget {
            authorization_target: crate::delegated_admin::AdminTarget::Worktree {
                ship_slug: ship_slug.clone(),
                worktree_id: files::posix_form(path),
            },
            resource: AdminExecutionResource::Worktree(files::posix_form(path)),
        }),
        [] => Err(format!(
            "execute_admin_operation worktree '{requested_path}' has no active authoritative ship owner"
        )),
        _ => Err(format!(
            "execute_admin_operation worktree '{requested_path}' has ambiguous ship ownership"
        )),
    }
}

fn resolve_admin_execution_target(
    ctx: &ControlContext,
    input: &AdminExecutionTargetInput,
) -> Result<ResolvedAdminExecutionTarget, String> {
    match input {
        AdminExecutionTargetInput::Fleet => Ok(ResolvedAdminExecutionTarget {
            authorization_target: crate::delegated_admin::AdminTarget::Fleet,
            resource: AdminExecutionResource::Fleet,
        }),
        AdminExecutionTargetInput::Ship { ship_slug } => {
            let captain = exact_active_captain_for_ship(ctx, ship_slug)?;
            Ok(ResolvedAdminExecutionTarget {
                authorization_target: crate::delegated_admin::AdminTarget::Ship {
                    ship_slug: captain.ship_slug.clone(),
                },
                resource: AdminExecutionResource::Ship(captain.ship_slug),
            })
        }
        AdminExecutionTargetInput::Session { session_id } => {
            let session_id = session_id.strip_prefix("th_").unwrap_or(session_id).trim();
            if session_id.is_empty() {
                return Err("execute_admin_operation sessionId must not be empty".into());
            }
            Ok(ResolvedAdminExecutionTarget {
                authorization_target: delegated_admin_target_for_terminal(ctx, session_id)?,
                resource: AdminExecutionResource::Session(session_id.to_string()),
            })
        }
        AdminExecutionTargetInput::Worktree { path } => resolve_admin_worktree_target(ctx, path),
        AdminExecutionTargetInput::GeneralReserved { action } => Ok(ResolvedAdminExecutionTarget {
            authorization_target: crate::delegated_admin::AdminTarget::GeneralReserved {
                action: action.clone(),
            },
            resource: AdminExecutionResource::Forbidden,
        }),
        AdminExecutionTargetInput::Implementation {
            ship_slug,
            assignment_id,
        } => Ok(ResolvedAdminExecutionTarget {
            authorization_target: crate::delegated_admin::AdminTarget::Implementation {
                ship_slug: ship_slug.clone(),
                assignment_id: assignment_id.clone(),
            },
            resource: AdminExecutionResource::Forbidden,
        }),
    }
}

fn revalidate_admin_execution_authority(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
) -> Result<(), String> {
    let grant = ctx
        .delegated_admin
        .get(&audit.grant_id)
        .filter(|grant| {
            grant.state.is_active()
                && grant.grant_generation == audit.grant_generation
                && grant.actor_identity_id == audit.actor_identity_id
        })
        .ok_or("delegated admin: exact grant changed before administrative execution")?;
    let supervisor = current_delegating_supervisor(ctx, &grant);
    let actor = current_admin_actor(ctx, &grant);
    ctx.delegated_admin
        .authorize(
            &crate::delegated_admin::AdminActor {
                identity_id: audit.actor_identity_id.clone(),
                session_tile: audit.actor_session_tile.clone(),
                ..actor
            },
            &supervisor,
            audit.operation,
            &audit.target,
            &crate::delegated_admin::AdminSafeguards::default(),
        )
        .map(|_| ())
        .map_err(|error| format!("{}: {error}", error.code()))
}

fn revalidate_admin_execution_target(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    target: &ResolvedAdminExecutionTarget,
) -> Result<(), String> {
    let current = match &target.resource {
        AdminExecutionResource::Fleet => crate::delegated_admin::AdminTarget::Fleet,
        AdminExecutionResource::Ship(ship_slug) => {
            let captain = exact_active_captain_for_ship(ctx, ship_slug)?;
            crate::delegated_admin::AdminTarget::Ship {
                ship_slug: captain.ship_slug,
            }
        }
        AdminExecutionResource::Session(session_id) => {
            delegated_admin_target_for_terminal(ctx, session_id)?
        }
        AdminExecutionResource::Worktree(path) => {
            resolve_admin_worktree_target(ctx, path)?.authorization_target
        }
        AdminExecutionResource::Forbidden => audit.target.clone(),
    };
    if current != audit.target {
        return Err(
            "delegated admin: exact target ownership changed before administrative execution"
                .into(),
        );
    }
    Ok(())
}

fn revalidate_admin_effect_session(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    target: &ResolvedAdminExecutionTarget,
    session_id: &str,
) -> Result<(), String> {
    revalidate_admin_execution_target(ctx, audit, target)?;
    let current_session = delegated_admin_target_for_terminal(ctx, session_id)?;
    match (&audit.target, &current_session) {
        (
            crate::delegated_admin::AdminTarget::Fleet,
            crate::delegated_admin::AdminTarget::Captain { .. },
        ) => Ok(()),
        (
            crate::delegated_admin::AdminTarget::Ship { ship_slug },
            crate::delegated_admin::AdminTarget::Captain {
                ship_slug: current, ..
            }
            | crate::delegated_admin::AdminTarget::CrewSession {
                ship_slug: current, ..
            },
        ) if ship_slug == current => Ok(()),
        (expected, current) if expected == current => Ok(()),
        _ => Err(
            "delegated admin: administrative session target changed ownership before mutation"
                .into(),
        ),
    }
}

fn session_liveness_label(liveness: tmux::SessionLiveness) -> &'static str {
    match liveness {
        tmux::SessionLiveness::Alive => "alive",
        tmux::SessionLiveness::Gone => "gone",
        tmux::SessionLiveness::Unknown => "unknown",
    }
}

fn admin_session_ids_for_target(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    target: &ResolvedAdminExecutionTarget,
) -> Result<Vec<String>, String> {
    let snapshot = ctx.captains.snapshot();
    let mut sessions = match &target.resource {
        AdminExecutionResource::Session(session_id) => vec![session_id.clone()],
        AdminExecutionResource::Ship(ship_slug) => {
            let captain = exact_active_captain_for_ship(ctx, ship_slug)?;
            let mut sessions = captain.terminal_id.into_iter().collect::<Vec<_>>();
            if audit.delegated_role == crate::delegated_admin::DelegatedAdminRole::ShipAdmin {
                sessions.extend(
                    captain
                        .crew
                        .into_iter()
                        .filter(|crew| !matches!(crew.state, CrewState::Removed { .. }))
                        .map(|crew| crew.terminal_id),
                );
            }
            sessions
        }
        AdminExecutionResource::Fleet => snapshot
            .captains
            .into_iter()
            .filter(|captain| {
                captain.role == FleetRole::Captain && captain.state == ClaimState::Active
            })
            .filter_map(|captain| captain.terminal_id)
            .collect(),
        AdminExecutionResource::Worktree(_) | AdminExecutionResource::Forbidden => Vec::new(),
    };
    sessions.sort();
    sessions.dedup();
    Ok(sessions)
}

fn maintain_admin_sessions(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    target: &ResolvedAdminExecutionTarget,
) -> Result<Value, String> {
    let session_ids = admin_session_ids_for_target(ctx, audit, target)?;
    if session_ids.is_empty() {
        return Err("execute_admin_operation target has no authoritative session resources".into());
    }
    let mut maintained = Vec::new();
    let mut recovery_plan = Vec::new();
    for session_id in session_ids {
        let tmux_session = tmux_target(&session_id);
        let liveness = tmux::session_liveness(&tmux_session);
        match liveness {
            tmux::SessionLiveness::Alive => {
                revalidate_admin_effect_session(ctx, audit, target, &session_id)?;
                revalidate_admin_execution_authority(ctx, audit)?;
                tmux::maintain_session(&tmux_session).map_err(|error| {
                    format!("session '{session_id}' maintenance failed: {error}")
                })?;
                maintained.push(json!({
                    "sessionId": session_id,
                    "tmuxSession": tmux_session,
                    "outcome": "maintained",
                }));
            }
            tmux::SessionLiveness::Gone | tmux::SessionLiveness::Unknown => {
                recovery_plan.push(json!({
                    "sessionId": session_id,
                    "tmuxSession": tmux_session,
                    "observedLiveness": session_liveness_label(liveness),
                    "requiredSupervisorDecision": "replaceOrRetireRuntime",
                }));
            }
        }
    }
    revalidate_admin_execution_target(ctx, audit, target)?;
    revalidate_admin_execution_authority(ctx, audit)?;
    Ok(json!({
        "outcome": if recovery_plan.is_empty() { "maintained" } else { "recoveryPrepared" },
        "maintainedSessions": maintained,
        "recoveryPlan": recovery_plan,
    }))
}

fn recover_admin_worktree(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    path: &str,
) -> Result<Value, String> {
    revalidate_admin_execution_target(
        ctx,
        audit,
        &ResolvedAdminExecutionTarget {
            authorization_target: audit.target.clone(),
            resource: AdminExecutionResource::Worktree(path.to_string()),
        },
    )?;
    revalidate_admin_execution_authority(ctx, audit)?;
    let info = git::git_info_cached(path);
    if !info.is_repo || info.worktree_root.as_deref() != Some(path) {
        return Err(format!(
            "execute_admin_operation worktree '{path}' no longer resolves as the exact Git worktree"
        ));
    }
    let recovery_required = info.head_commit.is_none();
    Ok(json!({
        "outcome": if recovery_required { "recoveryPrepared" } else { "resourceReconciled" },
        "worktree": {
            "path": path,
            "branch": info.branch,
            "headCommit": info.head_commit,
            "dirtyCount": info.dirty_count,
            "isLinkedWorktree": info.is_linked_worktree,
        },
        "recoveryPlan": recovery_required.then(|| json!({
            "requiredSupervisorDecision": "selectAuthoritativeBaseline",
            "preserveDirtyWork": info.dirty_count > 0,
        })),
    }))
}

fn retirement_plan_id(
    audit: &crate::delegated_admin::AdminAuditContext,
    blockers: &[Value],
) -> String {
    let canonical = serde_json::to_vec(&json!({
        "grantId": audit.grant_id,
        "grantGeneration": audit.grant_generation,
        "target": audit.target,
        "blockers": blockers,
    }))
    .expect("retirement plan inputs are serializable");
    format!("sha256:{:x}", Sha256::digest(canonical))
}

fn prepare_admin_retirement(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    target: &ResolvedAdminExecutionTarget,
) -> Result<Value, String> {
    revalidate_admin_execution_target(ctx, audit, target)?;
    revalidate_admin_execution_authority(ctx, audit)?;
    let mut blockers = Vec::new();
    match &target.resource {
        AdminExecutionResource::Session(session_id) => {
            let liveness = tmux::session_liveness(&tmux_target(session_id));
            if !matches!(liveness, tmux::SessionLiveness::Gone) {
                blockers.push(json!({
                    "kind": "sessionNotStopped",
                    "sessionId": session_id,
                    "liveness": session_liveness_label(liveness),
                }));
            }
            if let crate::delegated_admin::AdminTarget::Captain {
                captain_identity_id,
                ..
            } = &audit.target
            {
                let dependent_grants = ctx
                    .delegated_admin
                    .grants_delegated_by(captain_identity_id)
                    .into_iter()
                    .filter(|grant| grant.state.is_active())
                    .count();
                if dependent_grants > 0 {
                    blockers.push(json!({
                        "kind": "activeDependentGrants",
                        "count": dependent_grants,
                    }));
                }
            }
        }
        AdminExecutionResource::Ship(ship_slug) => {
            let captain = exact_active_captain_for_ship(ctx, ship_slug)?;
            if let Some(session_id) = &captain.terminal_id {
                blockers.push(json!({
                    "kind": "activeCaptain",
                    "sessionId": session_id,
                }));
            }
            let active_crew = captain
                .crew
                .iter()
                .filter(|crew| !matches!(crew.state, CrewState::Removed { .. }))
                .count();
            if active_crew > 0 {
                blockers.push(json!({
                    "kind": "activeCrew",
                    "count": active_crew,
                }));
            }
            let active_grants = ctx
                .delegated_admin
                .active_grants()
                .into_iter()
                .filter(|grant| {
                    matches!(
                        &grant.scope,
                        crate::delegated_admin::AdminScope::Ship { ship_slug: scope }
                            if scope == ship_slug
                    )
                })
                .count();
            if active_grants > 0 {
                blockers.push(json!({
                    "kind": "activeAdministrativeGrants",
                    "count": active_grants,
                }));
            }
        }
        AdminExecutionResource::Worktree(path) => {
            let info = git::git_info_cached(path);
            if info.dirty_count > 0 {
                blockers.push(json!({
                    "kind": "dirtyWorktree",
                    "dirtyCount": info.dirty_count,
                }));
            }
            let leased_sessions = tmux::pane_info()
                .map_err(|error| format!("retirement lease inspection failed: {error}"))?
                .into_iter()
                .filter(|pane| {
                    pane.cwd == *path
                        || pane
                            .cwd
                            .strip_prefix(path)
                            .is_some_and(|suffix| suffix.starts_with('/'))
                })
                .map(|pane| pane.session)
                .collect::<Vec<_>>();
            if !leased_sessions.is_empty() {
                blockers.push(json!({
                    "kind": "liveSessionLeases",
                    "sessions": leased_sessions,
                }));
            }
        }
        AdminExecutionResource::Fleet | AdminExecutionResource::Forbidden => {
            return Err(
                "execute_admin_operation target is not valid for retirement preparation".into(),
            );
        }
    }
    revalidate_admin_execution_target(ctx, audit, target)?;
    revalidate_admin_execution_authority(ctx, audit)?;
    let plan_id = retirement_plan_id(audit, &blockers);
    Ok(json!({
        "outcome": "retirementPrepared",
        "planId": plan_id,
        "ready": blockers.is_empty(),
        "blockers": blockers,
        "destructiveActionPerformed": false,
    }))
}

fn execute_admin_operation(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_exact_args(args, "execute_admin_operation", &["operation", "target"])?;
    require_socket_identity(caller, trusted_internal, "execute_admin_operation")?;
    let caller = caller
        .ok_or("execute_admin_operation requires the exact delegated Crew session identity")?;
    let operation = serde_json::from_value::<crate::delegated_admin::AdminOperation>(
        args.get("operation")
            .cloned()
            .ok_or("execute_admin_operation requires an operation")?,
    )
    .map_err(|error| format!("execute_admin_operation operation is invalid: {error}"))?;
    if !matches!(
        operation,
        crate::delegated_admin::AdminOperation::MaintainSession
            | crate::delegated_admin::AdminOperation::RecoverResource
            | crate::delegated_admin::AdminOperation::PrepareRetirement
            | crate::delegated_admin::AdminOperation::MaintainFleetResource
    ) {
        return Err("execute_admin_operation supports maintainSession, recoverResource, prepareRetirement, or maintainFleetResource only".into());
    }
    let target_input = serde_json::from_value::<AdminExecutionTargetInput>(
        args.get("target")
            .cloned()
            .ok_or("execute_admin_operation requires a target")?,
    )
    .map_err(|error| format!("execute_admin_operation target is invalid: {error}"))?;
    let target = resolve_admin_execution_target(ctx, &target_input)?;
    let audit = authorize_delegated_admin(
        ctx,
        caller,
        operation,
        target.authorization_target.clone(),
        crate::delegated_admin::AdminSafeguards::default(),
    )?;
    let result = match operation {
        crate::delegated_admin::AdminOperation::MaintainSession => {
            if !matches!(target.resource, AdminExecutionResource::Session(_)) {
                Err("execute_admin_operation maintainSession requires a session target".into())
            } else {
                maintain_admin_sessions(ctx, &audit, &target)
            }
        }
        crate::delegated_admin::AdminOperation::RecoverResource => match &target.resource {
            AdminExecutionResource::Worktree(path) => recover_admin_worktree(ctx, &audit, path),
            AdminExecutionResource::Forbidden => {
                Err("execute_admin_operation cannot recover a forbidden target".into())
            }
            _ => maintain_admin_sessions(ctx, &audit, &target),
        },
        crate::delegated_admin::AdminOperation::PrepareRetirement => {
            prepare_admin_retirement(ctx, &audit, &target)
        }
        crate::delegated_admin::AdminOperation::MaintainFleetResource => {
            if !matches!(
                target.resource,
                AdminExecutionResource::Fleet
                    | AdminExecutionResource::Ship(_)
                    | AdminExecutionResource::Session(_)
            ) {
                Err("execute_admin_operation maintainFleetResource requires a fleet, ship, or Captain session target".into())
            } else {
                maintain_admin_sessions(ctx, &audit, &target)
            }
        }
        _ => unreachable!(),
    }
    .map(|outcome| {
        json!({
            "accepted": "execute_admin_operation",
            "operation": operation,
            "target": target.authorization_target,
            "outcome": outcome,
            "delegatedAdmin": audit,
            "audited": true,
        })
    });
    record_delegated_admin_execution_outcome(ctx, &audit, &result);
    result
}

fn authorize_delegated_admin(
    ctx: &ControlContext,
    caller: &ResolvedIdentity,
    operation: crate::delegated_admin::AdminOperation,
    target: crate::delegated_admin::AdminTarget,
    safeguards: crate::delegated_admin::AdminSafeguards,
) -> Result<crate::delegated_admin::AdminAuditContext, String> {
    let grant = ctx
        .delegated_admin
        .grants_for_actor(&caller.session_id)
        .into_iter()
        .find(|grant| grant.state.is_active())
        .ok_or("delegated admin: caller has no active administrative grant")?;
    let supervisor = current_delegating_supervisor(ctx, &grant);
    let actor = current_admin_actor(ctx, &grant);
    let audit = ctx
        .delegated_admin
        .authorize(
            &crate::delegated_admin::AdminActor {
                identity_id: caller.session_id.clone(),
                session_tile: caller.tile.clone(),
                ..actor
            },
            &supervisor,
            operation,
            &target,
            &safeguards,
        )
        .map_err(|error| format!("{}: {error}", error.code()))?;
    Ok(audit)
}

fn record_delegated_admin_outcome<T>(
    ctx: &ControlContext,
    audit: Option<&crate::delegated_admin::AdminAuditContext>,
    result: &Result<T, String>,
) {
    let Some(audit) = audit else {
        return;
    };
    let decision = if result.is_ok() {
        "succeeded"
    } else {
        "failed"
    };
    let audit_value = json!({
        "authorization": audit,
        "outcome": decision,
        "error": result.as_ref().err(),
    });
    ctx.audit.record(
        "delegated_admin_operation",
        "organization",
        decision,
        &audit_value,
        AuditMeta {
            peer: if ctx.peer_is_loopback {
                "loopback"
            } else {
                "remote"
            },
            token_tier: "delegated",
            session: audit.actor_session_tile.as_deref(),
            spawned_by: None,
            error: result.as_ref().err().map(String::as_str),
        },
    );
}

/// Record the bounded typed result of an explicit administration command.
///
/// Other delegated reads intentionally use [`record_delegated_admin_outcome`]
/// without serializing their result because terminal scrollback and status
/// payloads may contain sensitive or unbounded user data.
fn record_delegated_admin_execution_outcome(
    ctx: &ControlContext,
    audit: &crate::delegated_admin::AdminAuditContext,
    result: &Result<Value, String>,
) {
    let decision = if result.is_ok() {
        "succeeded"
    } else {
        "failed"
    };
    let audit_value = json!({
        "authorization": audit,
        "outcome": decision,
        "result": result.as_ref().ok(),
        "error": result.as_ref().err(),
    });
    ctx.audit.record(
        "delegated_admin_operation",
        "organization",
        decision,
        &audit_value,
        AuditMeta {
            peer: if ctx.peer_is_loopback {
                "loopback"
            } else {
                "remote"
            },
            token_tier: "delegated",
            session: audit.actor_session_tile.as_deref(),
            spawned_by: None,
            error: result.as_ref().err().map(String::as_str),
        },
    );
}

/// Comms-plane Phase 3: operate-fleet-infra (§2.7 R-L2). The plane's own administrative
/// operations (queue purge/flush) gated to the apex fleet-infra owner
/// (`can_operate_fleet_infra`): a captain/crew may NOT administer the shared plane. The
/// only op today is `purge` (reset a wedged recipient's queue) - the "flushing/
/// administering queues" surface the design names; WHO holds it is a matrix policy call.
fn plane_admin(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "plane_admin")?;
    if let Some(id) = caller {
        let actor = acl_actor(id);
        if let Err(d) = crate::acl::can_operate_fleet_infra(&actor) {
            ctx.fanout.emit_event(
                "control://acl",
                &json!({
                    "cell": "operate-fleet-infra",
                    "decision": "refused",
                    "session": actor.session_id.as_str(),
                    "role": actor.role.label(),
                    "reason": d.reason.as_str(),
                }),
            );
            return Err(format!("acl: {}", d.reason));
        }
    }
    // A caller without a session identity reached this point only with in-process host proof.
    let op = arg_str(args, "op").unwrap_or_default();
    match op.as_str() {
        "purge" => {
            let recipient = arg_str(args, "recipient")
                .or_else(|| arg_str(args, "sessionId"))
                .ok_or("plane_admin op=purge requires a 'recipient' tile id")?;
            let removed = ctx.inbox.purge_recipient(&recipient);
            Ok(json!({
                "accepted": "plane_admin",
                "op": "purge",
                "recipient": recipient,
                "removed": removed,
            }))
        }
        other => Err(format!(
            "plane_admin: unknown op '{other}' (supported: 'purge')"
        )),
    }
}

fn read_terminal(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("read_terminal requires a 'sessionId' argument")?;
    // Phase 3 (§2.6 H3): the cross-ship READ hole - `read_terminal` captures another
    // session's scrollback directly via tmux, bypassing the plane entirely. An
    // identified session may read a pane ONLY on its own ship; the proven host is unrestricted.
    let caller_has_active_admin_grant = caller.is_some_and(|caller| {
        ctx.delegated_admin
            .grants_for_actor(&caller.session_id)
            .iter()
            .any(|grant| grant.state.is_active())
    });
    let delegated_audit = if caller_has_active_admin_grant {
        let caller = caller.expect("an active delegated grant requires an identified caller");
        let target = delegated_admin_target_for_terminal(ctx, &session_id)?;
        Some(authorize_delegated_admin(
            ctx,
            caller,
            crate::delegated_admin::AdminOperation::InspectStatus,
            target,
            crate::delegated_admin::AdminSafeguards::default(),
        )?)
    } else {
        enforce_session_access(ctx, caller, trusted_internal, &session_id)?;
        None
    };
    let result = (|| {
        let target = tmux_target(&session_id);
        let history = args
            .get("historyLines")
            .or_else(|| args.get("history_lines"))
            .and_then(|v| v.as_u64())
            .unwrap_or(0)
            .min(10_000) as u32;
        let text = tmux::capture_pane_text(&target, history)
            .map_err(|e| format!("failed to capture pane for '{session_id}': {e}"))?;
        Ok(json!({
            "sessionId": session_id,
            "target": target,
            "historyLines": history,
            "text": text,
        }))
    })();
    record_delegated_admin_outcome(ctx, delegated_audit.as_ref(), &result);
    result
}

fn delegated_admin_target_for_terminal(
    ctx: &ControlContext,
    terminal_id: &str,
) -> Result<crate::delegated_admin::AdminTarget, String> {
    let terminal_id = terminal_id.strip_prefix("th_").unwrap_or(terminal_id);
    let snapshot = ctx.captains.snapshot();
    if let Some(captain) = snapshot
        .captains
        .iter()
        .find(|captain| captain.terminal_id.as_deref() == Some(terminal_id))
    {
        let captain_identity_id = ctx
            .identity
            .for_tile(terminal_id)
            .map(|identity| identity.id)
            .unwrap_or_else(|| captain.assignment_id.clone());
        return Ok(crate::delegated_admin::AdminTarget::Captain {
            ship_slug: captain.ship_slug.clone(),
            captain_identity_id,
        });
    }
    let owners = snapshot
        .captains
        .iter()
        .filter(|captain| {
            captain
                .crew
                .iter()
                .any(|crew| crew.terminal_id == terminal_id)
        })
        .collect::<Vec<_>>();
    match owners.as_slice() {
        [owner] => Ok(crate::delegated_admin::AdminTarget::CrewSession {
            ship_slug: owner.ship_slug.clone(),
            session_id: terminal_id.to_string(),
        }),
        [] => Err(format!(
            "delegated admin: terminal '{terminal_id}' has no authoritative Fleet owner"
        )),
        _ => Err(format!(
            "delegated admin: terminal '{terminal_id}' has ambiguous Fleet ownership"
        )),
    }
}

// ---------------------------------------------------------------------------
// Organization-tier handlers
// ---------------------------------------------------------------------------

/// `open_file`: resolve + read a capped text file for the requested path. This is
/// the one Organization-tier action that has a real, side-effect-free backing
/// implementation today (the Files reader), so the MCP "open a file" tool returns
/// the file's contents/metadata. Args: `path` (required).
fn open_file(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let path = arg_str(args, "path").ok_or("open_file requires a 'path' argument")?;
    enforce_project_path_authority(ctx, caller, trusted_internal, &path, "open_file")?;
    // Same file-read scope as the #23 reader: a REMOTE peer may only open files
    // under the operator allowlist; loopback (the local MCP) is unrestricted.
    let contents =
        files::control_read_text(&path, !ctx.peer_is_loopback, files::remote_file_roots())?;
    serde_json::to_value(contents).map_err(|e| e.to_string())
}

/// `create_worktree` (WS-4): create a git worktree, then open it as a new
/// workspace tab with a terminal spawned in the worktree dir. We run the git
/// command HERE (mirroring the Tauri `git_worktree_add` exec) so a git failure
/// (e.g. a branch already checked out elsewhere) is reported up front and nothing
/// is forwarded to the UI on failure. On success we forward an
/// `add_worktree_workspace` command to the frontend via the [`ApplySink`]; the
/// `controlBridge` maps it to the workspace store's atomic create→tab→spawn helper
/// (`addWorktreeWorkspace`), which is the same path the FilePanel UI uses. The git
/// worktree already exists by then, so the store SKIPS its own `gitWorktreeAdd` —
/// the forward carries `alreadyCreated: true`. Args: `repoRoot`, `worktreePath`
/// (required); `branch`, `tabName`, `startupCommand` (optional).
///
/// `startupCommand` mirrors `spawn_terminal`'s: the command the worktree
/// terminal execs back into inside an interactive login shell (e.g.
/// `claude --resume <id>`), plumbed through the SAME `pane_command` / `-ilc` exec
/// path `spawn_terminal` uses. Without it a worktree crew booted to a bare shell
/// (the provisioning gap powder/Cortana hit).
fn create_worktree(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    enforce_public_spawn_contract("create_worktree", args, caller, trusted_internal)?;
    let repo_root = arg_str(args, "repoRoot")
        .or_else(|| arg_str(args, "repo_root"))
        .ok_or("create_worktree requires a 'repoRoot' argument")?;
    let worktree_path = arg_str(args, "worktreePath")
        .or_else(|| arg_str(args, "worktree_path"))
        .ok_or("create_worktree requires a 'worktreePath' argument")?;
    let branch = arg_str(args, "branch");
    let tab_name = arg_str(args, "tabName").or_else(|| arg_str(args, "tab_name"));
    // The command the worktree terminal execs into, same contract + exec path as
    // spawn_terminal's startupCommand (snake alias for parity with the other args).
    let startup_command =
        arg_str(args, "startupCommand").or_else(|| arg_str(args, "startup_command"));
    // Captain-chat phase 2: a captain staging a crew worktree identifies itself
    // so the worktree terminal is recorded as crew (same contract as
    // spawn_terminal's spawnedBy).
    let spawned_by = arg_str(args, "spawnedBy").or_else(|| arg_str(args, "spawned_by"));

    let delegated_audit = authorize_worktree_maintenance(
        ctx,
        caller,
        trusted_internal,
        args,
        &repo_root,
        &worktree_path,
        startup_command.as_deref(),
        spawned_by.as_deref(),
    )?;
    let (repo_root, worktree_path) = if ctx.peer_is_loopback {
        (repo_root, worktree_path)
    } else {
        let roots = files::remote_file_roots();
        (
            files::scoped_create_path(&repo_root, true, roots)?
                .to_string_lossy()
                .into_owned(),
            files::scoped_create_path(&worktree_path, true, roots)?
                .to_string_lossy()
                .into_owned(),
        )
    };
    require_registered_git_capability(ctx, "create_worktree", &repo_root)?;
    let result = create_worktree_authorized(
        ctx,
        args,
        repo_root,
        worktree_path,
        branch,
        tab_name,
        startup_command,
        spawned_by,
        &delegated_audit,
    );
    record_delegated_admin_outcome(ctx, delegated_audit.as_ref(), &result);
    result
}

/// Stable capability failure shared by Git-only control operations.
/// The fields are deliberately stable so adapters do not parse locale-dependent
/// Git output or receive JSON encoded inside an error string.
fn require_git_capability(operation: &str, root: &str) -> Result<(), String> {
    let posix_root = files::posix_form(root);
    if git::git_info_cached(&posix_root).is_repo {
        return Ok(());
    }
    Err(format!(
        "git_required code=git_required operation={operation} capability=git action=initialize_git"
    ))
}

fn require_registered_git_capability(
    ctx: &ControlContext,
    operation: &str,
    root: &str,
) -> Result<(), String> {
    let identity = files::posix_form(root).trim_end_matches('/').to_string();
    let mut candidates = ctx
        .captains
        .projects()
        .into_iter()
        .filter_map(|project| {
            let project_root = files::posix_form(&project.repo_root)
                .trim_end_matches('/')
                .to_string();
            (identity == project_root || identity.starts_with(&format!("{project_root}/")))
                .then_some((project_root.len(), project))
        })
        .collect::<Vec<_>>();
    let Some(max_specificity) = candidates.iter().map(|(length, _)| *length).max() else {
        return Ok(());
    };
    candidates.retain(|(length, _)| *length == max_specificity);
    if candidates.len() != 1 {
        return Err(format!(
            "{operation}: registered Project identity for '{}' is ambiguous; refusing Git capability resolution",
            identity
        ));
    }
    if candidates[0].1.vcs_capability.as_deref() == Some("none") {
        return Err(format!(
            "git_required code=git_required operation={operation} capability=git action=initialize_git"
        ));
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn create_worktree_authorized(
    ctx: &ControlContext,
    args: &Value,
    repo_root: String,
    worktree_path: String,
    branch: Option<String>,
    tab_name: Option<String>,
    startup_command: Option<String>,
    spawned_by: Option<String>,
    delegated_audit: &Option<crate::delegated_admin::AdminAuditContext>,
) -> Result<Value, String> {
    // #27: a REMOTE peer may create worktrees ONLY under the operator allowlist —
    // this execs `git worktree add` SERVER-SIDE at peer-controlled paths (a write/
    // exec surface). Loopback (the local frontend/MCP) is unrestricted. For a remote
    // peer we substitute the SCOPED (normalized) paths so the security check and the
    // git call can't diverge; the new worktree dir doesn't exist yet, hence
    // scoped_create_path (checks the deepest existing ancestor).
    let (repo_root, worktree_path) = if ctx.peer_is_loopback {
        (repo_root, worktree_path)
    } else {
        let roots = files::remote_file_roots();
        (
            files::scoped_create_path(&repo_root, true, roots)?
                .to_string_lossy()
                .into_owned(),
            files::scoped_create_path(&worktree_path, true, roots)?
                .to_string_lossy()
                .into_owned(),
        )
    };

    // Create the worktree on disk first (shares git_worktree_add's impl). A git
    // failure short-circuits here — no tab/terminal is spawned for a failed add.
    let git_output = git::worktree_add(&repo_root, &worktree_path, branch.as_deref())?;

    // A delegated administrator owns filesystem maintenance, not runtime creation.
    // Stop at the exact authorized artifact boundary: no tab, terminal, identity,
    // capability, Crew membership, or UI orchestration is created or forwarded.
    if delegated_audit.is_some() {
        return Ok(json!({
            "accepted": "create_worktree",
            "worktreePath": worktree_path,
            "branch": branch,
            "tabId": Value::Null,
            "terminalId": Value::Null,
            "gitOutput": git_output,
            "delegatedAdmin": delegated_audit,
            "administrativeMaintenanceOnly": true,
            "crewRecorded": false,
            "audited": true,
            "applied": false,
            "note": "worktree filesystem maintenance completed within the delegated Ship Admin grant; no runtime, identity, tab, or UI state was created.",
        }));
    }

    // Resolve the TARGET TAB by NAME deterministically (TASK C / #22): the tile
    // must land in a tab identified by name, NOT in whatever tab is focused. Reuse
    // an existing tab with this name; otherwise mint a fresh id CORE-side. We record
    // it in the registry now (so it's addressable immediately) and forward the
    // chosen `tabId` so the frontend places the tile in THAT tab (creating it with
    // this id+name if needed) rather than defaulting to the active workspace.
    let effective_tab_name = tab_name
        .clone()
        .or_else(|| branch.clone())
        .unwrap_or_else(|| final_path_component(&worktree_path));
    let existing_tab_id = ctx.tabs.id_for_name(&effective_tab_name);
    let tab_was_created = existing_tab_id.is_none();
    let tab_id = existing_tab_id.unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
    ctx.tabs.insert_tab(&tab_id, &effective_tab_name);

    // Headless-org: spawn the worktree terminal SERVER-side (the server owns tmux
    // either way - the webview's spawnTerminal IPC lands in this same process) and
    // place the tile in the named tab in the authoritative registry, so placement
    // holds even when that tab is hidden or the window is minimized, and the
    // terminal id is returned synchronously. With NO UI at all (no sink, no
    // subscribers), keep the headless behavior: worktree created on disk, tab
    // recorded, no terminal spawned (nothing would render it).
    let has_ui = ctx.apply_sink.is_some() || ctx.fanout.subscriber_count() > 0;
    let mut terminal_id: Option<String> = None;
    let mut tab_id = tab_id;
    if has_ui {
        // Worktree terminals are Crew and receive stable discovery plus a durable
        // per-session identity token.
        let (elevation, minted_identity) =
            match spawn_env_with_identity(ctx, args, "create_worktree", None) {
                Ok(value) => value,
                Err(error) => {
                    let rollback = rollback_created_worktree_state(
                        ctx,
                        &repo_root,
                        &worktree_path,
                        &tab_id,
                        tab_was_created,
                    );
                    return Err(create_worktree_rollback_error(
                        format!("create_worktree: identity persistence failed: {error}"),
                        rollback,
                    ));
                }
            };
        // Wrap the startupCommand into the pane exec the SAME way spawn_terminal
        // does (pane_command → an interactive login shell that execs the command);
        // None keeps the prior bare-shell behavior. No `shell` preset for a
        // worktree spawn - the crew boots into the worktree dir running this.
        let pane = crate::commands::pane_command(None, startup_command.as_deref());
        match spawn_tmux_terminal(&worktree_path, pane.as_deref(), &elevation) {
            Ok((id, _)) => {
                if let Some(identity) = &minted_identity {
                    if let Err(error) = ctx.identity.bind_tile(&identity.id, &id) {
                        let terminal_reap = tmux::kill_session_tree(&tmux_target(&id));
                        let identity_rollback = ctx.identity.retire(&identity.id);
                        let primary = format!(
                            "create_worktree: identity binding persistence failed: {error}{}",
                            identity_rollback
                                .err()
                                .map(|rollback| format!(
                                    "; identity rollback also failed: {rollback}"
                                ))
                                .unwrap_or_default()
                        );
                        let rollback = match terminal_reap {
                            Ok(()) => rollback_created_worktree_state(
                                ctx,
                                &repo_root,
                                &worktree_path,
                                &tab_id,
                                tab_was_created,
                            ),
                            Err(reap_error) => {
                                let tab_rollback =
                                    rollback_created_tab(ctx, &tab_id, tab_was_created);
                                Err(format!(
                                    "terminal reap failed ({reap_error}); the worktree was preserved{}",
                                    tab_rollback
                                        .err()
                                        .map(|error| format!("; tab rollback also failed: {error}"))
                                        .unwrap_or_default()
                                ))
                            }
                        };
                        return Err(create_worktree_rollback_error(primary, rollback));
                    }
                }
                // Atomic placement with fallback: if the named tab was closed in
                // the race window between resolution and placement, the tile
                // lands in the active (else first) tab - never orphaned outside
                // the registry. tab_id then reflects the ACTUAL placement.
                if let Some(placed) = ctx.tabs.place_tile_with_fallback(&id, Some(&tab_id)) {
                    tab_id = placed;
                }
                terminal_id = Some(id);
            }
            Err(e) => {
                // Review L2: retire the just-minted identity so a failed worktree
                // spawn does not leave an orphaned, secret-bearing entry.
                if let Some(identity) = &minted_identity {
                    if let Err(rollback) = ctx.identity.retire(&identity.id) {
                        let tab_rollback = rollback_created_tab(ctx, &tab_id, tab_was_created);
                        return Err(ambiguous_spawn_rollback_error(&e, &rollback, tab_rollback));
                    }
                }
                eprintln!("t-hub-control: create_worktree: worktree terminal spawn failed: {e}")
            }
        }
    }

    // Captain-chat phase 2: link the spawned worktree terminal to its captain.
    // No terminal (headless boot / spawn failure) = no crew session to record.
    let crew_recorded = match (&spawned_by, &terminal_id) {
        (Some(cap), Some(id)) => match ctx.captains.record_crew(cap, id) {
            Ok(recorded) => recorded,
            Err(error) => {
                let _ = close_terminal(ctx, &json!({ "sessionId": id }));
                return Err(format!(
                    "create_worktree: Crew registry persistence failed and the terminal was rolled back: {error}"
                ));
            }
        },
        _ => false,
    };
    if crew_recorded {
        let _ = captains_sync_apply(ctx);
    }

    // Forward the UI orchestration (open/reuse the named tab + adopt the spawned
    // terminal, rendered from the attached registry snapshot). The git worktree
    // already exists, so `alreadyCreated: true` tells any legacy consumer not to
    // run `gitWorktreeAdd` again.
    let forward = with_sync(
        ctx,
        json!({
            "worktreePath": worktree_path,
            "repoRoot": repo_root,
            "branch": branch,
            "tabId": tab_id,
            "tabName": effective_tab_name,
            "terminalId": terminal_id,
            "startupCommand": startup_command,
            "alreadyCreated": true,
        }),
    );
    let applied = has_ui && forward_apply(ctx, "add_worktree_workspace", &forward);
    Ok(json!({
        "accepted": "create_worktree",
        "worktreePath": worktree_path,
        "branch": branch,
        "tabId": tab_id,
        "tabName": effective_tab_name,
        "terminalId": terminal_id,
        "startupCommand": startup_command,
        "gitOutput": git_output,
        "spawnedBy": spawned_by,
        "crewRecorded": crew_recorded,
        "delegatedAdmin": delegated_audit,
        "audited": true,
        "applied": applied,
        "note": if applied {
            "worktree created on disk; the terminal was spawned server-side and \
             placed in the tab identified by tabName in the authoritative registry \
             (the user's active tab is not switched)."
        } else {
            "worktree created on disk; the UI tab/terminal forward was not \
             delivered (headless/no sink)."
        },
    }))
}

fn authorize_worktree_maintenance(
    ctx: &ControlContext,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
    args: &Value,
    repo_root: &str,
    worktree_path: &str,
    startup_command: Option<&str>,
    spawned_by: Option<&str>,
) -> Result<Option<crate::delegated_admin::AdminAuditContext>, String> {
    let admin_grants = caller
        .map(|caller| ctx.delegated_admin.grants_for_actor(&caller.session_id))
        .unwrap_or_default();
    let active_admin_grant = admin_grants
        .iter()
        .find(|grant| grant.state.is_active())
        .cloned();
    let has_admin_history = !admin_grants.is_empty();
    if trusted_internal && caller.is_none() {
        return Ok(None);
    }
    let caller = caller.ok_or("acl: create_worktree requires a session identity")?;
    if has_admin_history && active_admin_grant.is_none() {
        return Err(
            "acl: create_worktree administrative identity has no active Ship Admin grant".into(),
        );
    }
    if active_admin_grant.is_none() && caller_is_apex(Some(caller), false) {
        return Ok(None);
    }
    let snapshot = ctx.captains.snapshot();
    let project = snapshot
        .projects
        .iter()
        .find(|project| files::posix_form(&project.repo_root) == files::posix_form(repo_root))
        .ok_or("acl: create_worktree repository is not a registered Project")?;

    if active_admin_grant.is_none() && caller.fleet_role == Some(FleetRole::Captain) {
        let captain = snapshot.captains.iter().find(|captain| {
            captain.role == FleetRole::Captain
                && captain.state == ClaimState::Active
                && captain.terminal_id.as_deref() == caller.tile.as_deref()
                && captain.ship_slug == caller.ship_slug.as_deref().unwrap_or_default()
                && captain.project_id.as_deref() == Some(project.project_id.as_str())
        });
        let captain = captain.ok_or(
            "acl: create_worktree requires the active Captain that owns the registered Project",
        )?;
        if spawned_by.is_some_and(|terminal_id| captain.terminal_id.as_deref() != Some(terminal_id))
        {
            return Err("acl: create_worktree spawnedBy must name the owning Captain".into());
        }
        return Ok(None);
    }

    let runtime_or_capability_requested = startup_command.is_some()
        || spawned_by.is_some()
        || [
            "capability",
            "admissionPurpose",
            "admission_purpose",
            "shell",
            "preset",
            "startupCommand",
            "startup_command",
            "spawnedBy",
            "spawned_by",
        ]
        .iter()
        .any(|field| args.get(field).is_some_and(|value| !value.is_null()));
    if runtime_or_capability_requested {
        return Err(
            "acl: delegated worktree maintenance cannot create or elevate a runtime, dispatch implementation, or assign Crew".into(),
        );
    }
    let grant = active_admin_grant
        .ok_or("acl: create_worktree requires the owning Captain or a Ship Admin grant")?;
    let ship_slug = match &grant.scope {
        crate::delegated_admin::AdminScope::Ship { ship_slug } => ship_slug.clone(),
        crate::delegated_admin::AdminScope::Fleet => {
            return Err("acl: Fleet Admins cannot create implementation worktrees".into());
        }
    };
    let owns_project = snapshot.captains.iter().any(|captain| {
        captain.role == FleetRole::Captain
            && captain.state == ClaimState::Active
            && captain.ship_slug == ship_slug
            && captain.project_id.as_deref() == Some(project.project_id.as_str())
    });
    if !owns_project {
        return Err(format!(
            "acl: Ship Admin scope '{ship_slug}' does not own this registered Project"
        ));
    }
    authorize_delegated_admin(
        ctx,
        caller,
        crate::delegated_admin::AdminOperation::MaintainWorktree,
        crate::delegated_admin::AdminTarget::Worktree {
            ship_slug,
            worktree_id: files::posix_form(worktree_path),
        },
        crate::delegated_admin::AdminSafeguards::default(),
    )
    .map(Some)
}

fn create_worktree_rollback_error(primary: String, rollback: Result<(), String>) -> String {
    match rollback {
        Ok(()) => format!("{primary}; the new worktree was rolled back"),
        Err(error) => format!("{primary}; worktree rollback also failed: {error}"),
    }
}

fn ambiguous_spawn_rollback_error(
    spawn_error: &str,
    identity_error: &str,
    tab_rollback: Result<(), String>,
) -> String {
    format!(
        "create_worktree: terminal spawn failed ({spawn_error}); identity rollback also failed: {identity_error}; the worktree was preserved because terminal cleanup was not confirmed{}",
        tab_rollback
            .err()
            .map(|error| format!("; tab rollback also failed: {error}"))
            .unwrap_or_default()
    )
}

fn rollback_created_tab(
    ctx: &ControlContext,
    tab_id: &str,
    tab_was_created: bool,
) -> Result<(), String> {
    if tab_was_created {
        ctx.tabs.rollback_owned_empty_tab(tab_id)
    } else {
        Ok(())
    }
}

fn rollback_created_worktree_state(
    ctx: &ControlContext,
    repo_root: &str,
    worktree_path: &str,
    tab_id: &str,
    tab_was_created: bool,
) -> Result<(), String> {
    let worktree = git::rollback_created_worktree(repo_root, worktree_path);
    let tab = rollback_created_tab(ctx, tab_id, tab_was_created);
    match (worktree, tab) {
        (Ok(()), Ok(())) => Ok(()),
        (Err(worktree), Ok(())) => Err(worktree),
        (Ok(()), Err(tab)) => Err(format!("tab rollback failed: {tab}")),
        (Err(worktree), Err(tab)) => Err(format!(
            "worktree rollback failed: {worktree}; tab rollback failed: {tab}"
        )),
    }
}

/// The final non-empty path component of a POSIX path (the worktree dir's name),
/// used as a fallback tab name when neither `tabName` nor `branch` was given.
fn final_path_component(path: &str) -> String {
    path.rsplit('/')
        .find(|s| !s.is_empty())
        .unwrap_or(path)
        .to_string()
}

/// `remove_worktree` (WS-4): fail closed until one backend service can prove the
/// complete removal decision required by the worktree status contract.
///
/// The same gate is used by direct Tauri removal, so control, MCP, CLI, and UI
/// callers all receive a synchronous refusal before any UI detach or Git
/// mutation. Args: `repoRoot`, `worktreePath` (required); `force` (optional).
fn remove_worktree(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let repo_root = arg_str(args, "repoRoot")
        .or_else(|| arg_str(args, "repo_root"))
        .ok_or("remove_worktree requires a 'repoRoot' argument")?;
    let worktree_path = arg_str(args, "worktreePath")
        .or_else(|| arg_str(args, "worktree_path"))
        .ok_or("remove_worktree requires a 'worktreePath' argument")?;
    enforce_project_path_authority(ctx, caller, trusted_internal, &repo_root, "remove_worktree")?;
    enforce_project_path_authority(
        ctx,
        caller,
        trusted_internal,
        &worktree_path,
        "remove_worktree",
    )?;
    let force = args.get("force").and_then(|v| v.as_bool()).unwrap_or(false);

    // #27: a REMOTE peer may remove worktrees ONLY under the operator allowlist —
    // this forwards a `git worktree remove` of a peer-controlled path to the UI.
    // Loopback is unrestricted. (scoped_create_path also handles the existing path.)
    let (repo_root, worktree_path) = if ctx.peer_is_loopback {
        (repo_root, worktree_path)
    } else {
        let roots = files::remote_file_roots();
        (
            files::scoped_create_path(&repo_root, true, roots)?
                .to_string_lossy()
                .into_owned(),
            files::scoped_create_path(&worktree_path, true, roots)?
                .to_string_lossy()
                .into_owned(),
        )
    };
    require_registered_git_capability(ctx, "remove_worktree", &repo_root)?;

    // Preserve the remote path security boundary, then fail every authorized
    // caller before forwarding UI state or invoking Git.
    git::require_worktree_removal_safety_service()?;

    let forward = json!({
        "worktreePath": worktree_path,
        "repoRoot": repo_root,
        "force": force,
    });
    match &ctx.apply_sink {
        Some(sink) => {
            sink.apply("remove_worktree_workspace", &forward)
                .map_err(|e| {
                    format!("remove_worktree: failed to forward removal to the UI: {e}")
                })?;
            // T12: a native cockpit attached to this same server detaches its
            // own tiles rooted in the worktree in parallel; the detach->git
            // ordering and the git removal itself stay webview-owned. (With no
            // sink there is still no removal path - the refusal below - because
            // a socket client cannot run the git side; documented T12 deviation,
            // revisited at the T14 cutover.)
            let _ = broadcast_apply(ctx, "remove_worktree_workspace", &forward);
            Ok(json!({
                "accepted": "remove_worktree",
                "worktreePath": worktree_path,
                "force": force,
                "audited": true,
                // We only *forwarded* the removal request over this channel — the
                // real `git worktree remove` runs later in the frontend (after it
                // detaches live tiles) and can still fail (dirty tree without
                // force, a tile detach throwing). The control channel cannot
                // confirm that completion synchronously, so we report `requested`,
                // not `applied`, to avoid falsely telling the caller it succeeded.
                "requested": true,
                "note": "the UI was asked to detach any live tiles rooted in the \
                         worktree and then remove it (git worktree remove). \
                         Completion is NOT confirmed synchronously over this \
                         channel — the removal runs in the frontend and may still \
                         fail (e.g. a dirty tree without force).",
            }))
        }
        None => {
            // No UI at all ⇒ refuse rather than orphan a process unwitnessed.
            if ctx.fanout.subscriber_count() == 0 {
                return Err(
                    "remove_worktree: no UI is connected to detach the worktree's live \
                     tiles first; refusing to remove it to avoid orphaning a running \
                     process (the app must be running for worktree removal)"
                        .to_string(),
                );
            }
            // T-B native path: detach broadcast FIRST (queued to every
            // subscriber's socket), then the git removal server-side. A git
            // failure (e.g. dirty tree without force) surfaces verbatim — the
            // detach has still been requested, exactly like the webview path
            // where gitWorktreeRemove rejects after the tiles detached.
            let applied = broadcast_apply(ctx, "remove_worktree_workspace", &forward) > 0;
            git::worktree_remove(&repo_root, &worktree_path, force)?;
            Ok(json!({
                "accepted": "remove_worktree",
                "worktreePath": worktree_path,
                "force": force,
                "audited": true,
                "applied": applied,
                "removed": true,
                "note": "no webview is attached; the detach forward was broadcast to \
                         socket UI subscribers (the native cockpit detaches its tiles \
                         rooted in the worktree) and the server then ran `git worktree \
                         remove` itself. The removal IS confirmed: the worktree is gone.",
            }))
        }
    }
}

/// `list_worktrees` (T-B, read-only): the worktrees of the repo containing `cwd`
/// — the socket twin of the `git_worktree_list` Tauri command, sharing its
/// implementation (`git::worktree_list`), so a socket UI can build the worktree
/// list/re-open/remove flow the webview drives via IPC. Best-effort like the
/// IPC twin: a non-repo yields an empty list. Args: `cwd` (or `path`/`repoRoot`).
/// Remote peers are allowlist-gated exactly like `git_info` (the probe leaks
/// repo topology for an arbitrary host path).
fn list_worktrees(ctx: &ControlContext, args: &Value) -> Result<Value, String> {
    let cwd = arg_str(args, "cwd")
        .or_else(|| arg_str(args, "path"))
        .or_else(|| arg_str(args, "repoRoot"))
        .or_else(|| arg_str(args, "repo_root"))
        .ok_or("list_worktrees requires a 'cwd' argument")?;
    let cwd = if ctx.peer_is_loopback {
        cwd.to_string()
    } else {
        files::scoped_create_path(&cwd, true, files::remote_file_roots())?
            .to_string_lossy()
            .into_owned()
    };
    require_registered_git_capability(ctx, "list_worktrees", &cwd)?;
    let list = git::worktree_list(&cwd)?;
    Ok(json!({ "worktrees": list }))
}

/// Organization-tier actions whose effect is a pure UI mutation
/// (`focus_session`, `move_tile`, `rename_tab`). We **accept and audit** them
/// (PRD §11.2: "allowed with visible audit event") AND apply them: the accepted
/// `{command, args}` is forwarded to the frontend through the [`ApplySink`]
/// (a Tauri `control://apply` event), where `controlBridge.ts` dispatches it into
/// the workspace store. `applied` reflects whether the forward happened — `true`
/// once the app has wired its sink (the normal app path), `false` in the headless
/// proof/tests that run the listener without an `AppHandle` (still audited).
/// Broadcast one accepted forward to event subscribers on
/// [`APPLY_EVENT_CHANNEL`] (T12: the native client's delivery path). Returns how
/// many subscribers received it. Zero subscribers is a cheap no-op, so this runs
/// unconditionally next to every [`ApplySink`] forward.
fn broadcast_apply(ctx: &ControlContext, command: &str, args: &Value) -> usize {
    ctx.fanout.emit_event(
        APPLY_EVENT_CHANNEL,
        &json!({ "command": command, "args": args }),
    )
}

/// Forward one command + args to the frontend through the [`ApplySink`], returning
/// whether the forward was delivered. A forward failure is non-fatal (logged), and
/// no sink (headless proof/tests) is simply `false`. Shared by every
/// Organization-tier handler that mutates the UI.
///
/// T12: the forward is ALSO broadcast to event subscribers (the native client's
/// path). With a sink wired (the Tauri app), `applied` keeps meaning exactly what
/// it always did — the sink delivered — so the webview path is unchanged; with no
/// sink (a headless server fronting the native cockpit), reaching at least one
/// event subscriber counts as delivery.
fn forward_apply(ctx: &ControlContext, command: &str, args: &Value) -> bool {
    let sink_applied = match &ctx.apply_sink {
        Some(sink) => match sink.apply(command, args) {
            Ok(()) => Some(true),
            Err(e) => {
                eprintln!("t-hub-control: failed to forward '{command}' to the UI: {e}");
                Some(false)
            }
        },
        None => None,
    };
    let subscribers = broadcast_apply(ctx, command, args);
    sink_applied.unwrap_or(subscribers > 0)
}

fn organization_apply(ctx: &ControlContext, command: &str, args: &Value) -> Result<Value, String> {
    let applied = forward_apply(ctx, command, args);
    Ok(json!({
        "accepted": command,
        "args": args,
        "audited": true,
        "applied": applied,
        "note": if applied {
            "organization action accepted, audited, and forwarded to the UI \
             (control://apply) for application (PRD §11.2 organization tier)."
        } else {
            "organization action accepted + audited; UI application is delivered \
             by the frontend command (PRD §11.2 organization tier)."
        },
    }))
}

/// Merge the authoritative registry snapshot into a forward's args (under `sync`)
/// so the UI renders FROM the registry instead of re-deriving the mutation -
/// the headless-org apply contract. Applied AFTER the registry mutation, so the
/// snapshot already reflects it.
fn with_sync(ctx: &ControlContext, mut args: Value) -> Value {
    let snap = ctx.tabs.snapshot_full();
    args["sync"] = serde_json::to_value(&snap).unwrap_or(Value::Null);
    args
}

/// Registry-first organization mutation: the registry was already updated; forward
/// the args + authoritative snapshot to the UI and answer with the new revision.
fn organization_sync_apply(
    ctx: &ControlContext,
    command: &str,
    args: Value,
) -> Result<Value, String> {
    let forward = with_sync(ctx, args);
    let applied = forward_apply(ctx, command, &forward);
    let snap = ctx.tabs.snapshot_full();
    Ok(json!({
        "accepted": command,
        "audited": true,
        "applied": applied,
        "seq": snap.seq,
        "tabs": snap.tabs,
        "note": "applied to the server tab registry (authoritative) and forwarded \
                 to the UI with the registry snapshot; a hidden tab or unfocused \
                 window cannot lose this update.",
    }))
}

/// `new_tab` (Organization, audited): create a new workspace tab. TASK C / #22 —
/// the CORE mints the tab id so it can RETURN it (`tabId`), making the tab
/// immediately addressable for `move_tile` / `focus_tab`, and forwards that id to
/// the frontend to adopt (rather than letting the frontend mint its own id the
/// caller never learns). The id is recorded in the registry optimistically so
/// `list_tabs` sees it before the frontend reports back. Args: `name` (optional;
/// auto-named "Workspace N" when omitted).
fn new_tab(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let authority = workspace_mutation_authority(ctx, caller, trusted_internal, "new_tab")?;
    let name = arg_str(args, "name")
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .unwrap_or_else(|| ctx.tabs.auto_name());
    if name == CAPTAIN_WORKSPACE_NAME || name == "Captains" {
        return Err("new_tab: Captain Workspace is reserved and already exists".into());
    }
    let id = uuid::Uuid::new_v4().to_string();
    let owner = match &authority {
        WorkspaceMutationAuthority::Apex => None,
        WorkspaceMutationAuthority::Assignment(owner) => {
            if arg_str(args, "projectId")
                .or_else(|| arg_str(args, "project_id"))
                .is_some_and(|project_id| project_id != owner.project_id)
                || arg_str(args, "shipSlug")
                    .or_else(|| arg_str(args, "ship_slug"))
                    .is_some_and(|ship_slug| ship_slug != owner.ship_slug)
            {
                return Err("acl: new_tab requested a foreign Project or Captain ship".into());
            }
            Some(owner)
        }
    };
    ctx.captains.create_workspace(&id, &name, owner)?;
    ctx.tabs.insert_tab(&id, &name);
    let mut res = organization_sync_apply(ctx, "new_tab", json!({ "id": id, "name": name }))?;
    res["tabId"] = json!(id);
    res["name"] = json!(name);
    Ok(res)
}

/// `close_tab` (Organization, audited; headless-org): close a workspace tab over
/// the socket - the missing half of the headless tab lifecycle (an auto-created
/// tab emptied by `close_terminal` was previously only closeable by hand in the
/// UI). Policy (see [`TabRegistry::remove_tab`]): unknown tab and the last tab
/// are errors; a non-empty tab is refused unless `force: true` (its still-live
/// sessions are then re-adopted into the UI's active tab, never orphaned).
/// Auto-created empty tabs are NOT reaped implicitly - an agent staging a
/// workspace may empty and refill a tab, so closing is always an explicit call.
/// Args: `tabId` (or `tabName` to resolve by exact name); `force` (optional).
fn close_tab(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let tab_id = arg_str(args, "tabId")
        .or_else(|| arg_str(args, "id"))
        .or_else(|| {
            arg_str(args, "tabName")
                .or_else(|| arg_str(args, "tab_name"))
                .and_then(|n| ctx.tabs.id_for_name(&n))
        })
        .ok_or("close_tab requires a 'tabId' (or a 'tabName' that resolves to one)")?;
    let force = args.get("force").and_then(|v| v.as_bool()).unwrap_or(false);
    let authority = workspace_mutation_authority(ctx, caller, trusted_internal, "close_tab")?;
    if matches!(authority, WorkspaceMutationAuthority::Apex) {
        ctx.captains
            .adopt_unowned_workspace_projection(&ctx.tabs.snapshot())?;
    }
    enforce_workspace_owner(ctx, &authority, &tab_id, "close_tab")?;
    let expected_owner = match &authority {
        WorkspaceMutationAuthority::Apex => None,
        WorkspaceMutationAuthority::Assignment(owner) => Some(owner),
    };
    let closed = ctx
        .captains
        .close_workspace(&tab_id, force, expected_owner)?;
    #[cfg(test)]
    if args
        .get("testCrashAfterFleetCommit")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return Err("injected crash after durable Fleet Workspace close commit".into());
    }
    ctx.tabs.replace(ctx.captains.workspace_projection());
    let _ = captains_sync_apply(ctx);
    let mut res =
        organization_sync_apply(ctx, "close_tab", json!({ "tabId": tab_id, "force": force }))?;
    res["tabId"] = json!(tab_id);
    res["orphanedTileIds"] = json!(closed.removed_tile_ids);
    res["captainsChanged"] = json!(closed.captains_changed);
    Ok(res)
}

/// `rename_tab` (Organization, audited; headless-org): rename a tab. Registry-
/// first + strict (unknown tab is an error), then forwards the snapshot so the
/// rename applies even when the tab is hidden or the window is unfocused.
/// Args: `tabId` (or `id`), `name`.
fn rename_tab(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let tab_id = arg_str(args, "tabId")
        .or_else(|| arg_str(args, "id"))
        .ok_or("rename_tab requires a 'tabId' argument")?;
    let name = arg_str(args, "name")
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .ok_or("rename_tab requires a non-empty 'name' argument")?;
    let authority = workspace_mutation_authority(ctx, caller, trusted_internal, "rename_tab")?;
    if matches!(authority, WorkspaceMutationAuthority::Apex) {
        ctx.captains
            .adopt_unowned_workspace_projection(&ctx.tabs.snapshot())?;
    }
    enforce_workspace_owner(ctx, &authority, &tab_id, "rename_tab")?;
    ctx.captains.rename_workspace(&tab_id, &name)?;
    ctx.tabs.rename_tab(&tab_id, &name)?;
    organization_sync_apply(ctx, "rename_tab", json!({ "tabId": tab_id, "name": name }))
}

/// Forward the authoritative captains snapshot to the UI as a `sync_captains`
/// apply (captain-chat phase 2) - the captains twin of [`with_sync`]'s tab
/// snapshot, emitted AFTER a registry mutation so the UI renders FROM the
/// registry. Rides the same [`forward_apply`] path (webview sink + T12 socket
/// broadcast). Returns whether the forward was delivered.
fn captains_sync_apply(ctx: &ControlContext) -> bool {
    let snap = ctx.captains.snapshot();
    let args = json!({ "sync": serde_json::to_value(&snap).unwrap_or(Value::Null) });
    forward_apply(ctx, "sync_captains", &args)
}

fn captain_checkpoint(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "captain_checkpoint")?;
    let captain_session_id =
        arg_str(args, "captainSessionId").or_else(|| arg_str(args, "captain_session_id"));
    let ship_slug = arg_str(args, "shipSlug").or_else(|| arg_str(args, "ship_slug"));
    let crew_session_id =
        arg_str(args, "crewSessionId").or_else(|| arg_str(args, "crew_session_id"));
    let conversation_id =
        arg_str(args, "conversationId").or_else(|| arg_str(args, "conversation_id"));
    let resume_point = arg_str(args, "resumePoint").or_else(|| arg_str(args, "resume_point"));
    let snapshot = ctx.captains.snapshot();
    let captain = snapshot
        .captains
        .iter()
        .find(|captain| {
            captain_session_id
                .as_deref()
                .is_some_and(|id| captain.terminal_id.as_deref() == Some(id))
                || ship_slug
                    .as_deref()
                    .is_some_and(|slug| captain.ship_slug == slug)
        })
        .ok_or("captain_checkpoint: no matching Captain is registered")?;
    let target = crew_session_id
        .as_deref()
        .or(captain.terminal_id.as_deref())
        .ok_or("captain_checkpoint: Captain has no active terminal")?;
    let _ = enforce_target_lifecycle_authority(ctx, caller, trusted_internal, target)?;

    let captain = ctx.captains.checkpoint(
        captain_session_id.as_deref(),
        ship_slug.as_deref(),
        crew_session_id.as_deref(),
        conversation_id.as_deref(),
        resume_point.as_deref(),
    )?;
    let _ = captains_sync_apply(ctx);
    Ok(json!({
        "accepted": "captain_checkpoint",
        "audited": true,
        "captain": captain,
        "target": if crew_session_id.is_some() { "crew" } else { "captain" },
    }))
}

fn rename_captain(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "rename_captain")?;
    let captain_session_id =
        arg_str(args, "captainSessionId").or_else(|| arg_str(args, "captain_session_id"));
    let ship_slug = arg_str(args, "shipSlug").or_else(|| arg_str(args, "ship_slug"));
    let snapshot = ctx.captains.snapshot();
    let captain = snapshot
        .captains
        .iter()
        .find(|captain| {
            captain_session_id
                .as_deref()
                .is_some_and(|id| captain.terminal_id.as_deref() == Some(id))
                || ship_slug
                    .as_deref()
                    .is_some_and(|slug| captain.ship_slug == slugify_ship(slug))
        })
        .ok_or("rename_captain: no matching Captain is registered")?;
    enforce_ship_authority(caller, trusted_internal, &captain.ship_slug)?;
    let display_name = arg_str(args, "displayName")
        .or_else(|| arg_str(args, "display_name"))
        .ok_or("rename_captain requires a 'displayName' argument")?;
    let captain = ctx.captains.rename_captain(
        captain_session_id.as_deref(),
        ship_slug.as_deref(),
        &display_name,
    )?;
    let _ = captains_sync_apply(ctx);
    Ok(json!({
        "accepted": "rename_captain",
        "audited": true,
        "captain": captain,
    }))
}

/// `claim_captain` (Organization, audited; captain-chat phase 2): claim captaincy
/// of a ship. This is a durable authority mutation, separate from the UI's visual
/// overlay pin. It is registry-first (strict: a ship already captained by another
/// session is refused), then the authoritative captains snapshot is forwarded via
/// `sync_captains` so every client renders from it. Args: `captainSessionId` (or
/// `sessionId`) required; `shipSlug` optional (slugified; defaults to
/// `ship-<sessionId>`); `workspaceTabIds` optional and always explicit (an omitted
/// list owns no Work Workspace).
///
/// LIVENESS: the session must be a LIVE terminal (`th_<id>` exists in tmux) - a
/// claim for a dead/unknown session would persist and linger forever (nothing
/// ever kills a session that never existed). A re-claim that changes nothing is
/// idempotent: `seq` is unchanged and no redundant `sync_captains` is forwarded.
fn claim_captain(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let _identity_transaction = ctx.tabs.identity_transaction();
    claim_captain_locked(ctx, args, caller, trusted_internal, None, true)
}

fn claim_captain_locked(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
    binding: Option<(&str, &str, &str)>,
    forward_projection: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "claim_captain")?;
    let captain_session_id = arg_str(args, "captainSessionId")
        .or_else(|| arg_str(args, "captain_session_id"))
        .or_else(|| arg_str(args, "sessionId"))
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("claim_captain requires a 'captainSessionId' argument")?;
    // Resolve authority before probing runtime state so a foreign caller cannot
    // use this command as a terminal-liveness oracle.
    let ship_slug = arg_str(args, "shipSlug").or_else(|| arg_str(args, "ship_slug"));
    let role = match arg_str(args, "role").map(|r| r.to_ascii_lowercase()) {
        Some(r) if r == "cortana" => FleetRole::Cortana,
        _ if ship_slug.as_deref().map(slugify_ship).as_deref() == Some(CORTANA_SLUG) => {
            FleetRole::Cortana
        }
        _ => FleetRole::Captain,
    };
    enforce_attach_authority(ctx, caller, trusted_internal, &captain_session_id, role)?;
    // Liveness: refuse a claim for a session with no live terminal, so a bogus
    // or raced id can never be persisted into captains.json to linger forever.
    // De-conflation (spawn-wedge): only a DEFINITIVE `Gone` rejects; an `Unknown`
    // probe is retryable (refuse to persist a claim on an unverifiable session, but
    // never assert it is dead) so a degraded control plane can't block a legitimate
    // claim by mislabelling a live session as gone.
    match tmux::session_liveness(&tmux_target(&captain_session_id)) {
        tmux::SessionLiveness::Alive => {}
        tmux::SessionLiveness::Gone => {
            return Err(format!(
                "claim_captain: no live terminal for session '{captain_session_id}' \
                 (spawn or attach it first - a claim for a dead session would linger)"
            ));
        }
        tmux::SessionLiveness::Unknown => {
            return Err(retryable_error(format!(
                "claim_captain: liveness probe for session '{captain_session_id}' timed out; \
                 not confirmed live — retry (refusing to persist a claim on an unverified session)"
            )));
        }
    }
    // Provider continuity is a checkpoint hint only. It never bypasses the live
    // incumbent check, and runtime-derived identity wins when available.
    let requested_provider = arg_str(args, "provider")
        .or_else(|| arg_str(args, "harness"))
        .map(|value| value.trim().to_ascii_lowercase());
    let existing_provider = ctx
        .captains
        .captain_for_session(&captain_session_id)
        .and_then(|captain| captain.provider.or(captain.harness));
    let runtime_provider = detected_harness(&captain_session_id);
    if let Some(requested) = requested_provider.as_deref() {
        if runtime_provider.as_deref() != Some(requested) {
            return Err(format!(
                "claim_captain: declared provider '{requested}' does not match a live harness in terminal '{captain_session_id}'"
            ));
        }
    }
    let provider = requested_provider
        .or(runtime_provider)
        .or(existing_provider)
        .ok_or_else(|| {
            format!(
                "claim_captain: no supported harness is live in terminal '{captain_session_id}'"
            )
        })?;
    if provider != "claude" && provider != "codex" {
        return Err(format!(
            "claim_captain: unsupported provider '{provider}' (expected 'codex' or 'claude')"
        ));
    }
    if tmux::harness_liveness(&tmux_target(&captain_session_id), &provider)
        != tmux::SessionLiveness::Alive
    {
        return Err(format!(
            "claim_captain: provider '{provider}' is not verifiably live in terminal '{captain_session_id}'"
        ));
    }
    let presented_provider_session_id = arg_str(args, "providerSessionId")
        .or_else(|| arg_str(args, "provider_session_id"))
        .or_else(|| arg_str(args, "conversationId"))
        .or_else(|| arg_str(args, "conversation_id"));
    let provider_session_id = trusted_provider_session_id(
        ctx,
        &captain_session_id,
        &provider,
        presented_provider_session_id,
    )?;
    let workspace_tab_ids: Vec<String> = args
        .get("workspaceTabIds")
        .or_else(|| args.get("workspace_tab_ids"))
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|t| t.as_str().map(str::to_string))
                .collect()
        })
        .unwrap_or_default();
    if tmux::harness_liveness(&tmux_target(&captain_session_id), &provider)
        != tmux::SessionLiveness::Alive
    {
        return Err(format!(
            "claim_captain: provider '{provider}' stopped before the identity transaction committed"
        ));
    }
    let previous_workspace = ctx.tabs.workspace_for_tile(&captain_session_id);
    let captain_workspace_existed = ctx.tabs.has_tab(CAPTAIN_WORKSPACE_ID);
    let requested_slug = match role {
        FleetRole::Cortana => CORTANA_SLUG.to_string(),
        FleetRole::Captain => ship_slug
            .as_deref()
            .map(slugify_ship)
            .filter(|slug| !slug.is_empty())
            .unwrap_or_else(|| slugify_ship(&format!("ship-{captain_session_id}"))),
    };
    let previous_claim = ctx
        .captains
        .snapshot()
        .captains
        .into_iter()
        .find(|captain| {
            captain.terminal_id.as_deref() == Some(captain_session_id.as_str())
                || captain.ship_slug == requested_slug
        });
    let previous_authority = previous_claim.as_ref().map(|captain| {
        let identity_id = captain
            .terminal_id
            .as_deref()
            .and_then(|terminal_id| ctx.identity.for_tile(terminal_id))
            .map(|identity| identity.id);
        (
            captain.ship_slug.clone(),
            captain.terminal_id.clone(),
            identity_id,
        )
    });
    let mut unique_workspace_ids = std::collections::HashSet::new();
    for workspace_id in &workspace_tab_ids {
        if !unique_workspace_ids.insert(workspace_id.as_str()) {
            return Err(format!(
                "claim_captain: duplicate workspaceTabId '{workspace_id}'"
            ));
        }
        if ctx.tabs.work_workspace(workspace_id).is_none() {
            return Err(format!(
                "claim_captain: workspaceTabId '{workspace_id}' is not an existing Work Workspace"
            ));
        }
    }
    let before_seq = ctx.captains.snapshot().seq;
    // The transfer-grade liveness predicate (R1): the SOLE signal that may auto-release
    // an incumbent's slug to this claimant is its tmux session being DEFINITIVELY gone.
    // De-conflation (spawn-wedge): an `Unknown` probe (timed out / failed to spawn) is
    // ambiguous and is NEVER transfer-grade - `is_definitively_gone` returns true only
    // for a completed absent probe, so a degraded control plane can never seize a live
    // ship (item-2 two-tier liveness: ambiguous is never seized). Evaluated lock-free
    // inside `claim` (the CAS discipline, MED-3).
    let is_terminal_dead =
        |tile: &str| tmux::is_definitively_gone(tmux::session_liveness(&tmux_target(tile)));
    // BUG-1: readopt of a resuming captain's Orphaned crew is now GATED on a per-
    // crew liveness probe (Alive->active, Gone->retired, Unknown->stays orphaned)
    // instead of blind-activating every orphan. The probes are tmux subprocesses,
    // so they run HERE, lock-free, into a precomputed map (MED-3: tmux is never
    // called while the registry lock is held). Probe every orphaned crew tile in
    // the current snapshot; `claim` reads the map purely under the lock and any
    // tile not in it (a race adding an orphan after this snapshot) defaults to
    // Unknown -> left orphaned, re-adoptable on the next resume.
    let orphan_liveness: std::collections::HashMap<String, tmux::SessionLiveness> = ctx
        .captains
        .snapshot()
        .captains
        .iter()
        .flat_map(|c| c.crew.iter())
        .filter(|cr| matches!(cr.state, CrewState::Orphaned { .. }))
        .map(|cr| {
            let tile = cr.terminal_id.clone();
            let liveness = tmux::session_liveness(&tmux_target(&tile));
            (tile, liveness)
        })
        .collect();
    let crew_liveness = |tile: &str| {
        orphan_liveness
            .get(tile)
            .copied()
            .unwrap_or(tmux::SessionLiveness::Unknown)
    };
    let outcome = ctx.captains.claim_provider_with_binding(
        &captain_session_id,
        ship_slug.as_deref(),
        role,
        Some(&provider),
        provider_session_id.as_deref(),
        workspace_tab_ids,
        binding,
        &is_terminal_dead,
        &crew_liveness,
    )?;
    ctx.tabs
        .insert_tab(CAPTAIN_WORKSPACE_ID, CAPTAIN_WORKSPACE_NAME);
    if let Err(error) = ctx
        .tabs
        .move_tile(&captain_session_id, CAPTAIN_WORKSPACE_ID)
    {
        let rollback = ctx.captains.rollback_provisioned_claim(
            &captain_session_id,
            &outcome.record,
            previous_claim.clone(),
        );
        let workspace_rollback = (!captain_workspace_existed)
            .then(|| ctx.tabs.rollback_owned_empty_tab(CAPTAIN_WORKSPACE_ID))
            .transpose();
        return Err(format!(
            "claim_captain: Captain Workspace relocation failed: {error}{}{}",
            rollback
                .err()
                .map(|rollback| format!("; registry rollback failed: {rollback}"))
                .unwrap_or_default(),
            workspace_rollback
                .err()
                .map(|rollback| format!("; Workspace rollback failed: {rollback}"))
                .unwrap_or_default()
        ));
    }
    let snap = ctx.captains.snapshot();
    let projection = if forward_projection {
        organization_sync_apply(
            ctx,
            "move_tile",
            json!({"terminalId": captain_session_id, "tabId": CAPTAIN_WORKSPACE_ID}),
        )
    } else {
        Ok(Value::Null)
    };
    if let Err(error) = projection {
        let placement_rollback = ctx
            .tabs
            .restore_tile_placement_locked(&captain_session_id, previous_workspace.as_deref());
        let registry_rollback = ctx.captains.rollback_provisioned_claim(
            &captain_session_id,
            &outcome.record,
            previous_claim,
        );
        let workspace_rollback = (!captain_workspace_existed)
            .then(|| ctx.tabs.rollback_owned_empty_tab(CAPTAIN_WORKSPACE_ID))
            .transpose();
        return Err(format!(
            "claim_captain: Captain Workspace synchronization failed: {error}{}{}{}",
            placement_rollback
                .err()
                .map(|rollback| format!("; placement rollback failed: {rollback}"))
                .unwrap_or_default(),
            registry_rollback
                .err()
                .map(|rollback| format!("; registry rollback failed: {rollback}"))
                .unwrap_or_default(),
            workspace_rollback
                .err()
                .map(|rollback| format!("; Workspace rollback failed: {rollback}"))
                .unwrap_or_default()
        ));
    }
    if let Some((previous_ship_slug, previous_terminal_id, previous_identity_id)) =
        previous_authority
    {
        let ownership_changed = previous_ship_slug != outcome.record.ship_slug
            || previous_terminal_id != outcome.record.terminal_id;
        if ownership_changed {
            ctx.delegated_admin
                .invalidate_ship_delegator(
                    &previous_ship_slug,
                    format!(
                        "Captain ownership for ship '{previous_ship_slug}' changed during claim"
                    ),
                )
                .map_err(|error| format!("{}: {error}", error.code()))?;
            if let Some(identity_id) = previous_identity_id {
                ctx.delegated_admin
                    .invalidate_delegator(
                        &identity_id,
                        "delegating supervisor ownership changed during claim",
                    )
                    .map_err(|error| format!("{}: {error}", error.code()))?;
            }
        }
    }
    if let Some(identity_id) = ctx
        .identity
        .for_tile(&captain_session_id)
        .map(|identity| identity.id)
    {
        ctx.delegated_admin
            .invalidate_actor(
                &identity_id,
                "administrative actor acquired supervisor authority",
            )
            .map_err(|error| format!("{}: {error}", error.code()))?;
    }
    // Idempotent re-claim (unchanged): the registry left `seq` alone, so skip the
    // redundant Captain forward. Placement sync above still heals a stale tile.
    let applied = forward_projection && snap.seq != before_seq && captains_sync_apply(ctx);
    Ok(json!({
        "accepted": "claim_captain",
        "audited": true,
        "applied": applied,
        "captain": outcome.record,
        "disposition": outcome.disposition.label(),
        "seq": snap.seq,
        "captains": snap.captains,
        "note": "captaincy claimed in the server captains registry (authoritative, \
                 persistent) and the snapshot forwarded to the UI (sync_captains).",
    }))
}

/// `release_captain` (Organization, audited; captain-chat phase 2): release a
/// claimed captaincy, addressed by `captainSessionId` (or `sessionId`) or
/// `shipSlug`. Strict (an unknown claim is an error), then the snapshot is
/// forwarded via `sync_captains` exactly like `claim_captain`.
fn release_captain(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "release_captain")?;
    let target = arg_str(args, "captainSessionId")
        .or_else(|| arg_str(args, "captain_session_id"))
        .or_else(|| arg_str(args, "sessionId"))
        .or_else(|| arg_str(args, "session_id"))
        .or_else(|| arg_str(args, "shipSlug"))
        .or_else(|| arg_str(args, "ship_slug"))
        .ok_or("release_captain requires a 'captainSessionId' (or 'shipSlug') argument")?;
    let record = ctx
        .captains
        .snapshot()
        .captains
        .into_iter()
        .find(|captain| {
            captain.terminal_id.as_deref() == Some(target.as_str())
                || captain.ship_slug == slugify_ship(&target)
        })
        .ok_or_else(|| format!("release_captain: no claim matches '{target}'"))?;
    enforce_ship_authority(caller, trusted_internal, &record.ship_slug)?;
    ctx.delegated_admin
        .invalidate_ship_delegator(
            &record.ship_slug,
            format!(
                "Captain authority for ship '{}' was released",
                record.ship_slug
            ),
        )
        .map_err(|error| format!("{}: {error}", error.code()))?;
    if let Some(identity_id) = record
        .terminal_id
        .as_deref()
        .and_then(|terminal_id| ctx.identity.for_tile(terminal_id))
        .map(|identity| identity.id)
    {
        ctx.delegated_admin
            .invalidate_actor(
                &identity_id,
                "actor acquired or released supervisor authority",
            )
            .map_err(|error| format!("{}: {error}", error.code()))?;
    }
    let released = ctx.captains.release(&target)?;
    let applied = captains_sync_apply(ctx);
    let snap = ctx.captains.snapshot();
    Ok(json!({
        "accepted": "release_captain",
        "audited": true,
        "applied": applied,
        "released": released,
        "seq": snap.seq,
        "captains": snap.captains,
    }))
}

/// Parse the `scope` argument of `watch_fleet` into a [`crate::fleet::WatchScope`].
/// Accepts the string `"captains"` (default) or `"all"`, or an array of tile ids
/// (an explicit session list). An empty/absent scope defaults to captains.
fn parse_watch_scope(args: &Value) -> Result<crate::fleet::WatchScope, String> {
    use crate::fleet::WatchScope;
    match args.get("scope") {
        None | Some(Value::Null) => Ok(WatchScope::Captains),
        Some(Value::String(s)) => match s.to_ascii_lowercase().as_str() {
            "captains" | "" => Ok(WatchScope::Captains),
            "all" => Ok(WatchScope::All),
            other => Err(format!(
                "watch_fleet: unknown scope '{other}' (use \"captains\", \"all\", or an array of session ids)"
            )),
        },
        Some(Value::Array(arr)) => {
            let ids: Vec<String> = arr
                .iter()
                .filter_map(|v| v.as_str().map(str::to_string))
                .collect();
            if ids.is_empty() {
                return Err("watch_fleet: scope array must contain at least one session id".into());
            }
            Ok(WatchScope::Sessions(ids))
        }
        Some(_) => Err(
            "watch_fleet: 'scope' must be \"captains\", \"all\", or an array of session ids".into(),
        ),
    }
}

/// `watch_fleet` (Organization, audited): arm an orchestrator wake. The CALLING
/// orchestrator (identified by its own tile id in `orchestratorSessionId`) asks to
/// be re-invoked - a wake prompt injected into its terminal - whenever a session in
/// `scope` (default: every claimed captain) transitions into one of `states`
/// (default: the actionable set - idle/turn-complete, needs-input, completed/exited).
/// Requires a live terminal (like `claim_captain`), so a bogus id can't arm a dead
/// watch. Idempotent: re-arming replaces the prior watch for that orchestrator.
fn enforce_watch_owner(
    ctx: &ControlContext,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
    orchestrator: &str,
    command: &str,
) -> Result<(), String> {
    require_socket_identity(caller, trusted_internal, command)?;
    if caller_is_apex(caller, trusted_internal) {
        return Ok(());
    }
    let caller = caller.expect("non-apex watch caller is identified");
    if caller.tile.as_deref() == Some(orchestrator) {
        return Ok(());
    }
    let owns_same_ship = caller.fleet_role == Some(FleetRole::Captain)
        && caller.ship_slug.is_some()
        && target_ship_slug(ctx, orchestrator).as_deref() == caller.ship_slug.as_deref();
    if owns_same_ship {
        return Ok(());
    }
    Err(format!(
        "acl: '{command}' may mutate only the caller's own or same-ship watch"
    ))
}

fn ship_scoped_watch_scope(
    ctx: &ControlContext,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
    scope: crate::fleet::WatchScope,
) -> Result<crate::fleet::WatchScope, String> {
    if caller_is_apex(caller, trusted_internal) {
        return Ok(scope);
    }
    let caller = caller.ok_or("watch_fleet requires a durable caller identity")?;
    let ship = caller
        .ship_slug
        .as_deref()
        .ok_or("watch_fleet requires an authoritative ship scope")?;
    let snapshot = ctx.captains.snapshot();
    let mut captain_ids = Vec::new();
    let mut all_ids = Vec::new();
    for captain in snapshot
        .captains
        .iter()
        .filter(|captain| captain.ship_slug == ship && captain.state == ClaimState::Active)
    {
        if let Some(terminal_id) = &captain.terminal_id {
            captain_ids.push(terminal_id.clone());
            all_ids.push(terminal_id.clone());
        }
        all_ids.extend(
            captain
                .crew
                .iter()
                .filter(|crew| matches!(crew.state, CrewState::Active))
                .map(|crew| crew.terminal_id.clone()),
        );
    }
    let sessions = match scope {
        crate::fleet::WatchScope::Captains => captain_ids,
        crate::fleet::WatchScope::All => all_ids,
        crate::fleet::WatchScope::Sessions(sessions) => {
            for target in &sessions {
                if caller.tile.as_deref() != Some(target.as_str())
                    && target_ship_slug(ctx, target).as_deref() != Some(ship)
                {
                    return Err(format!(
                        "acl: watch_fleet target '{target}' is outside caller ship '{ship}'"
                    ));
                }
            }
            sessions
        }
    };
    if sessions.is_empty() {
        return Err(format!(
            "watch_fleet has no active sessions in caller ship '{ship}'"
        ));
    }
    Ok(crate::fleet::WatchScope::Sessions(sessions))
}

fn watch_fleet(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let orchestrator = arg_str(args, "orchestratorSessionId")
        .or_else(|| arg_str(args, "orchestrator_session_id"))
        .or_else(|| arg_str(args, "sessionId"))
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("watch_fleet requires an 'orchestratorSessionId' argument (the orchestrator's own session id)")?;
    enforce_watch_owner(ctx, caller, trusted_internal, &orchestrator, "watch_fleet")?;
    // De-conflation (spawn-wedge): only a DEFINITIVE `Gone` rejects; an `Unknown`
    // probe is a retryable control-plane timeout, not proof the orchestrator died.
    match tmux::session_liveness(&tmux_target(&orchestrator)) {
        tmux::SessionLiveness::Alive => {}
        tmux::SessionLiveness::Gone => {
            return Err(format!(
                "watch_fleet: no live terminal for orchestrator '{orchestrator}' \
                 (a wake could never be delivered to a dead session)"
            ));
        }
        tmux::SessionLiveness::Unknown => {
            return Err(retryable_error(format!(
                "watch_fleet: liveness probe for orchestrator '{orchestrator}' timed out; \
                 not confirmed live — retry (the control plane is degraded, not the session)"
            )));
        }
    }
    let scope = ship_scoped_watch_scope(ctx, caller, trusted_internal, parse_watch_scope(args)?)?;
    // `states`: an array of camelCase status strings, or absent for the default
    // actionable set. Unrecognized strings are dropped (they can never match a real
    // status); an all-unrecognized list falls back to the default rather than a
    // watch that can never fire.
    let states = match args.get("states").and_then(|v| v.as_array()) {
        Some(arr) => {
            let strs: Vec<String> = arr
                .iter()
                .filter_map(|v| v.as_str().map(str::to_string))
                .collect();
            target_statuses(&strs)
        }
        None => Vec::new(),
    };
    let watch = ctx.fleet_watches.arm(&orchestrator, scope, states);
    Ok(json!({
        "accepted": "watch_fleet",
        "audited": true,
        "watch": watch,
        "note": "armed - this session will be woken (a prompt injected into its \
                 terminal) when a watched session transitions into a target state.",
    }))
}

/// `unwatch_fleet` (Organization, audited): disarm an orchestrator wake previously
/// armed by `watch_fleet`, addressed by `orchestratorSessionId`. Idempotent-ish:
/// reports whether a watch was actually removed.
fn unwatch_fleet(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let orchestrator = arg_str(args, "orchestratorSessionId")
        .or_else(|| arg_str(args, "orchestrator_session_id"))
        .or_else(|| arg_str(args, "sessionId"))
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("unwatch_fleet requires an 'orchestratorSessionId' argument")?;
    enforce_watch_owner(
        ctx,
        caller,
        trusted_internal,
        &orchestrator,
        "unwatch_fleet",
    )?;
    let removed = ctx.fleet_watches.disarm(&orchestrator);
    Ok(json!({
        "accepted": "unwatch_fleet",
        "audited": true,
        "removed": removed,
    }))
}

/// `list_fleet_watches` (Read): the armed orchestrator wakes.
fn list_fleet_watches(ctx: &ControlContext) -> Result<Value, String> {
    let watches = ctx.fleet_watches.snapshot();
    Ok(json!({
        "watches": watches,
        "count": watches.len(),
    }))
}

/// `focus_tab` (Organization, audited): activate a tab - the ONE organization
/// command that intentionally moves the user's view. Validates the tab against
/// the registry (strict), mirrors the new active tab there (so `list_tabs` and
/// default spawn placement track it), and forwards to the UI.
fn focus_tab(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let tab_id = arg_str(args, "tabId")
        .or_else(|| arg_str(args, "id"))
        .ok_or("focus_tab requires a 'tabId' argument")?;
    let authority = workspace_mutation_authority(ctx, caller, trusted_internal, "focus_tab")?;
    enforce_workspace_owner(ctx, &authority, &tab_id, "focus_tab")?;
    // Validate-and-set atomically (a focus racing a close must fail cleanly, not
    // leave the registry's active pointer on a deleted tab).
    if !ctx.tabs.set_active_tab(&tab_id) {
        return Err(format!("focus_tab: unknown tabId '{tab_id}'"));
    }
    organization_apply(ctx, "focus_tab", &json!({ "tabId": tab_id }))
}

/// `move_tile` (Organization, audited; headless-org): move a tile into another
/// tab. Registry-FIRST and STRICT: the server registry is updated (or the command
/// errors - an unknown `tabId` is a hard error now, not the silent accept-then-
/// lose of the mirror model), then the authoritative snapshot is forwarded so the
/// UI applies it even when the target tab is hidden. A `targetId`-only call is
/// the legacy within-tab reorder: forwarded for the UI to apply and report back
/// (visual order is a UI concern).
fn move_tile(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    let tile = arg_str(args, "terminalId").or_else(|| arg_str(args, "id"));
    let tab = arg_str(args, "tabId");
    match (tile, tab) {
        (Some(tile), Some(tab)) => {
            let authority =
                workspace_mutation_authority(ctx, caller, trusted_internal, "move_tile")?;
            if matches!(authority, WorkspaceMutationAuthority::Apex) {
                ctx.captains
                    .adopt_unowned_workspace_projection(&ctx.tabs.snapshot())?;
            }
            enforce_workspace_owner(ctx, &authority, &tab, "move_tile")?;
            if let Some(source) = ctx
                .captains
                .snapshot()
                .workspaces
                .iter()
                .find(|workspace| workspace.tile_ids.contains(&tile))
                .map(|workspace| workspace.id.clone())
            {
                enforce_workspace_owner(ctx, &authority, &source, "move_tile")?;
            }
            let kind = ctx
                .tabs
                .kind_for_id(&tab)
                .ok_or_else(|| format!("move_tile: unknown tabId '{tab}'"))?;
            validate_workspace_occupant(&ctx.captains, &tile, &tab, kind)?;
            ctx.captains.move_workspace_tile(&tile, &tab)?;
            ctx.tabs.replace(ctx.captains.workspace_projection());
            organization_sync_apply(
                ctx,
                "move_tile",
                json!({ "terminalId": tile, "tabId": tab }),
            )
        }
        _ => organization_apply(ctx, "move_tile", args),
    }
}

/// `spawn_terminal` (Process-changing, PRD §11.2: confirmation required).
/// Headless-org: the SERVER spawns the tmux session (same id minting + pane wrap
/// as the Tauri `commands::spawn_terminal`), resolves the target tab against the
/// authoritative registry - `tabName` reuses-or-creates a tab WITHOUT switching
/// the user's active tab - places the tile there, and forwards the registry
/// snapshot for the UI (webview sink and/or socket subscribers) to render. The
/// real terminal id is therefore returned synchronously, and a hidden target tab
/// or a minimized window cannot lose the spawn or its placement. Refused only
/// when NO UI is connected at all (nothing would render the tile). Its MCP
/// description still carries the CONFIRMATION REQUIRED contract (the user-facing
/// gate). Args: `cwd`, `name`, `shell`, `startupCommand` (T-B), `tabName`,
/// `tabId` (all optional; `tabId` must exist, default placement is the user's
/// active tab).
///
/// `startupCommand` is the socket twin of the webview "+" presets' field: the
/// command runs inside an interactive login shell the pane execs back into
/// (`commands::pane_command`, the same wrap the Tauri spawn uses), which is what
/// the native client's resume flow rides (`claude --resume <id>`). SECURITY: it
/// is process-changing surface and deliberately stays INSIDE this command's
/// existing confirmation-gate tier — same audit, same remote-peer cwd allowlist,
/// no new ungated path (a caller with this tier could already run commands via
/// the equally-gated `send_text`).
fn string_set_arg(args: &Value, key: &str, command: &str) -> Result<BTreeSet<String>, String> {
    args.get(key)
        .and_then(Value::as_array)
        .ok_or_else(|| format!("{command} requires a '{key}' array"))?
        .iter()
        .map(|value| {
            value
                .as_str()
                .map(str::to_string)
                .ok_or_else(|| format!("{command} '{key}' entries must be strings"))
        })
        .collect()
}

fn active_dispatch_lanes(
    snapshot: &CaptainsSnapshot,
    project_id: &str,
) -> Vec<crate::governor::LaneClaim> {
    snapshot
        .agent_sessions
        .iter()
        .filter(|agent| agent.project_id == project_id)
        .filter(|agent| agent_retains_lane_ownership(agent))
        .map(|agent| {
            let mut lane = agent
                .lane_claim
                .clone()
                .unwrap_or_else(|| crate::governor::LaneClaim {
                    lane_id: format!("legacy:{}", agent.agent_session_id),
                    owner_id: agent.agent_session_id.clone(),
                    dependencies: Some(BTreeSet::new()),
                    mutable_files: [agent.directory.clone()].into_iter().collect(),
                    mutable_schemas: BTreeSet::new(),
                    mutable_interfaces: BTreeSet::new(),
                });
            // The lane was admitted only after its dispatch dependencies were
            // satisfied. They are provenance now, not unresolved dependencies
            // for a later preflight.
            lane.dependencies = Some(BTreeSet::new());
            lane
        })
        .collect()
}

fn agent_retains_lane_ownership(agent: &AgentSessionRecord) -> bool {
    agent.work_stage != crate::agent_session::WorkStage::Stopped
        && !agent
            .delivery_states()
            .is_some_and(|states| states.integrated)
}

fn dispatch_machine_evidence(ctx: &ControlContext, live_sessions: usize) -> (bool, usize) {
    let metrics = ctx.metrics.as_ref().and_then(|fetch| fetch().ok());
    let Some(metrics) = metrics else {
        #[cfg(test)]
        return (true, ctx.governor.max_sessions());
        #[cfg(not(test))]
        return (false, live_sessions);
    };
    let cpu_count = usize::try_from(metrics.cpu_count).unwrap_or(1).max(1);
    let load_healthy = metrics.load_avg[0].is_finite()
        && metrics.load_avg[0] <= (cpu_count.saturating_mul(2)) as f32;
    let memory_known = metrics.mem_total_kib > 0;
    let memory_healthy = memory_known && metrics.mem_available_kib >= 512 * 1024;
    let memory_slots = if memory_known {
        usize::try_from(metrics.mem_available_kib / (512 * 1024)).unwrap_or(0)
    } else {
        ctx.governor.max_sessions()
    };
    let cpu_slots = cpu_count.saturating_mul(8);
    let additional_slots = memory_slots.min(cpu_slots).max(1);
    (
        load_healthy && memory_healthy,
        live_sessions
            .saturating_add(additional_slots)
            .min(crate::governor::HARD_SESSION_CEILING),
    )
}

fn recorded_admin_harness(snapshot: &CaptainsSnapshot, terminal_id: &str) -> Option<String> {
    snapshot
        .agent_sessions
        .iter()
        .find(|agent| agent.agent_session_id == terminal_id)
        .map(|agent| agent.provider.clone())
        .or_else(|| {
            snapshot.captains.iter().find_map(|captain| {
                captain
                    .crew
                    .iter()
                    .find(|crew| crew.terminal_id == terminal_id)
                    .and_then(|crew| crew.harness.clone().or_else(|| crew.provider.clone()))
            })
        })
}

fn live_admin_counts(
    ctx: &ControlContext,
    snapshot: &CaptainsSnapshot,
) -> (usize, BTreeMap<String, usize>) {
    let active_captain_ships = snapshot
        .captains
        .iter()
        .filter(|captain| captain.role == FleetRole::Captain && captain.state == ClaimState::Active)
        .map(|captain| captain.ship_slug.clone())
        .collect::<BTreeSet<_>>();
    let mut fleet_admin_actors = BTreeSet::new();
    let mut ship_admin_actors_by_scope = BTreeMap::<String, BTreeSet<String>>::new();
    for grant in ctx.delegated_admin.active_grants() {
        let actor = current_admin_actor(ctx, &grant);
        let supervisor = current_delegating_supervisor(ctx, &grant);
        if ctx
            .delegated_admin
            .validate_effective_grant(&grant, &actor, &supervisor)
            .is_err()
        {
            continue;
        }
        let Some(terminal_id) = actor.session_tile.as_deref() else {
            continue;
        };
        let Some(harness) = recorded_admin_harness(snapshot, terminal_id) else {
            continue;
        };
        if tmux::harness_liveness(&tmux_target(terminal_id), &harness)
            != tmux::SessionLiveness::Alive
        {
            continue;
        }
        match grant.role {
            crate::delegated_admin::DelegatedAdminRole::FleetAdmin => {
                fleet_admin_actors.insert(grant.actor_identity_id);
            }
            crate::delegated_admin::DelegatedAdminRole::ShipAdmin => {
                if let crate::delegated_admin::AdminScope::Ship { ship_slug } = grant.scope {
                    if active_captain_ships.contains(&ship_slug) {
                        ship_admin_actors_by_scope
                            .entry(ship_slug)
                            .or_default()
                            .insert(grant.actor_identity_id);
                    }
                }
            }
        }
    }
    (
        fleet_admin_actors.len(),
        ship_admin_actors_by_scope
            .into_iter()
            .map(|(scope, actors)| (scope, actors.len()))
            .collect(),
    )
}

fn packaged_provider_capacity_evidence() -> Result<ProviderCapacityEvidence, String> {
    let policy: PackagedProviderCapacity =
        serde_json::from_str(include_str!("../provider-capacity.json"))
            .map_err(|error| format!("packaged provider capacity policy is invalid: {error}"))?;
    if policy.schema_version != 1 {
        return Err(format!(
            "packaged provider capacity policy schema {} is unsupported",
            policy.schema_version
        ));
    }
    if policy.source.trim().is_empty() || policy.session_capacity == 0 {
        return Err("packaged provider capacity policy is incomplete".into());
    }
    Ok(ProviderCapacityEvidence {
        session_capacity: policy
            .session_capacity
            .min(crate::governor::HARD_SESSION_CEILING),
        status: crate::governor::ProviderCapacityStatus {
            source: policy.source,
            degraded: true,
            detail: Some(
                "live provider quota telemetry is unavailable; enforcing the packaged conservative safety ceiling"
                    .into(),
            ),
        },
    })
}

fn provider_capacity_from_environment(
    configured: Result<String, std::env::VarError>,
) -> Result<ProviderCapacityEvidence, String> {
    match configured {
        Ok(raw) => {
            let session_capacity = raw
                .trim()
                .parse::<usize>()
                .ok()
                .filter(|value| *value > 0)
                .map(|value| value.min(crate::governor::HARD_SESSION_CEILING))
                .ok_or_else(|| {
                    "configured provider capacity telemetry is invalid: T_HUB_PROVIDER_SESSION_CAPACITY must be a positive integer"
                        .to_string()
                })?;
            Ok(ProviderCapacityEvidence {
                session_capacity,
                status: crate::governor::ProviderCapacityStatus {
                    source: "environment-override:T_HUB_PROVIDER_SESSION_CAPACITY".into(),
                    degraded: false,
                    detail: None,
                },
            })
        }
        Err(std::env::VarError::NotPresent) => packaged_provider_capacity_evidence(),
        Err(std::env::VarError::NotUnicode(_)) => Err(
            "configured provider capacity telemetry is unavailable: T_HUB_PROVIDER_SESSION_CAPACITY is not valid Unicode"
                .into(),
        ),
    }
}

fn recorded_provider_harnesses(snapshot: &CaptainsSnapshot) -> BTreeMap<String, String> {
    let mut harnesses = BTreeMap::new();
    for agent in &snapshot.agent_sessions {
        if agent_has_durable_provider_intent(agent) {
            harnesses.insert(tmux_target(&agent.agent_session_id), agent.provider.clone());
        }
    }
    for captain in &snapshot.captains {
        if let (Some(terminal_id), Some(harness)) = (
            captain.terminal_id.as_deref(),
            captain.harness.as_deref().or(captain.provider.as_deref()),
        ) {
            harnesses.insert(tmux_target(terminal_id), harness.to_string());
        }
        for crew in &captain.crew {
            if let Some(harness) = crew.harness.as_deref().or(crew.provider.as_deref()) {
                harnesses.insert(tmux_target(&crew.terminal_id), harness.to_string());
            }
        }
    }
    harnesses
}

fn durable_agent_provider_harnesses(snapshot: &CaptainsSnapshot) -> BTreeMap<String, String> {
    snapshot
        .agent_sessions
        .iter()
        .filter(|agent| agent_has_durable_provider_intent(agent))
        .map(|agent| (tmux_target(&agent.agent_session_id), agent.provider.clone()))
        .collect()
}

fn pending_provider_marker(harness: &str) -> String {
    format!("pending:{harness}")
}

fn inspect_provider_live_sessions(
    snapshot: &CaptainsSnapshot,
    sessions: &[String],
) -> Result<usize, String> {
    let recorded = recorded_provider_harnesses(snapshot);
    let durable_agents = durable_agent_provider_harnesses(snapshot);
    let mut live = 0usize;
    for tmux_session in sessions.iter().filter(|session| session.starts_with("th_")) {
        let marker = tmux::session_environment(tmux_session, PROVIDER_SESSION_ENV)
            .map_err(|error| {
                format!(
                    "provider session marker is unavailable for tmux session '{tmux_session}': {error}"
                )
            })?;
        if durable_agents.contains_key(tmux_session) {
            live = live.saturating_add(1);
            continue;
        }
        let (harness, pending, established) = match marker.as_deref() {
            Some("none") => (None, false, false),
            Some("pending:codex") => (Some("codex".to_string()), true, false),
            Some("pending:claude") => (Some("claude".to_string()), true, false),
            Some("alive:codex") => (Some("codex".to_string()), false, true),
            Some("alive:claude") => (Some("claude".to_string()), false, true),
            Some(harness @ ("codex" | "claude")) => (Some(harness.to_string()), false, false),
            Some(other) => {
                return Err(format!(
                    "provider session marker for tmux session '{tmux_session}' is invalid: '{other}'"
                ));
            }
            None => match recorded.get(tmux_session).cloned() {
                Some(harness) => (Some(harness), false, false),
                None => {
                    let legacy_provider = ["codex", "claude"].into_iter().any(|harness| {
                        tmux::harness_liveness(tmux_session, harness)
                            == tmux::SessionLiveness::Alive
                    });
                    if legacy_provider {
                        live = live.saturating_add(1);
                    }
                    continue;
                }
            },
        };
        let Some(harness) = harness else {
            continue;
        };
        match tmux::harness_liveness(tmux_session, &harness) {
            tmux::SessionLiveness::Alive => {
                live = live.saturating_add(1);
                if pending {
                    tmux::set_session_environment(
                        tmux_session,
                        PROVIDER_SESSION_ENV,
                        &format!("alive:{harness}"),
                    )
                    .map_err(|error| {
                        format!(
                            "provider readiness marker could not be persisted for tmux session '{tmux_session}': {error}"
                        )
                    })?;
                }
            }
            tmux::SessionLiveness::Gone if pending => {
                // A dead terminal cannot become the provider runtime it was
                // reserving.  Clear the marker and release the quota instead
                // of leaking one provider slot forever after Harness exit.
                // Count this observation once so the in-flight transition is
                // fail-closed, then the cleared marker prevents future leaks.
                live = live.saturating_add(1);
                tmux::set_session_environment(tmux_session, PROVIDER_SESSION_ENV, "none")
                    .map_err(|error| {
                        format!(
                            "provider pending marker could not be cleared for tmux session '{tmux_session}': {error}"
                        )
                    })?;
            }
            tmux::SessionLiveness::Gone => {}
            tmux::SessionLiveness::Unknown => {
                if pending || established {
                    live = live.saturating_add(1);
                } else {
                    return Err(format!(
                        "provider Harness evidence is unavailable for tmux session '{tmux_session}'"
                    ));
                }
            }
        }
    }
    Ok(live)
}

fn provider_capacity_evidence(ctx: &ControlContext) -> Result<ProviderCapacityEvidence, String> {
    (ctx.provider_capacity)()
        .and_then(|mut evidence| {
            if evidence.session_capacity == 0 {
                return Err("provider capacity evidence reported a zero ceiling".into());
            }
            if evidence.status.source.trim().is_empty() {
                return Err("provider capacity evidence omitted its source".into());
            }
            evidence.session_capacity = evidence
                .session_capacity
                .min(crate::governor::HARD_SESSION_CEILING);
            Ok(evidence)
        })
        .map_err(|error| format!("provider capacity evidence unavailable: {error}"))
}

fn runtime_capacity_from_evidence(
    ctx: &ControlContext,
    snapshot: &CaptainsSnapshot,
    live: &LiveSessionEvidence,
    available_worktrees: usize,
) -> Result<crate::governor::RuntimeCapacity, String> {
    let live_sessions = live.total_live_sessions;
    let (machine_healthy, machine_session_capacity) = dispatch_machine_evidence(ctx, live_sessions);
    let provider = provider_capacity_evidence(ctx)?;
    let provider_live_sessions = (ctx.provider_live_sessions)(snapshot, &live.tmux_sessions)
        .map_err(|error| format!("provider usage evidence unavailable: {error}"))?
        .saturating_add(live.pending_provider_sessions);
    let active_captains = snapshot
        .captains
        .iter()
        .filter(|captain| captain.role == FleetRole::Captain && captain.state == ClaimState::Active)
        .map(|captain| captain.ship_slug.as_str())
        .collect::<BTreeSet<_>>()
        .len();
    let active_captain_ships = snapshot
        .captains
        .iter()
        .filter(|captain| captain.role == FleetRole::Captain && captain.state == ClaimState::Active)
        .map(|captain| captain.ship_slug.clone())
        .collect::<BTreeSet<_>>();
    let live_cortana = snapshot
        .cortana
        .terminal_id
        .as_deref()
        .is_some_and(|terminal_id| {
            matches!(
                &snapshot.cortana.recovery,
                crate::cortana_reconcile::CortanaRecoveryState::Healthy { .. }
            ) && snapshot.cortana.harness.as_deref().is_some_and(|harness| {
                tmux::session_liveness(&tmux_target(terminal_id)) == tmux::SessionLiveness::Alive
                    && tmux::harness_liveness(&tmux_target(terminal_id), harness)
                        == tmux::SessionLiveness::Alive
            })
        }) as usize;
    let live_recovery_sessions = snapshot
        .agent_sessions
        .iter()
        .filter(|agent| {
            agent.admission_purpose == crate::governor::AdmissionPurpose::Recovery
                && agent_has_durable_provider_intent(agent)
        })
        .count();
    let (live_fleet_admins, live_ship_admin_scopes) = live_admin_counts(ctx, snapshot);
    let live_ship_admins = live_ship_admin_scopes.values().copied().sum();
    Ok(crate::governor::RuntimeCapacity {
        live_sessions,
        machine_healthy,
        machine_session_capacity,
        provider_session_capacity: provider.session_capacity,
        provider_live_sessions,
        provider_capacity_status: provider.status,
        available_worktrees,
        active_captains,
        active_captain_ships,
        live_cortana,
        live_fleet_admins,
        live_ship_admins,
        live_ship_admin_scopes,
        live_recovery_sessions,
    })
}

fn admit_spawn<'a>(
    ctx: &'a ControlContext,
    purpose: SpawnPurpose,
    requested_provider_lanes: usize,
    excluded_history_terminal_id: Option<&str>,
) -> Result<SpawnAdmissionGuard<'a>, crate::governor::Refusal> {
    let lock = ctx
        .dispatch_admission
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let capacity = evaluate_spawn_capacity(
        ctx,
        &purpose,
        requested_provider_lanes,
        excluded_history_terminal_id,
    )?;
    Ok(SpawnAdmissionGuard {
        _lock: lock,
        _capacity: capacity,
    })
}

/// Evaluate and consume one spawn admission while the caller holds
/// `dispatch_admission`. Keeping this separate lets start_agent validate identity,
/// exact baseline, and lane arguments under the atomic lock before it consumes a
/// rate token.
fn evaluate_spawn_capacity(
    ctx: &ControlContext,
    purpose: &SpawnPurpose,
    requested_provider_lanes: usize,
    excluded_history_terminal_id: Option<&str>,
) -> Result<crate::governor::CapacityReport, crate::governor::Refusal> {
    let snapshot = ctx.captains.snapshot();
    let live =
        live_session_evidence(ctx, &snapshot, excluded_history_terminal_id).map_err(|message| {
            crate::governor::Refusal {
                code: "refused-evidence",
                message: format!("spawn refused: {message}"),
            }
        })?;
    let capacity = runtime_capacity_from_evidence(
        ctx,
        &snapshot,
        &live,
        crate::governor::HARD_SESSION_CEILING,
    )
    .map_err(|message| crate::governor::Refusal {
        code: "refused-provider",
        message: format!("spawn refused: {message}"),
    })?;
    let request = crate::governor::DispatchPreflight {
        requested_lanes: vec![crate::governor::LaneClaim {
            lane_id: "spawn-admission".into(),
            owner_id: "spawn-admission".into(),
            dependencies: Some(BTreeSet::new()),
            mutable_files: BTreeSet::new(),
            mutable_schemas: BTreeSet::new(),
            mutable_interfaces: BTreeSet::new(),
        }],
        requested_provider_lanes,
        admission_purpose: durable_admission_purpose(purpose),
        ship_admin_scope: ship_admin_scope(purpose),
        active_lanes: Vec::new(),
        satisfied_dependencies: BTreeSet::new(),
        integration_contracts: Vec::new(),
        capacity,
    };
    let capacity = ctx
        .governor
        .preflight_dispatch(&request)
        .map_err(|refusal| crate::governor::Refusal {
            code: refusal.code.as_str(),
            message: refusal.message,
        })?;
    ctx.governor
        .check_spawn(live.total_live_sessions, Instant::now())?;
    Ok(capacity)
}

fn evaluate_spawn_capacity_for_new_ship(
    ctx: &ControlContext,
    ship_slug: &str,
) -> Result<crate::governor::CapacityReport, crate::governor::Refusal> {
    let snapshot = ctx.captains.snapshot();
    let live = live_session_evidence(ctx, &snapshot, None).map_err(|message| {
        crate::governor::Refusal {
            code: "refused-evidence",
            message: format!("spawn refused: {message}"),
        }
    })?;
    let mut capacity = runtime_capacity_from_evidence(
        ctx,
        &snapshot,
        &live,
        crate::governor::HARD_SESSION_CEILING,
    )
    .map_err(|message| crate::governor::Refusal {
        code: "refused-provider",
        message: format!("spawn refused: {message}"),
    })?;
    capacity.active_captain_ships.insert(ship_slug.to_string());
    capacity.active_captains = capacity.active_captain_ships.len();
    let request = crate::governor::DispatchPreflight {
        requested_lanes: vec![crate::governor::LaneClaim {
            lane_id: "commission-captain".into(),
            owner_id: "commission-captain".into(),
            dependencies: Some(BTreeSet::new()),
            mutable_files: BTreeSet::new(),
            mutable_schemas: BTreeSet::new(),
            mutable_interfaces: BTreeSet::new(),
        }],
        requested_provider_lanes: 1,
        admission_purpose: crate::governor::AdmissionPurpose::Ordinary,
        ship_admin_scope: None,
        active_lanes: Vec::new(),
        satisfied_dependencies: BTreeSet::new(),
        integration_contracts: Vec::new(),
        capacity,
    };
    ctx.governor
        .preflight_dispatch(&request)
        .map_err(|refusal| crate::governor::Refusal {
            code: "refused-cap",
            message: refusal.message,
        })
}

fn dispatch_runtime_capacity(
    ctx: &ControlContext,
    snapshot: &CaptainsSnapshot,
    project_id: &str,
) -> Result<crate::governor::RuntimeCapacity, String> {
    let project = snapshot
        .projects
        .iter()
        .find(|project| project.project_id == project_id)
        .ok_or_else(|| format!("dispatch preflight: unknown projectId '{project_id}'"))?;
    require_registered_git_capability(ctx, "capacity", &project.repo_root)?;
    let live = live_session_evidence(ctx, snapshot, None)?;
    let active_directories = snapshot
        .agent_sessions
        .iter()
        .filter(|agent| agent_retains_lane_ownership(agent))
        .map(|agent| files::posix_form(&agent.directory))
        .collect::<BTreeSet<_>>();
    let available_worktrees = git::worktree_list(&files::posix_form(&project.repo_root))
        .map_err(|error| format!("dispatch preflight: could not inspect worktrees: {error}"))?
        .into_iter()
        .map(|worktree| files::posix_form(&worktree.path))
        .filter(|path| !active_directories.contains(path))
        .collect::<BTreeSet<_>>()
        .len();
    runtime_capacity_from_evidence(ctx, snapshot, &live, available_worktrees)
}

fn parse_integration_contracts(
    args: &Value,
    command: &str,
) -> Result<Vec<crate::governor::IntegrationContract>, String> {
    serde_json::from_value(
        args.get("integrationContracts")
            .cloned()
            .ok_or_else(|| format!("{command} requires an 'integrationContracts' array"))?,
    )
    .map_err(|error| format!("{command} integrationContracts are invalid: {error}"))
}

fn validate_dependency_result_ancestry(
    command: &str,
    snapshot: &CaptainsSnapshot,
    project_id: &str,
    dependencies: &BTreeSet<String>,
    checkout: &str,
    source_commit: &str,
) -> Result<BTreeSet<String>, String> {
    let mut satisfied = BTreeSet::new();
    for dependency in dependencies {
        let completed = snapshot
            .agent_sessions
            .iter()
            .filter(|agent| agent.project_id == project_id)
            .filter(|agent| {
                agent
                    .lane_claim
                    .as_ref()
                    .is_some_and(|lane| lane.lane_id == *dependency)
            })
            .filter(|agent| {
                agent
                    .delivery_states()
                    .is_some_and(|states| states.complete)
            })
            .collect::<Vec<_>>();
        if completed.is_empty() {
            return Err(format!(
                "{command}: dependency '{dependency}' has no complete lane in project '{project_id}'"
            ));
        }

        let mut result_commits = BTreeSet::new();
        for agent in completed {
            let resulting_commit = agent
                .delivery
                .as_ref()
                .and_then(|delivery| delivery.resulting_commit.as_deref())
                .ok_or_else(|| {
                    format!(
                        "{command}: dependency '{dependency}' has complete delivery without an exact resulting commit"
                    )
                })?;
            result_commits.insert(resulting_commit.to_string());
        }
        for resulting_commit in result_commits {
            git::require_commit_ancestor(checkout, &resulting_commit, source_commit).map_err(
                |error| {
                    format!(
                        "{command}: dependency '{dependency}' result '{resulting_commit}' is not present in sourceCommit '{source_commit}': {error}"
                    )
                },
            )?;
        }
        satisfied.insert(dependency.clone());
    }
    Ok(satisfied)
}

fn start_agent(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "start_agent")?;
    require_exact_args(
        args,
        "start_agent",
        &[
            "requestId",
            "captainSessionId",
            "assignment",
            "directory",
            "harness",
            "name",
            "workspaceTabId",
            "sourceCommit",
            "visibleProductBug",
            "laneId",
            "dependencies",
            "mutableFiles",
            "mutableSchemas",
            "mutableInterfaces",
            "integrationContracts",
            "admissionPurpose",
        ],
    )?;
    arg_str(args, "requestId")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'requestId'")?;
    let captain_session_id = arg_str(args, "captainSessionId")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'captainSessionId'")?;
    let assignment = arg_str(args, "assignment")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'assignment'")?;
    let directory = arg_str(args, "directory")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'directory'")?;
    let source_commit = arg_str(args, "sourceCommit")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'sourceCommit'")?;
    let visible_product_bug = args
        .get("visibleProductBug")
        .and_then(Value::as_bool)
        .ok_or("start_agent requires a boolean 'visibleProductBug'")?;
    let lane_id = arg_str(args, "laneId")
        .filter(|value| !value.trim().is_empty())
        .ok_or("start_agent requires a non-empty 'laneId'")?;
    let dependencies = string_set_arg(args, "dependencies", "start_agent")?;
    let mutable_files = string_set_arg(args, "mutableFiles", "start_agent")?;
    let mutable_schemas = string_set_arg(args, "mutableSchemas", "start_agent")?;
    let mutable_interfaces = string_set_arg(args, "mutableInterfaces", "start_agent")?;
    let integration_contracts = parse_integration_contracts(args, "start_agent")?;
    let spawn_purpose = requested_spawn_purpose("start_agent", args, caller, trusted_internal)
        .map_err(|refusal| format!("start_agent: {}", refusal.message))?;
    let admission_purpose = durable_admission_purpose(&spawn_purpose);
    let admission_lock = ctx
        .dispatch_admission
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let snapshot = ctx.captains.snapshot();
    let captain = snapshot
        .captains
        .iter()
        .find(|captain| captain.terminal_id.as_deref() == Some(captain_session_id.as_str()))
        .cloned()
        .ok_or_else(|| format!("start_agent: Captain '{captain_session_id}' was not found"))?;
    authorize_agent_filter(
        ctx,
        Some(captain_session_id.as_str()),
        captain.project_id.as_deref(),
        caller,
        trusted_internal,
        "start_agent",
        false,
    )?;
    let project_id = captain
        .project_id
        .clone()
        .ok_or("start_agent: Captain is not bound to a registered Project")?;
    let project = snapshot
        .projects
        .iter()
        .find(|project| project.project_id == project_id)
        .cloned()
        .ok_or_else(|| format!("start_agent: unknown projectId '{project_id}'"))?;
    require_registered_git_capability(ctx, "start_agent", &project.repo_root)?;
    let checkout = validate_crew_checkout(&project, Some(directory))
        .map_err(|error| error.replacen("dispatch_crew", "start_agent", 1))?;
    let worktree = git::worktree_list(&files::posix_form(&project.repo_root))
        .map_err(|error| format!("start_agent: could not detect worktree: {error}"))?
        .into_iter()
        .find(|worktree| files::posix_form(&worktree.path) == checkout);
    git::require_clean_exact_baseline(&checkout, &source_commit)
        .map_err(|error| format!("start_agent: baseline rejected: {error}"))?;
    if snapshot.agent_sessions.iter().any(|agent| {
        agent_retains_lane_ownership(agent) && files::posix_form(&agent.directory) == checkout
    }) {
        return Err(format!(
            "start_agent: checkout '{checkout}' is already owned by an active implementation lane"
        ));
    }
    let harness_name = arg_str(args, "harness")
        .unwrap_or_else(|| captain.harness.clone().unwrap_or_else(|| "codex".into()));
    let harness_name = harness_name.trim().to_ascii_lowercase();
    if !matches!(harness_name.as_str(), "codex" | "claude") {
        return Err("start_agent harness must be 'codex' or 'claude'".into());
    }
    let harness = Harness::from_provider(&harness_name);
    let agent_session_id = loop {
        let candidate = uuid::Uuid::new_v4().simple().to_string();
        let candidate = candidate[..8].to_string();
        if !snapshot
            .agent_sessions
            .iter()
            .any(|agent| agent.agent_session_id == candidate)
        {
            break candidate;
        }
    };
    let satisfied_dependencies = validate_dependency_result_ancestry(
        "start_agent",
        &snapshot,
        &project.project_id,
        &dependencies,
        &checkout,
        &source_commit,
    )?;
    let lane_claim = crate::governor::LaneClaim {
        lane_id,
        owner_id: agent_session_id.clone(),
        dependencies: Some(dependencies),
        mutable_files,
        mutable_schemas,
        mutable_interfaces,
    };
    let preflight = crate::governor::DispatchPreflight {
        requested_lanes: vec![lane_claim.clone()],
        requested_provider_lanes: 1,
        admission_purpose,
        ship_admin_scope: ship_admin_scope(&spawn_purpose),
        active_lanes: active_dispatch_lanes(&snapshot, &project.project_id),
        satisfied_dependencies,
        integration_contracts: integration_contracts.clone(),
        capacity: dispatch_runtime_capacity(ctx, &snapshot, &project.project_id)?,
    };
    let dispatch_capacity = ctx
        .governor
        .preflight_dispatch(&preflight)
        .map_err(|refusal| {
            format!(
                "start_agent: {}: {}",
                refusal.code.as_str(),
                refusal.message
            )
        })?;
    git::require_clean_exact_baseline(&checkout, &source_commit)
        .map_err(|error| format!("start_agent: baseline changed during admission: {error}"))?;
    let admission_capacity = evaluate_spawn_capacity(ctx, &spawn_purpose, 1, None)
        .map_err(|refusal| format!("start_agent: {}", refusal.message))?;
    let _admission = SpawnAdmissionGuard {
        _lock: admission_lock,
        _capacity: admission_capacity,
    };
    let now = now_ms();
    let record = AgentSessionRecord {
        agent_session_id: agent_session_id.clone(),
        captain_session_id: captain_session_id.clone(),
        project_id: project.project_id.clone(),
        assignment: assignment.clone(),
        directory: checkout.clone(),
        worktree_path: worktree
            .as_ref()
            .map(|worktree| files::posix_form(&worktree.path)),
        branch: worktree.and_then(|worktree| worktree.branch),
        workspace_tab_id: arg_str(args, "workspaceTabId"),
        harness: harness_name.clone(),
        provider: harness_name,
        provider_conversation_id: None,
        resume_point: None,
        runtime_state: RuntimeState::Starting,
        work_stage: crate::agent_session::WorkStage::Assigned,
        delivery: Some(crate::agent_session::DeliveryProvenance::new(
            source_commit,
            visible_product_bug,
        )),
        lane_claim: Some(lane_claim),
        integration_contracts,
        dispatch_capacity: Some(dispatch_capacity.clone()),
        admission_purpose,
        created_at: now,
        updated_at: now,
    };
    ctx.captains.insert_agent_session(record)?;
    #[cfg(test)]
    ctx.captains.pause_dispatch("start_agent_admitted");
    let launch = crew_launch_argv(harness, &assignment);
    let mut spawn_args = json!({
        "cwd": checkout,
        "name": arg_str(args, "name").unwrap_or_else(|| format!("Agent - {agent_session_id}")),
        "startupCommand": launch,
        "spawnedBy": captain_session_id,
    });
    if let Some(tab_id) = arg_str(args, "workspaceTabId") {
        spawn_args["tabId"] = json!(tab_id);
    }
    let spawned = match spawn_terminal_with_private_pane_command_and_id(
        ctx,
        &spawn_args,
        None,
        false,
        false,
        true,
        Some(&agent_session_id),
    ) {
        Ok(spawned) => spawned,
        Err(error) => {
            let cleanup = ctx.captains.mark_agent_unavailable(&agent_session_id);
            let identity_cleanup = ctx.identity.retire_tile(&agent_session_id);
            return Err(match cleanup {
                Ok(()) => match identity_cleanup {
                    Ok(_) => error,
                    Err(cleanup_error) => {
                        format!("{error}; identity cleanup failed: {cleanup_error}")
                    }
                },
                Err(cleanup_error) => {
                    format!(
                        "{error}; agent failure state could not be persisted: {cleanup_error}{}",
                        identity_cleanup
                            .err()
                            .map(|e| format!("; identity cleanup failed: {e}"))
                            .unwrap_or_default()
                    )
                }
            });
        }
    };
    let workspace_tab_id = spawned
        .get("tabId")
        .and_then(Value::as_str)
        .map(str::to_string);
    let started = match ctx
        .captains
        .mark_agent_started(&agent_session_id, workspace_tab_id)
    {
        Ok(started) => started,
        Err(error) => {
            let _ = tmux::kill_session_tree(&tmux_target(&agent_session_id));
            ctx.tabs.retire_tile_locked(&agent_session_id);
            let unavailable = ctx.captains.mark_agent_unavailable(&agent_session_id);
            let identity_cleanup = ctx.identity.retire_tile(&agent_session_id);
            let mut detail = format!(
                "start_agent: launch succeeded but durable start state could not be persisted: {error}"
            );
            if let Err(cleanup) = unavailable {
                detail.push_str(&format!(
                    "; recovery-required: unavailable state could not be persisted: {cleanup}"
                ));
            }
            if let Err(cleanup) = identity_cleanup {
                detail.push_str(&format!("; identity cleanup failed: {cleanup}"));
            }
            return Err(detail);
        }
    };
    let started_source_baseline = started
        .delivery
        .as_ref()
        .map(|delivery| delivery.source_baseline.clone())
        .ok_or("start_agent: durable start record lost its dispatch source baseline")?;
    Ok(json!({
        "agentSessionId": started.agent_session_id,
        "captainSessionId": started.captain_session_id,
        "projectId": started.project_id,
        "directory": started.directory,
        "worktreePath": started.worktree_path,
        "branch": started.branch,
        "workspaceTabId": started.workspace_tab_id,
        "harness": started.harness,
        "provider": started.provider,
        "runtimeState": started.runtime_state,
        "workStage": started.work_stage,
        "sourceCommit": started_source_baseline.clone(),
        "sourceBaseline": started_source_baseline,
        "admissionPurpose": started.admission_purpose,
        "deliveryStates": started.delivery_states(),
        "laneClaim": started.lane_claim,
        "dispatchCapacity": dispatch_capacity,
        "assignmentDelivered": true,
    }))
}

fn spawn_terminal(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    enforce_public_spawn_contract("spawn_terminal", args, caller, trusted_internal)?;
    if !caller_is_apex(caller, trusted_internal) {
        let caller = caller
            .ok_or("acl: spawn_terminal requires General/Cortana or an active owning Captain")?;
        if has_delegated_admin_history(ctx, &caller.session_id) {
            return Err(
                "acl: delegated administrators cannot spawn implementation sessions".into(),
            );
        }
        let caller_tile = caller
            .tile
            .as_deref()
            .ok_or("acl: spawn_terminal Captain has no terminal binding")?;
        let owns_active_captain = ctx
            .captains
            .captain_for_session(caller_tile)
            .filter(|captain| {
                captain.role == FleetRole::Captain
                    && captain.state == ClaimState::Active
                    && caller.fleet_role == Some(FleetRole::Captain)
                    && caller.ship_slug.as_deref() == Some(captain.ship_slug.as_str())
            })
            .is_some();
        if !owns_active_captain {
            return Err("acl: spawn_terminal requires an active owning Captain".into());
        }
    }
    spawn_terminal_with_private_pane_command(ctx, args, None, false, false, true)
}

/// Internal spawn variant for an already-formed private pane command.
///
/// The raw command is accepted only by in-process dispatch and is deliberately
/// excluded from the public response, apply forward, and command arguments.
fn spawn_terminal_with_private_pane_command(
    ctx: &ControlContext,
    args: &Value,
    private_pane_command: Option<&str>,
    allow_captain_workspace: bool,
    require_exact_tab: bool,
    forward_projection: bool,
) -> Result<Value, String> {
    spawn_terminal_with_private_pane_command_and_id(
        ctx,
        args,
        private_pane_command,
        allow_captain_workspace,
        require_exact_tab,
        forward_projection,
        None,
    )
}

fn spawn_terminal_with_private_pane_command_and_id(
    ctx: &ControlContext,
    args: &Value,
    private_pane_command: Option<&str>,
    allow_captain_workspace: bool,
    require_exact_tab: bool,
    forward_projection: bool,
    requested_session_id: Option<&str>,
) -> Result<Value, String> {
    let _identity_transaction = ctx.tabs.identity_transaction();
    let cwd = arg_str(args, "cwd");
    let name = arg_str(args, "name");
    let shell = arg_str(args, "shell");
    let startup_command =
        arg_str(args, "startupCommand").or_else(|| arg_str(args, "startup_command"));
    // Captain-chat phase 2: a captain spawning crew identifies itself so the
    // spawned session is recorded as crew in the captains registry.
    let spawned_by = arg_str(args, "spawnedBy").or_else(|| arg_str(args, "spawned_by"));
    if let Some(requested) = requested_session_id {
        if requested.len() != 8 || !requested.bytes().all(|byte| byte.is_ascii_alphanumeric()) {
            return Err(
                "spawn_terminal: requested session id must be eight alphanumeric bytes".into(),
            );
        }
    }

    // #27: a REMOTE peer may spawn ONLY with a cwd under the operator allowlist —
    // the spawn execs a shell SERVER-SIDE at a peer-controlled dir. Loopback (the
    // local frontend/MCP) is unrestricted. An absent cwd is fine (the UI spawns in
    // the shell's default dir).
    let cwd = match cwd {
        Some(c) if !ctx.peer_is_loopback => Some(
            files::scoped_create_path(&c, true, files::remote_file_roots())?
                .to_string_lossy()
                .into_owned(),
        ),
        other => other,
    };

    // A UI must exist to render the tile (webview sink or socket subscribers);
    // with neither, keep refusing rather than spawn a session nothing shows.
    if ctx.apply_sink.is_none() && ctx.fanout.subscriber_count() == 0 {
        return Err(
            "spawn_terminal: no UI is connected to adopt the new terminal tile; \
             refusing to spawn an untracked session (the app must be running to \
             spawn a terminal)"
                .to_string(),
        );
    }

    // Headless-org: resolve the TARGET TAB server-side, against the authoritative
    // registry, BEFORE spawning - `tabId` must exist (strict), `tabName` reuses an
    // existing tab or mints one (created hidden; the user's active tab is NOT
    // switched), and neither means the UI's active tab per the registry mirror.
    let tab_name = arg_str(args, "tabName").or_else(|| arg_str(args, "tab_name"));
    let tab_id = match (
        arg_str(args, "tabId").or_else(|| arg_str(args, "tab_id")),
        &tab_name,
    ) {
        (Some(id), _) => {
            if !ctx.tabs.has_tab(&id) {
                return Err(format!("spawn_terminal: unknown tabId '{id}'"));
            }
            if id == CAPTAIN_WORKSPACE_ID && !allow_captain_workspace {
                return Err(
                    "spawn_terminal: only durable Cortana or Captain identities may target Captain Workspace"
                        .into(),
                );
            }
            Some(id)
        }
        (None, Some(name)) if name == CAPTAIN_WORKSPACE_NAME || name == "Captains" => {
            if !allow_captain_workspace {
                return Err(
                    "spawn_terminal: only durable Cortana or Captain identities may target Captain Workspace"
                        .into(),
                );
            }
            ctx.tabs
                .insert_tab(CAPTAIN_WORKSPACE_ID, CAPTAIN_WORKSPACE_NAME);
            Some(CAPTAIN_WORKSPACE_ID.to_string())
        }
        (None, Some(name)) => Some(match ctx.tabs.id_for_name(name) {
            Some(id) => id,
            None => {
                let id = uuid::Uuid::new_v4().to_string();
                ctx.tabs.insert_tab(&id, name);
                id
            }
        }),
        // No target given: resolved atomically at placement time (active/first
        // tab) inside place_tile_with_fallback below.
        (None, None) => None,
    };

    // Spawn the tmux session SERVER-side (same id minting + pane wrap as the Tauri
    // `commands::spawn_terminal`) so the real id is known synchronously, the tile
    // can be placed in the registry atomically, and a hidden/suspended webview
    // cannot lose the spawn. Mirror `commands::resolve_cwd`'s unix arm ($HOME
    // fallback).
    let cwd_effective = cwd
        .clone()
        .unwrap_or_else(|| std::env::var("HOME").unwrap_or_default());
    let tmux_cwd = files::posix_form(&cwd_effective);
    let public_pane = crate::commands::pane_command(shell.as_deref(), startup_command.as_deref());
    let pane = private_pane_command.map(str::to_owned).or(public_pane);
    // Spawned terminals receive stable discovery plus a durable Crew identity.
    // Orchestration authority is acquired later from authoritative server state.
    let provider_harness = arg_str(args, "_providerHarness").or_else(|| {
        requested_session_id.and_then(|session_id| {
            ctx.captains
                .snapshot()
                .agent_sessions
                .into_iter()
                .find(|agent| agent.agent_session_id == session_id)
                .map(|agent| agent.provider)
        })
    });
    if let Some(provider_harness) = provider_harness.as_deref() {
        if !matches!(provider_harness, "codex" | "claude") {
            return Err("spawn_terminal: internal provider Harness marker is invalid".into());
        }
    }
    let (mut elevation, minted_identity) =
        spawn_env_with_identity(ctx, args, "spawn_terminal", requested_session_id)?;
    if let Some(provider_harness) = provider_harness {
        elevation.push((
            PROVIDER_SESSION_ENV.into(),
            pending_provider_marker(&provider_harness),
        ));
    }
    let spawn_result = match requested_session_id {
        Some(requested) => {
            spawn_tmux_terminal_with_id(requested, &tmux_cwd, pane.as_deref(), &elevation)
        }
        None => spawn_tmux_terminal(&tmux_cwd, pane.as_deref(), &elevation),
    };
    let (id, tmux_session) = match spawn_result {
        Ok(v) => v,
        Err(e) => {
            // Review L2: the mint persisted before this point, so a failed spawn would
            // leave an orphaned, secret-bearing identity for a session that never
            // existed. Retire it on the error leg.
            if let Some(identity) = &minted_identity {
                if let Err(rollback) = ctx.identity.retire(&identity.id) {
                    return Err(format!("{e}; identity rollback also failed: {rollback}"));
                }
            }
            return Err(e);
        }
    };
    // A requested id is pre-bound before tmux starts so a privileged child can never
    // observe a usable identity that is not yet tied to its durable AgentSession.
    // Generic terminal ids remain unknown until tmux returns and bind here.
    if let Some(identity) = minted_identity
        .as_ref()
        .filter(|_| requested_session_id.is_none())
    {
        if let Err(error) = ctx.identity.bind_tile(&identity.id, &id) {
            let _ = tmux::kill_session_tree(&tmux_session);
            let rollback = ctx.identity.retire(&identity.id);
            return Err(format!(
                "spawn_terminal: identity binding persistence failed and the terminal was rolled back: {error}{}",
                rollback
                    .err()
                    .map(|rollback| format!("; identity rollback also failed: {rollback}"))
                    .unwrap_or_default()
            ));
        }
    }

    // Atomic placement with fallback: if the resolved tab was closed in the race
    // window between spawn and placement, the tile lands in the active (else
    // first) tab instead - never orphaned outside the registry. The response
    // carries the ACTUAL placement.
    let placed_tab = if require_exact_tab {
        let exact = tab_id.as_deref().ok_or_else(|| {
            "spawn_terminal: exact placement requires an explicit tabId".to_string()
        });
        match exact.and_then(|tab_id| ctx.tabs.place_tile_exact(&id, tab_id)) {
            Ok(tab_id) => Some(tab_id),
            Err(error) => {
                let _ = tmux::kill_session_tree(&tmux_session);
                if let Some(identity) = &minted_identity {
                    if let Err(cleanup) = ctx.identity.retire(&identity.id) {
                        return Err(format!(
                            "spawn_terminal: exact Workspace placement failed; identity cleanup failed: {cleanup}"
                        ));
                    }
                }
                return Err(format!(
                    "spawn_terminal: exact Workspace placement failed and the terminal was rolled back: {error}"
                ));
            }
        }
    } else {
        ctx.tabs.place_tile_with_fallback(&id, tab_id.as_deref())
    };

    // A headless client may have no Work tab yet. Placement can be adopted by
    // the UI later; only exact placement is a hard requirement.
    if placed_tab.is_none() && require_exact_tab {
        let _ = tmux::kill_session_tree(&tmux_session);
        ctx.tabs.retire_tile_locked(&id);
        if let Some(identity) = &minted_identity {
            if let Err(error) = ctx.identity.retire(&identity.id) {
                return Err(format!(
                    "spawn_terminal: Workspace placement failed and identity cleanup failed: {error}"
                ));
            }
        }
        return Err(
            "spawn_terminal: Workspace placement failed and the terminal was rolled back".into(),
        );
    }

    // Captain-chat phase 2: record the crew link under the spawning captain.
    // The spawn NEVER fails on this - an unclaimed spawnedBy simply records
    // nothing (crewRecorded: false tells the caller to claim_captain first).
    let crew_recorded = match spawned_by.as_deref() {
        Some(cap) => match ctx.captains.record_crew(cap, &id) {
            Ok(recorded) => recorded,
            Err(error) => {
                let _ = tmux::kill_session_tree(&tmux_session);
                ctx.tabs.retire_tile_locked(&id);
                if let Some(identity) = &minted_identity {
                    if let Err(rollback) = ctx.identity.retire(&identity.id) {
                        return Err(format!(
                            "spawn_terminal: Crew registry persistence failed ({error}); identity rollback also failed: {rollback}"
                        ));
                    }
                }
                return Err(format!(
                    "spawn_terminal: Crew registry persistence failed and the terminal was rolled back: {error}"
                ));
            }
        },
        None => false,
    };
    if crew_recorded {
        let _ = captains_sync_apply(ctx);
    }

    let forward = with_sync(
        ctx,
        json!({
            "id": id,
            "tmuxSession": tmux_session,
            "cwd": cwd_effective,
            "name": name,
            "shell": shell,
            "startupCommand": startup_command,
            "tabId": placed_tab,
            "tabName": tab_name,
            "spawnedBy": spawned_by,
        }),
    );
    let applied = forward_projection && forward_apply(ctx, "spawn_terminal", &forward);
    Ok(json!({
        "accepted": "spawn_terminal",
        "id": id,
        "tmuxSession": tmux_session,
        "cwd": cwd_effective,
        "name": name,
        "shell": shell,
        "startupCommand": startup_command,
        "tabId": placed_tab,
        "placed": placed_tab.is_some(),
        "spawnedBy": spawned_by,
        "crewRecorded": crew_recorded,
        "audited": true,
        "applied": applied,
        "note": "the server spawned the session, placed the tile in the target tab \
                 in the authoritative registry (without switching the user's active \
                 tab), and forwarded the snapshot for the UI to render. tabId is the \
                 ACTUAL placement (falls back to the active tab if the target was \
                 closed mid-spawn).",
    }))
}

/// Mint a terminal id + create its detached tmux session. The id IS the tmux
/// session's own suffix, exactly like `commands::spawn_terminal` (bug #16 there:
/// id and session name must never disagree). Shared by the T12 native-path arms
/// of `spawn_terminal` / `create_worktree`, where no webview exists to run the
/// spawn client-side.
fn spawn_tmux_terminal(
    cwd: &str,
    command: Option<&str>,
    env: &[(String, String)],
) -> Result<(String, String), String> {
    let suffix = uuid::Uuid::new_v4().simple().to_string();
    let id = suffix[..8].to_string();
    spawn_tmux_terminal_with_id(&id, cwd, command, env)
}

fn spawn_tmux_terminal_with_id(
    id: &str,
    cwd: &str,
    command: Option<&str>,
    env: &[(String, String)],
) -> Result<(String, String), String> {
    let tmux_session = format!("th_{id}");
    let mut session_env = env.to_vec();
    if !session_env
        .iter()
        .any(|(key, _)| key == PROVIDER_SESSION_ENV)
    {
        session_env.push((PROVIDER_SESSION_ENV.into(), "none".into()));
    }
    // Phase 2b: `env` carries the capability token (+ addr) for the new session, set
    // via tmux `-e` so it is present BEFORE the first pane execs and never lands in
    // argv. Empty ⇒ a plain session (headless tests / addr unknown).
    tmux::new_session_with_env(&tmux_session, cwd, command, &session_env)
        .map_err(|e| format!("failed to create tmux session: {e}"))?;
    // Registry-vs-reality (Incident A/B, ask #3): never hand back an id whose tmux
    // session did not actually materialize. `new-session` returning success is not
    // enough - a session can fail to appear (a raced server teardown, a wsl.exe
    // relaunch dropping the detached session), and the caller would then place +
    // record a GHOST tile keyed to a session that never existed. Verifying
    // has-session here means the id is live BEFORE it is placed/recorded, so a
    // spawn that didn't take fails loudly (and idempotently retryable) instead of
    // registering a phantom.
    // `has_session` here is the ONE safe use of the boolean form under the
    // de-conflation: both `Gone` (spawn genuinely didn't take) and `Unknown`
    // (verify probe timed out) map to `false`, and the action for BOTH is identical
    // and safe - best-effort reap + a loud, idempotently-retryable failure. We must
    // NOT hand back an id we could not verify live (that is the Incident A/B ghost),
    // so an ambiguous verify deliberately fails-retryable rather than registering.
    if !tmux::has_session(&tmux_session) {
        // L1: a FALSE negative is possible (a has-session hiccup / TOCTOU / probe
        // timeout) - the session may in fact have come up. Returning Err WITHOUT
        // tearing it down
        // would orphan it: a live pane with no tile, invisible to close_terminal,
        // and (under a requestId) the failure is cached so the retry won't adopt
        // it. Best-effort reap the maybe-live session before failing, so a spawn
        // that DID take is killed, not leaked. Idempotent: a truly-absent session
        // is a no-op.
        let _ = tmux::kill_session_tree(&tmux_session);
        return Err(format!(
            "tmux session '{tmux_session}' did not materialize after new-session \
             (the spawn did not take; any partial session was reaped and nothing \
             was registered)"
        ));
    }
    Ok((id.to_string(), tmux_session))
}

/// comms-plane Phase 1: mark a BREAK-GLASS use of the demoted direct writers
/// (`send_text`/`send_keys`) LOUDLY. These are no longer the primary path - the
/// fleet wake and the in-app automation writers funnel through `plane` (path a/b) -
/// but they are DEMOTED, not DENIED (design H2): they still execute, so a human or
/// external script keeps its escape hatch. Every use emits a `t-hub-plane:`
/// break-glass log line AND a live `control://break-glass` fanout event so the
/// deviation is visible and cannot quietly become the primary path again (D11a).
///
/// HONEST LIMIT (Phase 1): break-glass rides the SHARED control token, so it is
/// attributed only as "some Full caller" (the command that deviated), not the
/// per-session identity - and it stays callable by every crew session until item 3
/// tiers the token away. This marker makes the deviation observable; it does not
/// yet make it impossible.
fn mark_break_glass(ctx: &ControlContext, command: &str, args: &Value) {
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .unwrap_or_default();
    let target = tmux_target(&session_id);
    // Payload size (length only, never content). `send_text` carries `text`;
    // `send_keys` carries its payload in the `keys` array, so fall back to the
    // joined key names - otherwise every `send_keys` marker would report bytes=0.
    let bytes = if let Some(text) = arg_str(args, "text") {
        text.len()
    } else {
        args.get("keys")
            .and_then(|v| v.as_array())
            .map(|arr| {
                arr.iter()
                    .filter_map(|k| k.as_str())
                    .collect::<Vec<_>>()
                    .join(" ")
                    .len()
            })
            .unwrap_or(0)
    };
    plane::note_break_glass(command, &target, bytes);
    ctx.fanout.emit_event(
        "control://break-glass",
        &json!({
            "command": command,
            "sessionId": session_id,
            "target": target,
            "bytes": bytes,
            "breakGlass": true,
            "note": "demoted direct writer used; NOT the plane primary path (Phase 1)",
        }),
    );
}

/// `send_text`: type literal `text` into an existing session, optionally pressing
/// Enter to submit it. Process-changing (PRD §11.2): the MCP tool description
/// marks it CONFIRMATION REQUIRED. Backend-only — drives tmux directly
/// (`send-keys -l`), no UI round trip. Args: `sessionId` + `text` (required),
/// `enter` (optional, default true). Requires the session to exist.
///
/// comms-plane Phase 1: DEMOTED to audited break-glass (see `mark_break_glass`).
/// It is no longer the fleet path; the wake injects via `plane::deliver_tmux`.
/// Liveness gate for the direct-writer break-glass commands (`send_text` /
/// `send_keys`): map a three-state probe to proceed / a DEFINITIVE "no such
/// session" / a RETRYABLE probe-timeout.
///
/// The `Unknown` arm is the spawn-wedge fix (de-conflation): a timed-out probe
/// must NEVER be reported as "no such session". That false negative is exactly
/// what made the app say sessions e05764f5/3647011c/68501753 were gone while tmux
/// held them alive, sending the fleet to raw-tmux break-glass on 0.3.62. The
/// caller is told the CONTROL PLANE is degraded (retry), not that its session died.
fn writer_liveness_gate(
    command: &str,
    session_id: &str,
    target: &str,
    liveness: tmux::SessionLiveness,
) -> Result<(), String> {
    match liveness {
        tmux::SessionLiveness::Alive => Ok(()),
        tmux::SessionLiveness::Gone => Err(format!(
            "{command}: no such session '{session_id}' (target {target})"
        )),
        tmux::SessionLiveness::Unknown => Err(retryable_error(format!(
            "{command}: liveness probe for '{session_id}' (target {target}) timed out; \
             session NOT confirmed gone — retry (the control plane is degraded, not the session)"
        ))),
    }
}

fn send_text(args: &Value) -> Result<Value, String> {
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("send_text requires a 'sessionId' argument")?;
    let text = arg_str(args, "text").ok_or("send_text requires a 'text' argument")?;
    let enter = args.get("enter").and_then(|v| v.as_bool()).unwrap_or(true);
    let target = tmux_target(&session_id);
    writer_liveness_gate(
        "send_text",
        &session_id,
        &target,
        tmux::session_liveness(&target),
    )?;
    tmux::send_text(&target, &text, enter)
        .map_err(|e| format!("failed to send text to '{session_id}': {e}"))?;
    Ok(json!({
        "accepted": "send_text",
        "sessionId": session_id,
        "target": target,
        "enter": enter,
        "audited": true,
    }))
}

/// `send_keys`: send one or more named control keys (e.g. `C-c`, `Up`, `Escape`)
/// to an existing session. Process-changing (confirmation-required). Backend-only
/// (`send-keys` with key-name interpretation). Args: `sessionId` (required) +
/// `keys` (required, a non-empty array of tmux key names).
fn send_keys(args: &Value) -> Result<Value, String> {
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("send_keys requires a 'sessionId' argument")?;
    let keys: Vec<String> = args
        .get("keys")
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|k| k.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default();
    if keys.is_empty() {
        return Err("send_keys requires a non-empty 'keys' array of tmux key names".into());
    }
    let target = tmux_target(&session_id);
    writer_liveness_gate(
        "send_keys",
        &session_id,
        &target,
        tmux::session_liveness(&target),
    )?;
    let key_refs: Vec<&str> = keys.iter().map(|s| s.as_str()).collect();
    tmux::send_keys(&target, &key_refs)
        .map_err(|e| format!("failed to send keys to '{session_id}': {e}"))?;
    Ok(json!({
        "accepted": "send_keys",
        "sessionId": session_id,
        "target": target,
        "keys": keys,
        "audited": true,
    }))
}

/// The action [`close_terminal`] takes for a given liveness probe + `force` flag.
enum ClosePlan {
    /// Reap the session (bounded, idempotent tree-kill). `existed` labels the
    /// outcome (`killed` vs `already_gone`); `forced` marks a force-escape reap of a
    /// session whose liveness stayed indeterminate.
    Kill { existed: bool, forced: bool },
    /// The probe timed out and `force` was not set: refuse with a RETRYABLE error
    /// (the de-conflation default - a wedge is not a death).
    RetryableTimeout,
    /// `force` was set but a fresh RE-PROBE CONFIRMED the session ALIVE: refuse.
    /// `force` never kills a session a re-probe reports `Alive` - that first
    /// `Unknown` was merely slowness. (This is the ONLY liveness state that refuses
    /// force; a re-probe that ALSO times out is `Unknown`, not `Alive`, and is
    /// force-reaped - see `plan_close`.)
    RefuseForceOnLive,
}

/// Decide [`close_terminal`]'s action with NO side effects (unit-testable). MED-1
/// (PR-58 review): `close_terminal` refusing every `Unknown` left a genuinely-dead-
/// but-unprobeable session unreapable under a wedge. `force:true` adds an escape:
///
/// - `Alive`            → `Kill{existed:true}`   (normal close of a live tile)
/// - `Gone`             → `Kill{existed:false}`  (idempotent already-gone)
/// - `Unknown`, `!force`→ `RetryableTimeout`     (retry once the plane recovers)
/// - `Unknown`, `force` → decided by a fresh `reprobe`:
///     * `reprobe==Alive`   → `RefuseForceOnLive` (re-probe CONFIRMS live: refuse)
///     * `reprobe==Gone`    → `Kill{existed:false}` (confirmed dead: clean reap)
///     * `reprobe==Unknown` → `Kill{forced:true}`   (still unreachable: forced reap)
///
/// The honest guarantee (NOT "never kills a live session"): force never kills a
/// session a fresh re-probe CONFIRMS `Alive`. Under a SUSTAINED wedge a live-but-
/// slow session's re-probe also returns `Unknown` - indistinguishable from dead -
/// and force WILL reap it. That is what `force:true` means: reap-during-wedge, at
/// the caller's risk. `reprobe` is `Some` ONLY when `force && initial==Unknown`;
/// otherwise `None`.
fn plan_close(
    force: bool,
    initial: tmux::SessionLiveness,
    reprobe: Option<tmux::SessionLiveness>,
) -> ClosePlan {
    use tmux::SessionLiveness::*;
    match initial {
        Alive => ClosePlan::Kill {
            existed: true,
            forced: false,
        },
        Gone => ClosePlan::Kill {
            existed: false,
            forced: false,
        },
        Unknown if !force => ClosePlan::RetryableTimeout,
        Unknown => match reprobe {
            Some(Alive) => ClosePlan::RefuseForceOnLive,
            Some(Gone) => ClosePlan::Kill {
                existed: false,
                forced: false,
            },
            // Still indeterminate (or, defensively, no reprobe supplied): the
            // operator asserted death and a fresh probe could not contradict it -
            // perform the bounded forced reap. `kill_session_tree` is idempotent, so
            // if the session was in fact already gone this is a clean no-op.
            _ => ClosePlan::Kill {
                existed: false,
                forced: true,
            },
        },
    }
}

/// `close_terminal`: kill an existing session and its process tree. Process-
/// changing/destructive (confirmation-required). Backend-only via tmux
/// `kill_session_tree` - the same guarantee the webview's `kill_terminal`
/// gives: `kill-session` alone only SIGHUPs, which agents like `claude`
/// survive and leak; the tree kill SIGKILLs the pane's descendants first.
/// Idempotent (already-gone ⇒ success).
///
/// Headless-org: the dead tile is also dropped from the server tab registry and
/// a `sync_tabs` snapshot is forwarded, so the tile leaves its tab cleanly even
/// when that tab is hidden or the window is minimized (previously removal relied
/// on the UI's ~5s live-terminal reconcile). Args: `sessionId` (required),
/// `force` (optional bool).
///
/// **`force` (MED-1 operator escape).** By default an `Unknown` liveness probe (a
/// timed-out/failed probe under a degraded spawn path) is REFUSED as retryable -
/// we never run a destructive tree-kill we cannot verify. But that leaves a
/// genuinely-dead-but-unprobeable session unreapable during a wedge. `force:true`
/// re-probes once and, if the session is STILL not confirmably alive, performs the
/// bounded reap anyway (outcome `force_reaped`).
///
/// The guarantee is NARROW and honest: force never kills a session a fresh re-probe
/// reports `Alive`. It is NOT "never kills a live session" - under a SUSTAINED wedge
/// a live-but-slow session's re-probe also times out (`Unknown`), which is
/// probe-indistinguishable from dead, and force WILL reap it. `force:true` therefore
/// means "reap this tile even if it turns out to be live-but-unreachable - I accept
/// that risk," so use it ONLY when you have independent reason to believe the session
/// is DEAD (its work finished, its process is gone) and a wedge is merely blocking
/// the reap. **⚠ Do NOT reach for `force` to work around slowness on a session you
/// think may still be live** - retry a normal `close_terminal` (no force) first; a
/// normal close reaps a confirmed-`Alive` session cleanly and refuses on `Unknown`.
/// If a forced close is refused, the re-probe confirmed the tile LIVE - investigate,
/// do not re-force.
fn close_terminal_authorized(
    ctx: &ControlContext,
    args: &Value,
    caller: Option<&ResolvedIdentity>,
    trusted_internal: bool,
) -> Result<Value, String> {
    require_socket_identity(caller, trusted_internal, "close_terminal")?;
    let target = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("close_terminal requires a 'sessionId' argument")?;
    // Authorize the target from ownership-only registry state before checking
    // historical Removed Crew state, which can lead to Project and Powder scope
    // resolution. Foreign callers must not use close as a binding-state oracle.
    let delegated_caller = caller.filter(|caller| {
        ctx.delegated_admin
            .grants_for_actor(&caller.session_id)
            .iter()
            .any(|grant| grant.state.is_active())
    });
    let (captain_authority, delegated_authority) = if let Some(caller) = delegated_caller {
        (
            None,
            Some(authorize_delegated_cleanup(ctx, args, caller, &target)?),
        )
    } else {
        (
            enforce_target_lifecycle_authority(ctx, caller, trusted_internal, &target)?,
            None,
        )
    };
    let delegated_audit = delegated_authority
        .as_ref()
        .map(|authority| authority.audit.clone());
    let target_identity_id = ctx.identity.for_tile(&target).map(|identity| identity.id);
    let removed_crew = match ctx.captains.removed_crew_powder_ship(&target) {
        Ok(removed_crew) => removed_crew,
        Err(error) => {
            let result = Err(error);
            record_delegated_admin_outcome(ctx, delegated_audit.as_ref(), &result);
            return result;
        }
    };
    if removed_crew.is_some() {
        let result =
            reconcile_removed_crew_powder_binding(ctx, caller, &target).and_then(|value| {
                invalidate_retired_admin_identity(ctx, target_identity_id.as_deref(), &target)?;
                Ok(value)
            });
        record_delegated_admin_outcome(ctx, delegated_audit.as_ref(), &result);
        return result;
    }
    let authority = captain_authority
        .map(CloseLifecycleAuthority::Captain)
        .or_else(|| {
            delegated_authority
                .map(|authority| CloseLifecycleAuthority::Delegated(Box::new(authority)))
        });
    let result =
        close_terminal_with_policy(ctx, args, false, authority.as_ref()).and_then(|value| {
            invalidate_retired_admin_identity(ctx, target_identity_id.as_deref(), &target)?;
            Ok(value)
        });
    record_delegated_admin_outcome(ctx, delegated_audit.as_ref(), &result);
    result
}

fn authorize_delegated_cleanup(
    ctx: &ControlContext,
    args: &Value,
    caller: &ResolvedIdentity,
    target: &str,
) -> Result<DelegatedCleanupAuthority, String> {
    let approval_id = arg_str(args, "approvalId")
        .filter(|approval_id| !approval_id.trim().is_empty())
        .ok_or("delegated admin: close_terminal requires an exact supervisor approvalId")?;
    let admin_target = delegated_admin_target_for_terminal(ctx, target)?;
    let grant = ctx
        .delegated_admin
        .grants_for_actor(&caller.session_id)
        .into_iter()
        .find(|grant| grant.state.is_active())
        .ok_or("delegated admin: caller has no active administrative grant")?;
    let supervisor = current_delegating_supervisor(ctx, &grant);
    let actor = current_admin_actor(ctx, &grant);
    let consumed_approval = ctx
        .delegated_admin
        .consume_exact_approval(
            &approval_id,
            &crate::delegated_admin::AdminActor {
                identity_id: caller.session_id.clone(),
                session_tile: caller.tile.clone(),
                ..actor
            },
            &supervisor,
            crate::delegated_admin::AdminOperation::CleanupSession,
            &admin_target,
        )
        .map_err(|error| format!("{}: {error}", error.code()))?;
    let audit = authorize_delegated_admin(
        ctx,
        caller,
        crate::delegated_admin::AdminOperation::CleanupSession,
        admin_target,
        crate::delegated_admin::AdminSafeguards {
            authoritative_ownership_verified: true,
            consumed_approval: Some(consumed_approval.clone()),
            worktree_safety: None,
        },
    )?;
    Ok(DelegatedCleanupAuthority {
        audit,
        consumed_approval,
    })
}

fn invalidate_retired_admin_identity(
    ctx: &ControlContext,
    identity_id: Option<&str>,
    terminal_id: &str,
) -> Result<(), String> {
    let Some(identity_id) = identity_id else {
        return Ok(());
    };
    ctx.delegated_admin
        .invalidate_actor(
            identity_id,
            format!("administrative actor terminal '{terminal_id}' was retired"),
        )
        .map_err(|error| format!("{}: {error}", error.code()))?;
    ctx.delegated_admin
        .invalidate_delegator(
            identity_id,
            format!("delegating supervisor terminal '{terminal_id}' was retired"),
        )
        .map_err(|error| format!("{}: {error}", error.code()))?;
    Ok(())
}

#[derive(Debug, Clone)]
struct DelegatedCleanupAuthority {
    audit: crate::delegated_admin::AdminAuditContext,
    consumed_approval: crate::delegated_admin::ConsumedExactApproval,
}

#[derive(Debug, Clone)]
enum CloseLifecycleAuthority {
    Captain(TargetLifecycleAuthority),
    Delegated(Box<DelegatedCleanupAuthority>),
}

fn revalidate_close_lifecycle_authority(
    ctx: &ControlContext,
    authority: &CloseLifecycleAuthority,
) -> Result<(), String> {
    match authority {
        CloseLifecycleAuthority::Captain(authority) => {
            revalidate_target_lifecycle_authority(ctx, authority)
        }
        CloseLifecycleAuthority::Delegated(authority) => {
            let current_target = match &authority.audit.target {
                crate::delegated_admin::AdminTarget::CrewSession { session_id, .. } => {
                    delegated_admin_target_for_terminal(ctx, session_id)?
                }
                crate::delegated_admin::AdminTarget::Captain {
                    captain_identity_id,
                    ..
                } => {
                    let terminal_id = ctx
                        .identity
                        .get(captain_identity_id)
                        .and_then(|identity| identity.session_tile)
                        .ok_or("delegated admin: Captain target lost its authoritative terminal")?;
                    delegated_admin_target_for_terminal(ctx, &terminal_id)?
                }
                _ => {
                    return Err(
                        "delegated admin: cleanup authority has an invalid session target".into(),
                    );
                }
            };
            if current_target != authority.audit.target {
                return Err(
                    "delegated admin: exact target ownership changed before terminal teardown"
                        .into(),
                );
            }
            let grant = ctx
                .delegated_admin
                .get(&authority.audit.grant_id)
                .filter(|grant| {
                    grant.state.is_active()
                        && grant.grant_generation == authority.audit.grant_generation
                        && grant.actor_identity_id == authority.audit.actor_identity_id
                })
                .ok_or("delegated admin: cleanup authority changed before terminal teardown")?;
            let supervisor = current_delegating_supervisor(ctx, &grant);
            let actor = current_admin_actor(ctx, &grant);
            ctx.delegated_admin
                .authorize(
                    &crate::delegated_admin::AdminActor {
                        identity_id: authority.audit.actor_identity_id.clone(),
                        session_tile: authority.audit.actor_session_tile.clone(),
                        ..actor
                    },
                    &supervisor,
                    crate::delegated_admin::AdminOperation::CleanupSession,
                    &authority.audit.target,
                    &crate::delegated_admin::AdminSafeguards {
                        authoritative_ownership_verified: true,
                        consumed_approval: Some(authority.consumed_approval.clone()),
                        worktree_safety: None,
                    },
                )
                .map(|_| ())
                .map_err(|error| format!("{}: {error}", error.code()))
        }
    }
}

fn reconcile_removed_crew_powder_binding(
    ctx: &ControlContext,
    caller: Option<&ResolvedIdentity>,
    crew_session_id: &str,
) -> Result<Value, String> {
    // Removed Crew records are historical tombstones. Their old Powder binding
    // remains deserializable and addressable for compatibility, but close must
    // never turn a tombstone lookup into a live Powder read or mutation.
    let _ = (ctx, caller);
    Ok(json!({
        "accepted": "close_terminal",
        "sessionId": crew_session_id,
        "target": tmux_target(crew_session_id),
        "outcome": "already_gone",
        "powderRelease": {
            "released": false,
            "outcome": "retired",
        },
        "crewBindingRetained": true,
        "audited": true,
    }))
}

fn close_terminal(ctx: &ControlContext, args: &Value) -> Result<Value, String> {
    close_terminal_with_policy(ctx, args, false, None)
}

#[allow(dead_code)]
fn retain_crew_binding_after_powder_failure(
    preserve_on_failure: bool,
    cleanup_was_pending: bool,
    completion_recovery_required: bool,
    has_powder_binding: bool,
    powder_release: Option<&Value>,
) -> bool {
    (preserve_on_failure
        || cleanup_was_pending
        || completion_recovery_required
        || has_powder_binding)
        && powder_release
            .is_some_and(|release| release.get("released").and_then(Value::as_bool) != Some(true))
}

fn freeze_close_terminal_powder_release(
    ctx: &ControlContext,
    crew_session_id: &str,
) -> Result<(u64, Option<PendingDispatchRelease>), String> {
    let snapshot = ctx.captains.snapshot();
    let matching_crew = snapshot
        .captains
        .iter()
        .flat_map(|captain| captain.crew.iter())
        .filter(|crew| crew.terminal_id == crew_session_id)
        .collect::<Vec<_>>();
    let crew = match matching_crew.as_slice() {
        [] => return Ok((snapshot.seq, None)),
        [crew] => *crew,
        _ => {
            return Err(format!(
                "Crew session '{crew_session_id}' is ambiguously assigned to multiple Captains"
            ));
        }
    };
    let _legacy_work = crew.powder_work.as_ref();
    Ok((snapshot.seq, None))
}

fn close_terminal_with_policy(
    ctx: &ControlContext,
    args: &Value,
    _preserve_crew_on_powder_failure: bool,
    authority: Option<&CloseLifecycleAuthority>,
) -> Result<Value, String> {
    let session_id = arg_str(args, "sessionId")
        .or_else(|| arg_str(args, "session_id"))
        .ok_or("close_terminal requires a 'sessionId' argument")?;
    let force = args.get("force").and_then(|v| v.as_bool()).unwrap_or(false);
    let target = tmux_target(&session_id);
    let tile_id = session_id.strip_prefix("th_").unwrap_or(&session_id);
    // Serialize the entire terminal-close transaction with completion,
    // renewal, and cleanup for this Crew. The guard must precede liveness and
    // tmux teardown so a close queued behind completion cannot kill the worker
    // before the authoritative Powder transition converges.
    let _operation_guard = ctx
        .captains
        .serialize_crew_powder_operation(tile_id, CrewPowderOperationKind::Cleanup);
    if let Some(authority) = authority {
        revalidate_close_lifecycle_authority(ctx, authority)?;
    }
    // Probe and choose the requested effect before preparing durable state.
    // A refused close therefore leaves no cleanup intent for startup recovery
    // to misinterpret as authority to force-reap the terminal.
    let initial = tmux::session_liveness(&target);
    let reprobe = if force && matches!(initial, tmux::SessionLiveness::Unknown) {
        Some(tmux::session_liveness(&target))
    } else {
        None
    };
    let (existed, forced) = match plan_close(force, initial, reprobe) {
        ClosePlan::Kill { existed, forced } => (existed, forced),
        ClosePlan::RetryableTimeout => {
            return Err(retryable_error(format!(
                "close_terminal: liveness probe for '{session_id}' (target {target}) timed out; \
                 session NOT confirmed gone — retry once the control plane recovers, or pass \
                 force:true to reap a session you know is dead (refusing an unverifiable tree-kill)"
            )));
        }
        ClosePlan::RefuseForceOnLive => {
            return Err(format!(
                "close_terminal: force refused — a re-probe shows session '{session_id}' (target \
                 {target}) is LIVE; the earlier probe was merely slow, not dead. Retry a normal \
                 close_terminal (no force) to reap it."
            ));
        }
    };
    let fleet_operation = match ctx.captains.pending_close_terminal_operation(tile_id) {
        Some(operation) => operation,
        None => {
            let (expected_seq, powder_release) =
                freeze_close_terminal_powder_release(ctx, tile_id)?;
            #[cfg(test)]
            ctx.captains.pause_dispatch("close_terminal_scope_frozen");
            ctx.captains
                .prepare_close_terminal_operation(tile_id, expected_seq, powder_release)?
        }
    };
    #[cfg(test)]
    ctx.captains.pause_dispatch("close_terminal_effect");
    // Registry-vs-reality (Incident C, ask #3): `kill_session_tree` is idempotent -
    // it returns Ok for an already-gone session too - so a caller could never tell
    // a real kill from a phantom close (ghost ids f0f3207b / 709c7252). Probe
    // liveness BEFORE the kill so we can report an HONEST outcome. We check first
    // (not the kill's own status) because the tree sweep SIGKILLs the pane pids,
    // which can auto-destroy the session before `kill-session` runs, making a real
    // kill look already-gone. The kill stays idempotent; only the label is refined.
    //
    // De-conflation (spawn-wedge) + MED-1 force escape: an `Unknown` probe means the
    // control plane is degraded, not that the session is gone, so the DEFAULT refuses
    // (retryable). `force:true` re-probes ONCE and reaps unless that re-probe CONFIRMS
    // `Alive` (only a definitive Alive refuses force). Under a sustained wedge a live-
    // but-slow session's re-probe is also `Unknown` - indistinguishable from dead - so
    // force reaps it too; force is a deliberate reap-during-wedge override, not a
    // never-touch-a-live-session guarantee. See `plan_close`.
    if let Err(error) = tmux::kill_session_tree(&target) {
        return Err(retryable_error(format!(
            "failed to close terminal '{session_id}': {error}; durable close recovery remains prepared"
        )));
    }
    // The terminal is now definitely stopped. Powder claims and release
    // recoveries are retired compatibility data, so close only commits the
    // local terminal/tombstone transition and never contacts Powder.
    let committed = Some(ctx.captains.commit_close_terminal_operation(
        &fleet_operation,
        false,
        None,
    )?);
    let outcome = if forced {
        "force_reaped"
    } else if existed {
        "killed"
    } else {
        "already_gone"
    };
    // The registry keys tiles by the bare terminal id; strip an already-prefixed
    // caller the same way tmux_target normalizes the other direction.
    if let Some(committed) = committed {
        ctx.tabs.replace(ctx.captains.workspace_projection());
        if committed.workspace_changed || ctx.tabs.retire_tile_locked(tile_id) {
            let _ = forward_apply(ctx, "sync_tabs", &with_sync(ctx, json!({})));
        }
        // Captain-chat phase 2: a dead session leaves the captains registry too -
        // its captaincy is released and it drops out of every crew list.
        if committed.captain_state_changed {
            let _ = captains_sync_apply(ctx);
        }
        // Comms-plane Phase 2 (review M3): a dead session's per-session identity is
        // retired too, so its secret stops resolving and the identity store does not
        // accrete dead sessions (it is bounded to live + not-yet-closed sessions).
        ctx.identity.retire_tile(tile_id)?;
    }
    // The provider transcript remains intact and is now resumable. Force the next
    // History read to observe any final transcript write immediately.
    notify_history_changed(ctx, "terminal-closed");
    Ok(json!({
        "accepted": "close_terminal",
        "sessionId": session_id,
        "target": target,
        // killed = a live session was reaped; already_gone = nothing was there to
        // kill (idempotent no-op); force_reaped = an operator force:true reaped a
        // session whose liveness stayed indeterminate. ok:true in every case, so a
        // retry stays safe.
        "outcome": outcome,
        "powderRelease": {
            "released": false,
            "outcome": "retired",
        },
        "crewBindingRetained": false,
        "audited": true,
    }))
}

/// Resolve a caller-supplied session id to its tmux target name on the `t-hub`
/// socket. The control listener lists terminals by stripping the `th_` prefix
/// (see [`list_terminals`]), so a bare id maps back to `th_<id>`. We also accept a
/// caller that already passed the full `th_`-prefixed name (idempotent).
fn tmux_target(session_id: &str) -> String {
    // Single shared derivation (must match commands.rs / remote_pty so client +
    // server attach to the SAME session). See tmux::target_for_id.
    tmux::target_for_id(session_id)
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Pull a string field out of a JSON args object.
fn arg_str(args: &Value, key: &str) -> Option<String> {
    args.get(key)
        .and_then(|v| v.as_str())
        .map(|s| s.to_string())
}

/// Collect a `HostMetrics`-shaped snapshot from the local system. On Linux/WSL
/// this reads `/proc`; on other platforms it returns a best-effort skeleton so
/// the tool still responds. Mirrors the agent's `host` collector shape.
fn collect_host_metrics() -> Value {
    let now_ms = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0);

    #[cfg(target_os = "linux")]
    {
        let (mem_total, mem_avail, swap_total, swap_free) = read_meminfo();
        let load_avg = read_loadavg();
        let cpu_count = std::thread::available_parallelism()
            .map(|n| n.get() as u32)
            .unwrap_or(0);
        let process_count = count_procs();
        let distro = read_pretty_name();
        json!({
            "memTotalKib": mem_total,
            "memAvailableKib": mem_avail,
            "swapTotalKib": swap_total,
            "swapFreeKib": swap_free,
            "cpuCount": cpu_count,
            "loadAvg": load_avg,
            "processCount": process_count,
            "distro": distro,
            "capturedAtMs": now_ms,
        })
    }
    #[cfg(not(target_os = "linux"))]
    {
        let cpu_count = std::thread::available_parallelism()
            .map(|n| n.get() as u32)
            .unwrap_or(0);
        json!({
            "memTotalKib": 0u64,
            "memAvailableKib": 0u64,
            "swapTotalKib": 0u64,
            "swapFreeKib": 0u64,
            "cpuCount": cpu_count,
            "loadAvg": [0.0, 0.0, 0.0],
            "processCount": 0u32,
            "distro": serde_json::Value::Null,
            "capturedAtMs": now_ms,
        })
    }
}

#[cfg(target_os = "linux")]
fn read_meminfo() -> (u64, u64, u64, u64) {
    let text = std::fs::read_to_string("/proc/meminfo").unwrap_or_default();
    let get = |key: &str| -> u64 {
        for line in text.lines() {
            if let Some(rest) = line.strip_prefix(key) {
                return rest
                    .trim()
                    .trim_end_matches("kB")
                    .trim()
                    .parse()
                    .unwrap_or(0);
            }
        }
        0
    };
    (
        get("MemTotal:"),
        get("MemAvailable:"),
        get("SwapTotal:"),
        get("SwapFree:"),
    )
}

#[cfg(target_os = "linux")]
fn read_loadavg() -> [f32; 3] {
    let text = std::fs::read_to_string("/proc/loadavg").unwrap_or_default();
    let mut it = text.split_whitespace();
    let p = |s: Option<&str>| s.and_then(|v| v.parse().ok()).unwrap_or(0.0);
    [p(it.next()), p(it.next()), p(it.next())]
}

#[cfg(target_os = "linux")]
fn count_procs() -> u32 {
    std::fs::read_dir("/proc")
        .map(|rd| {
            rd.filter_map(|e| e.ok())
                .filter(|e| {
                    e.file_name()
                        .to_str()
                        .map(|n| n.chars().all(|c| c.is_ascii_digit()))
                        .unwrap_or(false)
                })
                .count() as u32
        })
        .unwrap_or(0)
}

#[cfg(target_os = "linux")]
fn read_pretty_name() -> Option<String> {
    let text = std::fs::read_to_string("/etc/os-release").ok()?;
    for line in text.lines() {
        if let Some(rest) = line.strip_prefix("PRETTY_NAME=") {
            return Some(rest.trim_matches('"').to_string());
        }
    }
    None
}

// ---------------------------------------------------------------------------
// Construction from app state
// ---------------------------------------------------------------------------

impl ControlContext {
    /// Build a [`ControlContext`] from the app's shared state. `supervisor` is a
    /// closure that locks the bridge's `Supervisor` and runs a visitor — supplied
    /// by `lib.rs` so this module doesn't reach into `AgentBridge` internals.
    pub fn new(
        status: Arc<StatusBridge>,
        supervisor: Arc<dyn Fn(&mut dyn FnMut(&Supervisor)) + Send + Sync>,
        token: String,
    ) -> Self {
        #[cfg(not(test))]
        let provider_capacity: ProviderCapacityFn = Arc::new(|| {
            provider_capacity_from_environment(std::env::var("T_HUB_PROVIDER_SESSION_CAPACITY"))
        });
        #[cfg(not(test))]
        let provider_live_sessions: ProviderLiveSessionsFn =
            Arc::new(inspect_provider_live_sessions);
        // Most existing unit tests exercise unrelated control behavior. They get
        // explicit deterministic provider evidence, while dedicated regressions
        // replace this closure with unavailable and exhausted evidence.
        #[cfg(test)]
        let provider_capacity: ProviderCapacityFn = Arc::new(|| {
            Ok(ProviderCapacityEvidence {
                session_capacity: crate::governor::HARD_SESSION_CEILING,
                status: crate::governor::ProviderCapacityStatus {
                    source: "deterministic-test-evidence".into(),
                    degraded: false,
                    detail: None,
                },
            })
        });
        #[cfg(test)]
        let provider_live_sessions: ProviderLiveSessionsFn = Arc::new(|_, sessions| {
            Ok(sessions
                .iter()
                .filter(|session| session.starts_with("th_"))
                .count())
        });
        Self {
            status,
            history: crate::history::HistoryService::from_env(),
            supervisor,
            files: Arc::new(files::FileIndexState::new()),
            apply_sink: None,
            fanout: Arc::new(EventFanout::new()),
            metrics: None,
            provider_capacity,
            provider_live_sessions,
            live_sessions: Arc::new(|| tmux::list_sessions().map_err(|error| error.to_string())),
            tabs: Arc::new(TabRegistry::new()),
            captains: Arc::new(CaptainsRegistry::new()),
            dispatch_reservations: Arc::new(DispatchReservations::default()),
            dispatch_admission: Arc::new(Mutex::new(())),
            fleet_watches: Arc::new(crate::fleet::FleetWatchRegistry::new()),
            idle_timeout: CONN_READ_TIMEOUT,
            attach_write_timeout: ATTACH_WRITE_TIMEOUT,
            max_attach_forwarders: MAX_ATTACH_FORWARDERS,
            attach_keepalive_interval: ATTACH_KEEPALIVE_INTERVAL,
            peer_is_loopback: true,
            token,
            read_token: String::new(),
            host_token: format!(
                "{}{}",
                uuid::Uuid::new_v4().simple(),
                uuid::Uuid::new_v4().simple()
            ),
            addr: String::new(),
            listener_instance_id: uuid::Uuid::new_v4().simple().to_string(),
            listener_generation: Arc::new(AtomicU64::new(0)),
            governor: Arc::new(SpawnGovernor::from_env()),
            audit: Arc::new(AuditLog::from_env()),
            requests: Arc::new(RequestCache::new()),
            rebind: Arc::new(RebindController::new(REBIND_MIN_INTERVAL)),
            identity: Arc::new(crate::identity::IdentityStore::ephemeral()),
            control_leases: Arc::new(CaptainControlLeases::default()),
            inbox: Arc::new(crate::inbox::Inbox::ephemeral()),
            authz: Arc::new(crate::authz::AuthzStore::ephemeral()),
            delegated_admin: Arc::new(crate::delegated_admin::DelegatedAdminStore::ephemeral()),
        }
    }

    /// Attach the per-launch **read** capability token (socket-gate Phase 2).
    /// `lib.rs` mints it alongside the control token; headless tests set a known
    /// value so they can exercise read-only capability resolution.
    pub fn with_read_token(mut self, read_token: String) -> Self {
        self.read_token = read_token;
        self
    }

    /// Replace the [`SpawnGovernor`] (tests inject tiny limits; production keeps the
    /// env-configured one from [`new`](Self::new)).
    #[cfg(test)]
    pub fn with_governor(mut self, governor: Arc<SpawnGovernor>) -> Self {
        self.governor = governor;
        self
    }

    #[cfg(test)]
    fn with_provider_capacity(
        mut self,
        provider_capacity: impl Fn() -> Result<usize, String> + Send + Sync + 'static,
    ) -> Self {
        self.provider_capacity = Arc::new(move || {
            provider_capacity().map(|session_capacity| ProviderCapacityEvidence {
                session_capacity,
                status: crate::governor::ProviderCapacityStatus {
                    source: "injected-test-evidence".into(),
                    degraded: false,
                    detail: None,
                },
            })
        });
        self
    }

    #[cfg(test)]
    fn with_provider_capacity_evidence(
        mut self,
        provider_capacity: impl Fn() -> Result<ProviderCapacityEvidence, String> + Send + Sync + 'static,
    ) -> Self {
        self.provider_capacity = Arc::new(provider_capacity);
        self
    }

    #[cfg(test)]
    fn with_provider_live_sessions(
        mut self,
        provider_live_sessions: impl Fn(&[String]) -> Result<usize, String> + Send + Sync + 'static,
    ) -> Self {
        self.provider_live_sessions = Arc::new(move |_, sessions| provider_live_sessions(sessions));
        self
    }

    #[cfg(test)]
    fn with_live_sessions(
        mut self,
        live_sessions: impl Fn() -> Result<Vec<String>, String> + Send + Sync + 'static,
    ) -> Self {
        self.live_sessions = Arc::new(live_sessions);
        self
    }

    /// Replace the [`AuditLog`]. Tests point it at a temp dir so they never write to
    /// the real `~/.t-hub/audit`; item-3 also uses it in production to SHARE one audit
    /// sink between the control server and the Tauri UI spawn path (single hash chain).
    pub fn with_audit(mut self, audit: Arc<AuditLog>) -> Self {
        self.audit = audit;
        self
    }

    /// The shared tab registry (TASK C / #22). `lib.rs` grabs this before starting
    /// the listener and `.manage()`s the same `Arc` so the `report_workspace_tabs`
    /// Tauri command feeds reports into the very registry `list_tabs` reads.
    pub fn tab_registry(&self) -> Arc<TabRegistry> {
        self.tabs.clone()
    }

    /// Attach an externally-shared [`TabRegistry`] (so the Tauri report command and
    /// the control listener see one registry). Builder-style; headless tests keep
    /// the private empty one from [`new`](Self::new).
    pub fn with_tab_registry(mut self, tabs: Arc<TabRegistry>) -> Self {
        self.tabs = tabs;
        self
    }

    /// Attach a persistent [`CaptainsRegistry`] (captain-chat phase 2). `lib.rs`
    /// builds it with [`CaptainsRegistry::load`] over [`captains_path`] so claims
    /// survive app restarts; headless tests keep the in-memory one from
    /// [`new`](Self::new).
    pub fn with_captains_registry(mut self, captains: Arc<CaptainsRegistry>) -> Self {
        self.captains = captains;
        self
    }

    /// Replace the History service. Tests use isolated provider roots; production
    /// keeps the provider-home service created by [`new`](Self::new).
    pub fn with_history_service(mut self, history: Arc<crate::history::HistoryService>) -> Self {
        self.history = history;
        self
    }

    /// Share the [`crate::fleet::FleetWatchRegistry`] with the fleet notifier so
    /// `watch_fleet` / `unwatch_fleet` arm the same registry the notifier reads.
    /// `lib.rs` builds the `Arc` once and hands the same clone to the notifier;
    /// headless tests keep the in-memory one from [`new`](Self::new).
    pub fn with_fleet_watches(mut self, watches: Arc<crate::fleet::FleetWatchRegistry>) -> Self {
        self.fleet_watches = watches;
        self
    }

    /// Attach the persistent per-session [`crate::identity::IdentityStore`]
    /// (comms-plane Phase 2). `lib.rs` builds it with `IdentityStore::load` over
    /// `identities.json` so bindings survive restarts and shares the same `Arc`;
    /// headless tests keep the ephemeral one from [`new`](Self::new).
    pub fn with_identity_store(mut self, identity: Arc<crate::identity::IdentityStore>) -> Self {
        self.identity = identity;
        self
    }

    /// Attach the durable [`crate::inbox::Inbox`] (comms-plane Phase 2). `lib.rs`
    /// builds it with `Inbox::open` over `~/.t-hub/inbox/` and shares the same `Arc`
    /// with the fleet notifier (the inbox's first client); headless tests keep the
    /// ephemeral one from [`new`](Self::new).
    pub fn with_inbox(mut self, inbox: Arc<crate::inbox::Inbox>) -> Self {
        self.inbox = inbox;
        self
    }

    /// Attach the durable [`crate::authz::AuthzStore`] (comms-plane Phase 3 delegation-
    /// gate carrier). `lib.rs` builds it with `AuthzStore::load` over
    /// `authorizations.json` and shares the same `Arc`; headless tests keep the
    /// ephemeral one from [`new`](Self::new).
    pub fn with_authz(mut self, authz: Arc<crate::authz::AuthzStore>) -> Self {
        self.authz = authz;
        self
    }

    pub fn with_delegated_admin(
        mut self,
        delegated_admin: Arc<crate::delegated_admin::DelegatedAdminStore>,
    ) -> Self {
        self.delegated_admin = delegated_admin;
        self
    }

    /// Share the [`EventFanout`] that backend events fan out through, so a
    /// control connection that subscribes ([`SUBSCRIBE_COMMAND`]) receives the live
    /// event stream (server-split M1). `lib.rs` builds the `Arc` once and hands the
    /// same clone to the socket emitter, so emits and subscribers meet here.
    pub fn with_event_fanout(mut self, fanout: Arc<EventFanout>) -> Self {
        self.fanout = fanout;
        self
    }

    /// Attach the [`ApplySink`] that forwards Organization-tier UI mutations to
    /// the frontend (a `control://apply` Tauri event). Builder-style so `lib.rs`
    /// can wire it after constructing the context, while headless tests/proofs
    /// keep the sink-less context (they audit without applying).
    pub fn with_apply_sink(mut self, sink: Arc<dyn ApplySink>) -> Self {
        self.apply_sink = Some(sink);
        self
    }

    /// Attach the agent-bridge host-metrics RPC (server-split M3, overlay source
    /// #5). Builder-style so `lib.rs` wires it from `AgentBridge` after construction
    /// while headless tests keep the metrics-less context (they fall back to local
    /// `/proc` on Linux, or report the missing bridge elsewhere). See [`MetricsFn`].
    pub fn with_metrics(mut self, metrics: MetricsFn) -> Self {
        self.metrics = Some(metrics);
        self
    }

    /// Test/proof constructor: build a context directly over a shared
    /// `Mutex<Supervisor>` (and a status bridge), wiring the visitor closure
    /// internally. Lets the end-to-end integration test seed real supervision +
    /// status state, start a real listener, and exercise the real `t-hub-mcp`
    /// binary against it — without standing up the whole Tauri app.
    #[doc(hidden)]
    pub fn with_shared_supervisor(
        status: Arc<StatusBridge>,
        supervisor: Arc<parking_lot::Mutex<Supervisor>>,
        token: String,
    ) -> Self {
        let sup = supervisor.clone();
        let visitor: Arc<dyn Fn(&mut dyn FnMut(&Supervisor)) + Send + Sync> =
            Arc::new(move |f: &mut dyn FnMut(&Supervisor)| {
                let guard = sup.lock();
                f(&guard);
            });
        Self::new(status, visitor, token)
    }
}

