    fn powder_criterion(index: usize, checked: bool) -> powder::CriterionEvidence {
        powder::CriterionEvidence {
            criterion: index,
            text: format!("Criterion {index}"),
            checked_by: checked.then(|| "captain-powder".into()),
            checked_at: checked.then_some(123),
            proof_links: vec![],
        }
    }

    fn powder_run_criterion(
        card_id: &str,
        run_id: &str,
        index: usize,
        approved: bool,
    ) -> powder::RunCriterionEvidence {
        let criterion_id = format!("powder.criterion.v1:sha256:test:{index}");
        powder::RunCriterionEvidence {
            criterion_index: index,
            criterion_id: criterion_id.clone(),
            criterion_text: format!("Criterion {index}"),
            review: approved.then(|| powder::RunCriterionReview {
                review_id: format!("review-{index}"),
                operation_id: format!("review-operation-{index}"),
                card_id: card_id.into(),
                run_id: run_id.into(),
                criterion_index: index,
                criterion_id,
                criterion_text: format!("Criterion {index}"),
                decision: powder::CriterionReviewDecision::Approved,
                reviewer: "captain-powder".into(),
                reviewer_identity: "actor-captain-powder".into(),
                proof: Some("review proof".into()),
                supersedes_review_id: None,
                created_at: 123,
            }),
        }
    }

    fn powder_lifecycle_evidence(
        card_id: &str,
        run_id: &str,
        repository: &str,
        card_status: &str,
        run_state: &str,
        proof: Option<&str>,
    ) -> (powder::CardEvidence, powder::RunEvidence) {
        let run_summary = powder::RunSummary {
            run_id: run_id.into(),
            card_id: card_id.into(),
            state: run_state.into(),
            agent: "powder-agent".into(),
            proof: proof.map(str::to_string),
            created_at: 1,
            updated_at: 2,
        };
        let criteria = vec![powder_criterion(0, true)];
        let run_criteria = vec![powder_run_criterion(card_id, run_id, 0, true)];
        let has_claim = card_status != "done";
        (
            powder::CardEvidence {
                card_id: card_id.into(),
                title: "Powder lifecycle".into(),
                status: card_status.into(),
                repository: Some(repository.into()),
                claim: has_claim.then(|| powder::EvidenceClaim {
                    run_id: run_id.into(),
                    agent: "powder-agent".into(),
                    expires_at: 100,
                }),
                criteria: criteria.clone(),
                current_run_criteria: has_claim.then(|| run_criteria.clone()),
                runs: vec![run_summary.clone()],
                runs_total: 1,
                work_log: vec![],
                work_log_total: 0,
                truncated: false,
            },
            powder::RunEvidence {
                run: run_summary,
                card_title: "Powder lifecycle".into(),
                card_status: card_status.into(),
                repository: Some(repository.into()),
                card_criteria: criteria,
                criteria: run_criteria,
                activities: vec![],
                activities_total: 0,
                links: vec![],
                links_total: 0,
                truncated: false,
            },
        )
    }

    const LOOPBACK_POWDER_IO_TIMEOUT: Duration = Duration::from_secs(2);
    const LOOPBACK_POWDER_HANDLER_TIMEOUT: Duration = Duration::from_secs(4);
    const LOOPBACK_POWDER_POLL_INTERVAL: Duration = Duration::from_millis(10);

    #[derive(Clone, Debug, Default)]
    struct LoopbackPowderState {
        completed: bool,
        released: bool,
        capability_requests: usize,
        capability_schema_version: Option<i64>,
        proof: Option<String>,
        proof_url: Option<String>,
        completion_posts: Vec<Value>,
        work_log_posts: Vec<Value>,
        work_log_http_conflict: bool,
        work_log_response_failure: Option<LoopbackPowderResponseFailure>,
        criterion_review_posts: Vec<Value>,
        mutation_failure_code: Option<String>,
        response_run_id: Option<String>,
        recovery_gets: usize,
        recovery_outcome: Option<Value>,
        recovery_succeeds: bool,
        recovery_operation_id: Option<String>,
        normalized_work_log_body: Option<String>,
        normalized_completion_proof: Option<String>,
        normalized_completion_url: Option<String>,
        evidence_run_id: Option<String>,
        evidence_card_id: Option<String>,
        evidence_repository: Option<String>,
        evidence_claim_agent: Option<String>,
        evidence_run_agent: Option<String>,
        rehome_repository_after_work_log: Option<String>,
        force_claim: bool,
        omit_card_runs: bool,
        duplicate_card_run: bool,
        malformed_card_evidence: bool,
        run_card_status_override: Option<String>,
        pause_run_evidence: bool,
        card_evidence_gets: usize,
        run_evidence_gets: usize,
        release_response_run_id: Option<String>,
        release_response_failure: Option<LoopbackPowderResponseFailure>,
        claim_posts: usize,
        release_posts: usize,
        release_paths: Vec<String>,
        release_bodies: Vec<Value>,
        release_receipt_card_id: Option<String>,
        release_receipt_run_id: Option<String>,
        release_receipt_agent: Option<String>,
        renewal_receipt_card_id: Option<String>,
        renewal_receipt_run_id: Option<String>,
        renewal_receipt_agent: Option<String>,
        claim_receipt_card_id: Option<String>,
        claim_receipt_agent: Option<String>,
        claim_response_body: Option<Value>,
        claim_response_failure: Option<LoopbackPowderResponseFailure>,
        issued_claim_agent: Option<String>,
        renew_posts: usize,
    }

    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    enum LoopbackPowderBlockedOperation {
        Completion,
        Release,
        Renewal,
    }

    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    enum LoopbackPowderResponseFailure {
        Eof,
        Partial,
    }

    #[derive(Clone, Copy, Debug)]
    struct LoopbackPowderBehavior {
        blocked_operation: Option<LoopbackPowderBlockedOperation>,
        fail_release: bool,
    }

    struct LoopbackPowderServer {
        addr: SocketAddr,
        state: Arc<StdMutex<LoopbackPowderState>>,
        post_started: std::sync::mpsc::Receiver<Value>,
        release_post: std::sync::mpsc::SyncSender<()>,
        run_evidence_started: std::sync::mpsc::Receiver<()>,
        resume_run_evidence: std::sync::mpsc::SyncSender<()>,
        result: std::sync::mpsc::Receiver<Result<LoopbackPowderState, String>>,
        stop: std::sync::mpsc::SyncSender<()>,
        thread: Option<std::thread::JoinHandle<()>>,
        joined_outcome: Option<Result<LoopbackPowderState, String>>,
    }

    impl LoopbackPowderServer {
        fn start(expected_requests: usize) -> Self {
            Self::start_with_behavior(
                expected_requests,
                LoopbackPowderBehavior {
                    blocked_operation: Some(LoopbackPowderBlockedOperation::Completion),
                    fail_release: false,
                },
            )
        }

        fn start_with_blocked_release_failure(expected_requests: usize) -> Self {
            Self::start_with_behavior(
                expected_requests,
                LoopbackPowderBehavior {
                    blocked_operation: Some(LoopbackPowderBlockedOperation::Release),
                    fail_release: true,
                },
            )
        }

        fn start_with_blocked_renewal(expected_requests: usize) -> Self {
            Self::start_with_behavior(
                expected_requests,
                LoopbackPowderBehavior {
                    blocked_operation: Some(LoopbackPowderBlockedOperation::Renewal),
                    fail_release: false,
                },
            )
        }

        fn start_with_behavior(expected_requests: usize, behavior: LoopbackPowderBehavior) -> Self {
            use std::sync::mpsc;

            let listener = TcpListener::bind("127.0.0.1:0").unwrap();
            listener.set_nonblocking(true).unwrap();
            let addr = listener.local_addr().unwrap();
            let state = Arc::new(StdMutex::new(LoopbackPowderState::default()));
            let (post_started_tx, post_started) = mpsc::sync_channel(1);
            let (release_post, release_post_rx) = mpsc::sync_channel(1);
            let release_post_rx = Arc::new(StdMutex::new(Some(release_post_rx)));
            let (run_evidence_started_tx, run_evidence_started) = mpsc::sync_channel(1);
            let (resume_run_evidence, resume_run_evidence_rx) = mpsc::sync_channel(1);
            let resume_run_evidence_rx = Arc::new(StdMutex::new(Some(resume_run_evidence_rx)));
            let server_state = state.clone();
            let (result_tx, result) = mpsc::sync_channel(1);
            let (stop, stop_rx) = mpsc::sync_channel(1);
            let thread = std::thread::spawn(move || {
                let mut handlers = Vec::new();
                let accept_result = 'server: loop {
                    match stop_rx.recv_timeout(LOOPBACK_POWDER_POLL_INTERVAL) {
                        Ok(()) => break Ok(()),
                        Err(mpsc::RecvTimeoutError::Disconnected) => {
                            break Err("loopback Powder stop channel disconnected".to_string());
                        }
                        Err(mpsc::RecvTimeoutError::Timeout) => {}
                    }
                    loop {
                        let (mut stream, _) = match listener.accept() {
                            Ok(accepted) => accepted,
                            Err(error) if error.kind() == std::io::ErrorKind::WouldBlock => break,
                            Err(error) => {
                                break 'server Err(format!(
                                    "loopback Powder accept failed: {error}"
                                ));
                            }
                        };
                        let request = match read_loopback_powder_request(&mut stream) {
                            Ok(request) => request,
                            Err(error) => break 'server Err(error),
                        };
                        let state = server_state.clone();
                        let post_started_tx = post_started_tx.clone();
                        let release_post_rx = release_post_rx.clone();
                        let run_evidence_started_tx = run_evidence_started_tx.clone();
                        let resume_run_evidence_rx = resume_run_evidence_rx.clone();
                        let handler = std::thread::spawn(move || {
                            handle_loopback_powder_request(
                                stream,
                                request,
                                &state,
                                &post_started_tx,
                                &release_post_rx,
                                &run_evidence_started_tx,
                                &resume_run_evidence_rx,
                                behavior,
                            )
                        });
                        handlers.push(handler);
                    }
                };
                let mut errors = Vec::new();
                if let Err(error) = accept_result {
                    errors.push(error);
                }
                let handler_count = handlers.len();
                for handler in handlers {
                    match handler.join() {
                        Ok(Ok(())) => {}
                        Ok(Err(error)) => errors.push(error),
                        Err(_) => errors.push("loopback Powder request handler panicked".into()),
                    }
                }
                let capability_requests = server_state.lock().unwrap().capability_requests;
                let counted_requests = handler_count.saturating_sub(capability_requests);
                if counted_requests != expected_requests {
                    errors.push(format!(
                        "loopback Powder request count mismatch: expected {expected_requests}, received {counted_requests}"
                    ));
                }
                let outcome = if errors.is_empty() {
                    Ok(server_state.lock().unwrap().clone())
                } else {
                    Err(errors.join("; "))
                };
                let _ = result_tx.send(outcome);
            });
            Self {
                addr,
                state,
                post_started,
                release_post,
                run_evidence_started,
                resume_run_evidence,
                result,
                stop,
                thread: Some(thread),
                joined_outcome: None,
            }
        }

        fn start_with_release_receipt(
            expected_requests: usize,
            card_id: &str,
            run_id: &str,
            agent: &str,
        ) -> Self {
            let server = Self::start(expected_requests);
            {
                let mut state = server.state.lock().unwrap();
                state.release_receipt_card_id = Some(card_id.into());
                state.release_receipt_run_id = Some(run_id.into());
                state.release_receipt_agent = Some(agent.into());
            }
            server
        }

        fn finish(mut self) -> Result<LoopbackPowderState, String> {
            self.shutdown_and_join()
        }

        fn shutdown_and_join(&mut self) -> Result<LoopbackPowderState, String> {
            if let Some(outcome) = self.joined_outcome.as_ref() {
                return outcome.clone();
            }
            let mut errors = Vec::new();
            match self.stop.try_send(()) {
                Ok(()) | Err(mpsc::TrySendError::Full(())) => {}
                Err(mpsc::TrySendError::Disconnected(())) => {
                    errors.push("loopback Powder stop channel disconnected".to_string());
                }
            }
            if let Some(thread) = self.thread.take() {
                if thread.join().is_err() {
                    errors.push("loopback Powder server panicked".to_string());
                }
            }
            let mut state = None;
            match self.result.try_recv() {
                Ok(Ok(result)) => state = Some(result),
                Ok(Err(error)) => errors.push(error),
                Err(mpsc::TryRecvError::Empty) => {
                    errors.push("loopback Powder server returned without a result".to_string());
                }
                Err(mpsc::TryRecvError::Disconnected) => {
                    errors.push("loopback Powder result channel disconnected".to_string());
                }
            }
            let outcome = if !errors.is_empty() {
                Err(errors.join("; "))
            } else if let Some(state) = state {
                Ok(state)
            } else {
                Err("loopback Powder shutdown succeeded without state".to_string())
            };
            self.joined_outcome = Some(outcome.clone());
            outcome
        }
    }

    impl Drop for LoopbackPowderServer {
        fn drop(&mut self) {
            let _ = self.shutdown_and_join();
        }
    }

    struct LoopbackPowderRequest {
        method: String,
        path: String,
        body: Value,
    }

    fn get_loopback_powder(addr: SocketAddr, path: &str) -> Result<Value, String> {
        let mut stream = TcpStream::connect_timeout(&addr, LOOPBACK_POWDER_IO_TIMEOUT)
            .map_err(|error| format!("loopback Powder test connect failed: {error}"))?;
        stream
            .set_read_timeout(Some(LOOPBACK_POWDER_IO_TIMEOUT))
            .map_err(|error| format!("loopback Powder test read timeout failed: {error}"))?;
        stream
            .set_write_timeout(Some(LOOPBACK_POWDER_IO_TIMEOUT))
            .map_err(|error| format!("loopback Powder test write timeout failed: {error}"))?;
        write!(stream, "GET {path} HTTP/1.1\r\nHost: localhost\r\n\r\n")
            .map_err(|error| format!("loopback Powder test write failed: {error}"))?;
        stream
            .flush()
            .map_err(|error| format!("loopback Powder test flush failed: {error}"))?;
        let mut response = String::new();
        stream
            .take(64 * 1024)
            .read_to_string(&mut response)
            .map_err(|error| format!("loopback Powder test response failed: {error}"))?;
        let body = response
            .split_once("\r\n\r\n")
            .map(|(_, body)| body)
            .ok_or("loopback Powder test response had no body")?;
        serde_json::from_str(body)
            .map_err(|error| format!("loopback Powder test response was invalid: {error}"))
    }

    fn post_loopback_powder(addr: SocketAddr, path: &str, body: &Value) -> Result<Value, String> {
        let mut stream = TcpStream::connect_timeout(&addr, LOOPBACK_POWDER_IO_TIMEOUT)
            .map_err(|error| format!("loopback Powder test connect failed: {error}"))?;
        stream
            .set_read_timeout(Some(LOOPBACK_POWDER_IO_TIMEOUT))
            .map_err(|error| format!("loopback Powder test read timeout failed: {error}"))?;
        stream
            .set_write_timeout(Some(LOOPBACK_POWDER_IO_TIMEOUT))
            .map_err(|error| format!("loopback Powder test write timeout failed: {error}"))?;
        let body = body.to_string();
        write!(
            stream,
            "POST {path} HTTP/1.1\r\nHost: localhost\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{body}",
            body.len()
        )
        .map_err(|error| format!("loopback Powder test write failed: {error}"))?;
        stream
            .flush()
            .map_err(|error| format!("loopback Powder test flush failed: {error}"))?;
        let mut response = String::new();
        stream
            .take(64 * 1024)
            .read_to_string(&mut response)
            .map_err(|error| format!("loopback Powder test response failed: {error}"))?;
        let body = response
            .split_once("\r\n\r\n")
            .map(|(_, body)| body)
            .ok_or("loopback Powder test response had no body")?;
        serde_json::from_str(body)
            .map_err(|error| format!("loopback Powder test response was invalid: {error}"))
    }

    struct PowderProfileEnv {
        _lock: std::sync::MutexGuard<'static, ()>,
        previous: Option<std::ffi::OsString>,
        path: PathBuf,
    }

    impl PowderProfileEnv {
        fn install(profile: &str, addr: SocketAddr) -> Self {
            Self::install_with_operation_identity(profile, addr, "actor-t-hub")
        }

        fn install_with_operation_identity(
            profile: &str,
            addr: SocketAddr,
            operation_identity: &str,
        ) -> Self {
            Self::install_profiles_with_operation_identity(&[(profile, addr, operation_identity)])
        }

        fn install_profiles(profiles: &[(&str, SocketAddr)]) -> Self {
            let profiles: Vec<_> = profiles
                .iter()
                .map(|(profile, addr)| (*profile, *addr, "actor-t-hub"))
                .collect();
            Self::install_profiles_with_operation_identity(&profiles)
        }

        fn install_profiles_with_operation_identity(profiles: &[(&str, SocketAddr, &str)]) -> Self {
            static LOCK: std::sync::OnceLock<StdMutex<()>> = std::sync::OnceLock::new();
            let lock = LOCK
                .get_or_init(|| StdMutex::new(()))
                .lock()
                .unwrap_or_else(|poisoned| poisoned.into_inner());
            let path = std::env::temp_dir().join(format!(
                "t-hub-control-powder-profile-{}-{}.json",
                std::process::id(),
                uuid::Uuid::new_v4().simple()
            ));
            let mut configured_profiles = serde_json::Map::new();
            for (profile, addr, operation_identity) in profiles {
                configured_profiles.insert(
                    (*profile).to_string(),
                    json!({
                        "baseUrl": format!("http://{addr}"),
                        "agentName": "t-hub",
                        "operationIdentity": operation_identity,
                        "apiKey": "test-key"
                    }),
                );
            }
            std::fs::write(
                &path,
                serde_json::to_vec(&json!({
                    "schemaVersion": 1,
                    "profiles": configured_profiles,
                }))
                .unwrap(),
            )
            .unwrap();
            #[cfg(unix)]
            {
                use std::os::unix::fs::PermissionsExt;
                std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o600)).unwrap();
            }
            let previous = std::env::var_os("T_HUB_POWDER_PROFILES_FILE");
            std::env::set_var("T_HUB_POWDER_PROFILES_FILE", &path);
            Self {
                _lock: lock,
                previous,
                path,
            }
        }

        fn remap_profile_endpoint(&self, profile: &str, addr: SocketAddr) {
            self.set_profile_base_url(profile, &format!("http://{addr}"));
        }

        fn set_profile_base_url(&self, profile: &str, base_url: &str) {
            let mut document: Value =
                serde_json::from_slice(&std::fs::read(&self.path).unwrap()).unwrap();
            document["profiles"][profile]["baseUrl"] = json!(base_url);
            std::fs::write(&self.path, serde_json::to_vec(&document).unwrap()).unwrap();
        }

        fn set_profile_api_key(&self, profile: &str, api_key: &str) {
            let mut document: Value =
                serde_json::from_slice(&std::fs::read(&self.path).unwrap()).unwrap();
            document["profiles"][profile]["apiKey"] = json!(api_key);
            std::fs::write(&self.path, serde_json::to_vec(&document).unwrap()).unwrap();
        }
    }

    impl Drop for PowderProfileEnv {
        fn drop(&mut self) {
            match self.previous.as_ref() {
                Some(previous) => std::env::set_var("T_HUB_POWDER_PROFILES_FILE", previous),
                None => std::env::remove_var("T_HUB_POWDER_PROFILES_FILE"),
            }
            let _ = std::fs::remove_file(&self.path);
        }
    }

    struct FakeHarnessCommand {
        fixture_dir: PathBuf,
        command: String,
        invocation_path: PathBuf,
    }

    impl FakeHarnessCommand {
        fn new(harness: Harness, flags: &str) -> Self {
            let fixture_dir = std::env::temp_dir().join(format!(
                "t-hub-dispatch-harness-{}-{}",
                std::process::id(),
                uuid::Uuid::new_v4().simple()
            ));
            std::fs::create_dir_all(&fixture_dir).unwrap();
            let executable = fixture_dir.join(harness.as_provider());
            let invocation_path = fixture_dir.join("invoked");
            std::fs::write(
                &executable,
                format!(
                    "#!/usr/bin/env node\nrequire('fs').writeFileSync({}, 'invoked\\n');\nsetInterval(() => {{}}, 1000);\n",
                    serde_json::to_string(&invocation_path).unwrap()
                ),
            )
            .unwrap();
            #[cfg(unix)]
            {
                use std::os::unix::fs::PermissionsExt;
                std::fs::set_permissions(&executable, std::fs::Permissions::from_mode(0o700))
                    .unwrap();
            }
            let command = if flags.is_empty() {
                executable.display().to_string()
            } else {
                format!("{} {flags}", executable.display())
            };
            Self {
                fixture_dir,
                command,
                invocation_path,
            }
        }

        fn was_invoked(&self) -> bool {
            self.invocation_path.exists()
        }

        fn wait_for_invocation(&self) {
            let deadline = Instant::now() + Duration::from_secs(2);
            while !self.was_invoked() {
                assert!(
                    Instant::now() < deadline,
                    "fake Harness command was not invoked"
                );
                std::thread::sleep(Duration::from_millis(10));
            }
        }
    }

    impl Drop for FakeHarnessCommand {
        fn drop(&mut self) {
            let _ = std::fs::remove_dir_all(&self.fixture_dir);
        }
    }

    struct FakeCodexObserver {
        fixture_dir: PathBuf,
        command: String,
        invocation_path: PathBuf,
        identity_path: PathBuf,
    }

    impl FakeCodexObserver {
        fn new(exit_code: i32) -> Self {
            let fixture_dir = std::env::temp_dir().join(format!(
                "t-hub-codex-observer-{}-{}",
                std::process::id(),
                uuid::Uuid::new_v4().simple()
            ));
            std::fs::create_dir_all(&fixture_dir).unwrap();
            let executable = fixture_dir.join("t-hub-agent");
            let invocation_path = fixture_dir.join("invocation");
            let identity_path = fixture_dir.join("identity");
            std::fs::write(
                &executable,
                format!(
                    "#!/bin/sh\nprintf '%s\\n' \"$*\" > '{}'\nprintf '%s\\t%s\\n' \"$TMUX_PANE\" \"$(tmux display-message -p '#{{session_name}}')\" > '{}'\nexit {exit_code}\n",
                    invocation_path.display(),
                    identity_path.display()
                ),
            )
            .unwrap();
            #[cfg(unix)]
            {
                use std::os::unix::fs::PermissionsExt;
                std::fs::set_permissions(&executable, std::fs::Permissions::from_mode(0o700))
                    .unwrap();
            }
            Self {
                fixture_dir,
                command: format!("{} --codex-unobserved", executable.display()),
                invocation_path,
                identity_path,
            }
        }

        fn wait_for_invocation(&self) {
            let deadline = Instant::now() + Duration::from_secs(2);
            while !self.invocation_path.exists() || !self.identity_path.exists() {
                assert!(
                    Instant::now() < deadline,
                    "fake Codex observer was not invoked"
                );
                std::thread::sleep(Duration::from_millis(10));
            }
        }
    }

    impl Drop for FakeCodexObserver {
        fn drop(&mut self) {
            let _ = std::fs::remove_dir_all(&self.fixture_dir);
        }
    }

    fn tmux_pane_identity(target: &str) -> String {
        let output = std::process::Command::new("tmux")
            .args([
                "-L",
                tmux::socket(),
                "display-message",
                "-p",
                "-t",
                target,
                "#{pane_id}\t#{session_name}",
            ])
            .output()
            .unwrap();
        assert!(output.status.success());
        String::from_utf8(output.stdout).unwrap().trim().to_string()
    }

    struct FakeHarnessSession {
        session_id: String,
        _command: FakeHarnessCommand,
        _tmux_guard: ProcessAttestationTmuxGuard,
    }

    impl FakeHarnessSession {
        fn start(harness: Harness) -> Self {
            let tmux_guard = ProcessAttestationTmuxGuard::acquire();
            let flags = match harness {
                Harness::Codex => "--dangerously-bypass-approvals-and-sandbox",
                Harness::Claude => "--dangerously-skip-permissions",
            };
            let command = FakeHarnessCommand::new(harness, flags);
            let session_id = uuid::Uuid::new_v4().simple().to_string()[..8].to_string();
            let target = tmux_target(&session_id);
            // Start the hermetic Captain command as tmux's session command.
            // Injecting it into a freshly created zsh pane races zsh startup and
            // intermittently loses the input before liveness can observe Codex.
            // Crew dispatch tests still exercise the real zsh launch path.
            tmux::new_session_with_env(&target, "/tmp", Some(&command.command), &[]).unwrap();
            wait_for_harness_started(&session_id, harness.as_provider()).unwrap();
            Self {
                session_id,
                _command: command,
                _tmux_guard: tmux_guard,
            }
        }
    }

    impl Drop for FakeHarnessSession {
        fn drop(&mut self) {
            let _ = reap_test_tmux_session(&tmux_target(&self.session_id));
        }
    }

    struct DispatchWorkerCompletion(Arc<AtomicBool>);

    impl Drop for DispatchWorkerCompletion {
        fn drop(&mut self) {
            self.0.store(true, Ordering::SeqCst);
        }
    }

    struct DispatchWorker {
        sink: Arc<RecordingSink>,
        resume: Option<mpsc::SyncSender<()>>,
        worker: Option<std::thread::JoinHandle<Result<Value, String>>>,
    }

    impl DispatchWorker {
        fn start(
            ctx: ControlContext,
            args: Value,
            sink: Arc<RecordingSink>,
            resume: mpsc::SyncSender<()>,
            completion: Arc<AtomicBool>,
        ) -> Self {
            let worker = std::thread::spawn(move || {
                let _completion = DispatchWorkerCompletion(completion);
                dispatch_crew(&ctx, &args, None, true)
            });
            Self {
                sink,
                resume: Some(resume),
                worker: Some(worker),
            }
        }

        fn resume(&mut self) {
            if let Some(resume) = self.resume.take() {
                let _ = resume.send(());
            }
        }

        fn join(&mut self) -> std::thread::Result<Result<Value, String>> {
            self.resume();
            self.worker
                .take()
                .expect("dispatch worker was already joined")
                .join()
        }

        fn dispatched_terminal_ids(&self) -> Vec<String> {
            self.sink
                .calls
                .lock()
                .unwrap()
                .iter()
                .filter(|(command, _)| command == "spawn_terminal")
                .filter_map(|(_, args)| args["id"].as_str().map(str::to_string))
                .collect()
        }
    }

    impl Drop for DispatchWorker {
        fn drop(&mut self) {
            self.resume();
            if let Some(worker) = self.worker.take() {
                let _ = worker.join();
            }
            for terminal_id in self.dispatched_terminal_ids() {
                let _ = reap_test_tmux_session(&tmux_target(&terminal_id));
            }
        }
    }

