    fn seed_work_log_intent(
        registry: &CaptainsRegistry,
        ctx: &ControlContext,
        operation_id: &str,
        message: &str,
        created_at: Option<u64>,
    ) -> PowderMutationIntent {
        let scope = resolve_crew_powder_scope(ctx, "crew-powder").unwrap();
        let mut intent = powder_mutation_intent(
            PowderMutationKind::WorkLogAppend,
            &scope,
            operation_id,
            "crew-powder",
            &json!({
                "agent": "powder-agent",
                "harness": "codex",
                "message": message,
            }),
        );
        if let Some(created_at) = created_at {
            intent.created_at = created_at;
        }
        registry
            .begin_crew_powder_mutation(&scope, intent.clone())
            .unwrap();
        intent
    }

    fn downgrade_persisted_mutation_intent_to_v1(path: &Path) {
        let mut legacy: Value =
            serde_json::from_str(&std::fs::read_to_string(path).unwrap()).unwrap();
        legacy["schemaVersion"] = json!(6);
        let intent = legacy["captains"][0]["crew"][0]["powderWork"]["mutationIntent"]
            .as_object_mut()
            .unwrap();
        intent.insert("schemaVersion".into(), json!(1));
        intent.remove("powderRequestDigest");
        std::fs::write(path, serde_json::to_vec_pretty(&legacy).unwrap()).unwrap();
    }

    fn loopback_criterion_review_outcome(body: &Value) -> Value {
        let operation_id = body["operation_id"].as_str().unwrap();
        let criterion_id = body["criterion_id"].as_str().unwrap();
        loopback_operation_outcome(
            "criterion_review",
            body,
            json!({
                "id": "review-authoritative",
                "operation_id": operation_id,
                "card_id": "thub-powder-control-lifecycle",
                "run_id": "run-authoritative",
                "criterion_index": body["criterion"],
                "criterion_id": criterion_id,
                "criterion_text": "Criterion 0",
                "decision": body["decision"],
                "reviewer": "captain-powder",
                "reviewer_identity": "actor-t-hub",
                "proof": body["proof"].as_str().map(|_| "[scrubbed review proof]"),
                "supersedes_review_id": "review-0",
                "created_at": 126,
            }),
        )
    }

    #[test]
    fn powder_loopback_server_bounds_shutdown_and_reports_request_count_drift() {
        let mut clean = LoopbackPowderServer::start(0);
        let first = clean.shutdown_and_join().unwrap();
        let second = clean.shutdown_and_join().unwrap();
        assert_eq!(first.completion_posts, second.completion_posts);
        drop(clean);

        let dropped_without_finish = LoopbackPowderServer::start(0);
        drop(dropped_without_finish);

        let missing = LoopbackPowderServer::start(1);
        assert!(missing
            .finish()
            .unwrap_err()
            .contains("expected 1, received 0"));

        let extra = LoopbackPowderServer::start(0);
        let card =
            get_loopback_powder(extra.addr, "/api/v1/cards/thub-powder-control-lifecycle").unwrap();
        assert_eq!(card["card"]["id"], "thub-powder-control-lifecycle");
        assert!(extra
            .finish()
            .unwrap_err()
            .contains("expected 0, received 1"));
    }

    #[cfg(any())]
    #[test]
    fn launch_attestation_failure_rolls_back_terminal_binding_and_exact_claim() {
        if !std::process::Command::new("tmux")
            .arg("-V")
            .output()
            .is_ok_and(|output| output.status.success())
        {
            eprintln!(
                "launch_attestation_failure_rolls_back_terminal_binding_and_exact_claim: tmux not on PATH - skipping"
            );
            return;
        }
        let server = LoopbackPowderServer::start(4);
        {
            let mut state = server.state.lock().unwrap();
            state.evidence_claim_agent = Some("t-hub".into());
            state.evidence_run_agent = Some("t-hub".into());
        }
        let profile_name = format!("attestation-rollback-{}", uuid::Uuid::new_v4().simple());
        let _profile = PowderProfileEnv::install(&profile_name, server.addr);
        let _tmux_guard = ProcessAttestationTmuxGuard::acquire();
        let crew_id = uuid::Uuid::new_v4().simple().to_string()[..8].to_string();
        let registry =
            powder_lifecycle_registry_with_profile_and_crew(None, &profile_name, &crew_id);
        registry
            .bind_crew_context(
                "captain-powder",
                &crew_id,
                "Roll back exact attestation claim",
                "codex",
                Some("/tmp/powder-lifecycle"),
                Some("feat/powder-lifecycle"),
                PowderWorkBinding {
                    card_id: "thub-powder-control-lifecycle".into(),
                    run_id: "run-authoritative".into(),
                    agent: Some("t-hub".into()),
                    claim_expires_at: Some(100),
                    mutation_intent: None,
                    dispatch_release_recovery: false,
                    state: PowderWorkState::Active,
                },
            )
            .unwrap();
        let target = tmux_target(&crew_id);
        create_test_tmux_session(&target).unwrap();
        let ctx = test_ctx("secret").with_captains_registry(registry.clone());

        rollback_crew_dispatch(&ctx, &crew_id, None, None).unwrap();

        assert_eq!(tmux::session_liveness(&target), tmux::SessionLiveness::Gone);
        assert!(registry.snapshot().captains[0]
            .crew
            .iter()
            .all(|crew| crew.terminal_id != crew_id));
        let state = server.finish().unwrap();
        assert_eq!(state.release_posts, 1);
    }

    fn run_dispatch_attestation_failure(
        command: &str,
        codex_unobserved_command: &str,
        skip_harness_liveness: bool,
        expected_error: &str,
    ) {
        let server = LoopbackPowderServer::start(4);
        let profile_name = format!("dispatch-failure-{}", uuid::Uuid::new_v4().simple());
        let _profile = PowderProfileEnv::install(&profile_name, server.addr);
        let captain = FakeHarnessSession::start(Harness::Codex);
        let registry = dispatch_test_registry(None, &profile_name, &captain.session_id);
        let (ctx, sink) = dispatch_test_context(registry.clone());
        let mut args = json!({
            "captainSessionId": captain.session_id,
            "cardId": "thub-powder-control-lifecycle",
            "task": "Verify launch attestation rollback",
            "harness": "codex",
            "testHarnessCommand": command,
            "testCodexUnobservedCommand": codex_unobserved_command,
        });
        if skip_harness_liveness {
            args["testSkipHarnessLiveness"] = json!(true);
        }

        let error = dispatch_crew(&ctx, &args, None, true).unwrap_err();
        assert!(error.contains(expected_error), "unexpected error: {error}");
        assert!(error.contains("all side effects were rolled back"));
        assert!(!error.contains("supersecret"));
        assert!(!error.contains("api_key"));
        let crew_session_id = dispatched_terminal_id(&sink);
        assert_eq!(
            tmux::session_liveness(&tmux_target(&crew_session_id)),
            tmux::SessionLiveness::Gone
        );
        assert!(registry.snapshot().captains[0].crew.is_empty());

        let state = server.finish().unwrap();
        assert_eq!(state.claim_posts, 1);
        assert_eq!(state.release_posts, 1);
        assert_eq!(state.release_bodies[0]["run_id"], "run-authoritative");
    }

