    #[test]
    fn dispatch_release_recovery_endpoint_identity_never_persists_or_syncs_gateway_secrets() {
        let original = LoopbackPowderServer::start(0);
        let replacement = LoopbackPowderServer::start(0);
        let profile = format!("release-endpoint-secret-{}", uuid::Uuid::new_v4().simple());
        let profiles = PowderProfileEnv::install(&profile, original.addr);
        let original_secret = "original-path-secret";
        let original_base_url = format!(
            "http://{}/gateway/{original_secret}?access_token=original-query-secret#original-fragment-secret",
            original.addr
        );
        profiles.set_profile_base_url(&profile, &original_base_url);
        let client = powder::Client::from_profile(&profile).unwrap();
        let endpoint_identity = client.endpoint_identity().unwrap();
        let path = captains_tmp("release-endpoint-digest-secret");
        let _ = std::fs::remove_file(&path);
        let registry = dispatch_test_registry(Some(path.clone()), &profile, "digest-captain");
        let crew_session_id = "digest-crew";
        registry
            .record_crew("digest-captain", crew_session_id)
            .unwrap();
        registry
            .bind_crew_context(
                "digest-captain",
                crew_session_id,
                "Keep recovery endpoint credentials private",
                "codex",
                Some("/tmp/digest-crew"),
                Some("digest-crew"),
                PowderWorkBinding {
                    card_id: "thub-powder-control-lifecycle".into(),
                    run_id: "run-authoritative".into(),
                    agent: Some("t-hub".into()),
                    claim_expires_at: Some(100),
                    mutation_intent: None,
                    dispatch_release_recovery: false,
                    state: PowderWorkState::Active,
                },
            )
            .unwrap();
        let recovery = PendingDispatchRelease {
            crew_session_id: crew_session_id.into(),
            project_id: "project-dispatch-attestation".into(),
            connection_profile: profile.clone(),
            connection_endpoint_identity: endpoint_identity.clone(),
            repository: "t-hub".into(),
            card_id: "thub-powder-control-lifecycle".into(),
            run_id: "run-authoritative".into(),
            agent: "t-hub".into(),
            operation_id: "initial-claim:actor-t-hub:endpoint-digest".into(),
            created_at: 1,
            state: PendingDispatchReleaseState::InFlight,
        };
        registry.prepare_dispatch_release(recovery.clone()).unwrap();

        let persisted = std::fs::read_to_string(&path).unwrap();
        let persisted_json: Value = serde_json::from_str(&persisted).unwrap();
        let persisted_recovery = &persisted_json["pendingDispatchReleases"][0];
        assert_eq!(
            persisted_recovery["connectionEndpointIdentity"],
            endpoint_identity
        );
        assert!(persisted_recovery.get("connectionEndpoint").is_none());

        let (ctx, sink) = dispatch_test_context(registry.clone());
        assert!(captains_sync_apply(&ctx));
        let sync_payload = serde_json::to_string(&*sink.calls.lock().unwrap()).unwrap();
        let debug_output = format!("{recovery:?}");
        for secret in [
            original_secret,
            "original-query-secret",
            "original-fragment-secret",
            &original_base_url,
        ] {
            assert!(!persisted.contains(secret), "registry leaked {secret:?}");
            assert!(!sync_payload.contains(secret), "sync leaked {secret:?}");
            assert!(!debug_output.contains(secret), "debug leaked {secret:?}");
        }

        let replacement_base_url = format!(
            "http://{}/gateway/replacement-path-secret?access_token=replacement-query-secret#replacement-fragment-secret",
            replacement.addr
        );
        profiles.set_profile_base_url(&profile, &replacement_base_url);
        let error = recover_pending_dispatch_release_guarded(&ctx, &recovery).unwrap_err();
        assert_eq!(
            error,
            "the frozen profile endpoint changed before release recovery"
        );
        for secret in [
            original_secret,
            "original-query-secret",
            "original-fragment-secret",
            "replacement-path-secret",
            "replacement-query-secret",
            "replacement-fragment-secret",
            &original_base_url,
            &replacement_base_url,
        ] {
            assert!(!error.contains(secret), "error leaked {secret:?}");
        }
        assert_eq!(
            registry.snapshot().pending_dispatch_releases,
            vec![recovery],
            "endpoint remap must retain the original-scope recovery"
        );
        let original_state = original.finish().unwrap();
        assert_eq!(original_state.card_evidence_gets, 0);
        assert_eq!(original_state.run_evidence_gets, 0);
        assert_eq!(original_state.release_posts, 0);
        let replacement_state = replacement.finish().unwrap();
        assert_eq!(replacement_state.card_evidence_gets, 0);
        assert_eq!(replacement_state.run_evidence_gets, 0);
        assert_eq!(replacement_state.release_posts, 0);
        let _ = std::fs::remove_file(path.with_extension("json.bak"));
        let _ = std::fs::remove_file(path);
    }

    #[test]
    fn dispatch_release_recovery_matching_endpoint_transport_failure_never_leaks_secrets() {
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let addr = listener.local_addr().unwrap();
        drop(listener);
        let profile = format!("release-transport-secret-{}", uuid::Uuid::new_v4().simple());
        let profiles = PowderProfileEnv::install(&profile, addr);
        let endpoint =
            format!("http://{addr}/gateway/path-token?access_token=query-token#fragment-token");
        profiles.set_profile_base_url(&profile, &endpoint);
        let client = powder::Client::from_profile(&profile).unwrap();
        let path = captains_tmp("release-transport-secret");
        let _ = std::fs::remove_file(&path);
        let registry = dispatch_test_registry(Some(path.clone()), &profile, "transport-captain");
        let crew_session_id = "transport-crew";
        registry
            .record_crew("transport-captain", crew_session_id)
            .unwrap();
        registry
            .bind_crew_context(
                "transport-captain",
                crew_session_id,
                "Keep matching-endpoint transport errors private",
                "codex",
                Some("/tmp/transport-crew"),
                Some("transport-crew"),
                PowderWorkBinding {
                    card_id: "thub-powder-control-lifecycle".into(),
                    run_id: "run-authoritative".into(),
                    agent: Some("t-hub".into()),
                    claim_expires_at: Some(100),
                    mutation_intent: None,
                    dispatch_release_recovery: false,
                    state: PowderWorkState::Active,
                },
            )
            .unwrap();
        let recovery = PendingDispatchRelease {
            crew_session_id: crew_session_id.into(),
            project_id: "project-dispatch-attestation".into(),
            connection_profile: profile.clone(),
            connection_endpoint_identity: client.endpoint_identity().unwrap(),
            repository: "t-hub".into(),
            card_id: "thub-powder-control-lifecycle".into(),
            run_id: "run-authoritative".into(),
            agent: "t-hub".into(),
            operation_id: "initial-claim:actor-t-hub:transport-secret".into(),
            created_at: 1,
            state: PendingDispatchReleaseState::InFlight,
        };
        registry.prepare_dispatch_release(recovery.clone()).unwrap();
        let persisted = std::fs::read_to_string(&path).unwrap();
        let (ctx, sink) = dispatch_test_context(registry.clone());
        assert!(captains_sync_apply(&ctx));
        let sync_payload = serde_json::to_string(&*sink.calls.lock().unwrap()).unwrap();

        let error = recover_pending_dispatch_release_guarded(&ctx, &recovery).unwrap_err();
        assert_eq!(
            error,
            "the frozen repository cannot be reconciled: Powder transport failure"
        );
        // Periodic reconciliation logs this same endpoint-free error.  Invoke the
        // production path as well; it must retain the exact pending recovery.
        reconcile_powder_leases(&ctx);
        assert_eq!(
            registry.snapshot().pending_dispatch_releases,
            vec![recovery.clone()]
        );
        let debug_output = format!("{recovery:?}");
        for secret in [
            "path-token",
            "query-token",
            "fragment-token",
            "test-key",
            endpoint.as_str(),
        ] {
            assert!(!persisted.contains(secret), "registry leaked {secret:?}");
            assert!(!sync_payload.contains(secret), "sync leaked {secret:?}");
            assert!(!debug_output.contains(secret), "debug leaked {secret:?}");
            assert!(!error.contains(secret), "error leaked {secret:?}");
        }
        let _ = std::fs::remove_file(path.with_extension("json.bak"));
        let _ = std::fs::remove_file(path);
    }

    #[test]
    fn dispatch_release_recovery_status_errors_never_leak_gateway_echoes() {
        for (status, reason, expected_message) in [
            (403_u16, "Forbidden", "Powder HTTP status 403"),
            (500_u16, "Internal Server Error", "Powder HTTP status 500"),
        ] {
            let listener = TcpListener::bind("127.0.0.1:0").unwrap();
            let addr = listener.local_addr().unwrap();
            let body = json!({
                "error": "gateway echoed /gateway/path-token?access_token=query-token#fragment-token with test-key"
            });
            let server = std::thread::spawn(move || {
                for _ in 0..2 {
                    let (mut stream, _) = listener.accept().unwrap();
                    let _ = read_loopback_powder_request(&mut stream).unwrap();
                    write_loopback_json_status(&mut stream, status, reason, &body).unwrap();
                }
            });
            let profile = format!(
                "release-status-secret-{}-{}",
                status,
                uuid::Uuid::new_v4().simple()
            );
            let profiles = PowderProfileEnv::install(&profile, addr);
            let endpoint =
                format!("http://{addr}/gateway/path-token?access_token=query-token#fragment-token");
            profiles.set_profile_base_url(&profile, &endpoint);
            let client = powder::Client::from_profile(&profile).unwrap();
            let path = captains_tmp("release-status-secret");
            let _ = std::fs::remove_file(&path);
            let registry = dispatch_test_registry(Some(path.clone()), &profile, "status-captain");
            let crew_session_id = "status-crew";
            registry
                .record_crew("status-captain", crew_session_id)
                .unwrap();
            registry
                .bind_crew_context(
                    "status-captain",
                    crew_session_id,
                    "Keep gateway status echoes private",
                    "codex",
                    Some("/tmp/status-crew"),
                    Some("status-crew"),
                    PowderWorkBinding {
                        card_id: "thub-powder-control-lifecycle".into(),
                        run_id: "run-authoritative".into(),
                        agent: Some("t-hub".into()),
                        claim_expires_at: Some(100),
                        mutation_intent: None,
                        dispatch_release_recovery: false,
                        state: PowderWorkState::Active,
                    },
                )
                .unwrap();
            let recovery = PendingDispatchRelease {
                crew_session_id: crew_session_id.into(),
                project_id: "project-dispatch-attestation".into(),
                connection_profile: profile.clone(),
                connection_endpoint_identity: client.endpoint_identity().unwrap(),
                repository: "t-hub".into(),
                card_id: "thub-powder-control-lifecycle".into(),
                run_id: "run-authoritative".into(),
                agent: "t-hub".into(),
                operation_id: format!("initial-claim:actor-t-hub:status-{status}"),
                created_at: 1,
                state: PendingDispatchReleaseState::InFlight,
            };
            registry.prepare_dispatch_release(recovery.clone()).unwrap();
            let persisted = std::fs::read_to_string(&path).unwrap();
            let (ctx, sink) = dispatch_test_context(registry.clone());
            assert!(captains_sync_apply(&ctx));
            let sync_payload = serde_json::to_string(&*sink.calls.lock().unwrap()).unwrap();

            let error = recover_pending_dispatch_release_guarded(&ctx, &recovery).unwrap_err();
            assert_eq!(
                error,
                format!("the frozen repository cannot be reconciled: {expected_message}")
            );
            // Periodic reconciliation emits this same endpoint-free error to its
            // log-facing path and must retain the frozen recovery.
            reconcile_powder_leases(&ctx);
            assert_eq!(
                registry.snapshot().pending_dispatch_releases,
                vec![recovery.clone()]
            );
            let debug_output = format!("{recovery:?}");
            for secret in [
                "path-token",
                "query-token",
                "fragment-token",
                "test-key",
                endpoint.as_str(),
            ] {
                assert!(!persisted.contains(secret), "registry leaked {secret:?}");
                assert!(!sync_payload.contains(secret), "sync leaked {secret:?}");
                assert!(!debug_output.contains(secret), "debug leaked {secret:?}");
                assert!(!error.contains(secret), "error leaked {secret:?}");
            }
            server.join().unwrap();
            let _ = std::fs::remove_file(path.with_extension("json.bak"));
            let _ = std::fs::remove_file(path);
        }
    }

