    #[test]
    fn dispatch_release_recovery_rejects_reclaimed_different_unknown_and_malformed_card_state() {
        if !tmux_process_tests_available() {
            eprintln!(
                "dispatch_release_recovery_rejects_reclaimed_different_unknown_and_malformed_card_state: tmux or node not on PATH - skipping"
            );
            return;
        }
        for (case, expected_requests) in [
            ("reclaimed", 3usize),
            ("different-claim", 3),
            ("unknown-run", 3),
            ("malformed-card", 2),
        ] {
            let original = LoopbackPowderServer::start(expected_requests);
            let replacement = LoopbackPowderServer::start(0);
            {
                let mut state = original.state.lock().unwrap();
                state.evidence_claim_agent = Some("t-hub".into());
                state.evidence_run_agent = Some("t-hub".into());
                match case {
                    "reclaimed" => {
                        state.force_claim = true;
                        state.evidence_run_id = Some("run-reclaimed".into());
                    }
                    "different-claim" => state.evidence_claim_agent = Some("other-agent".into()),
                    "unknown-run" => state.completed = true,
                    "malformed-card" => state.malformed_card_evidence = true,
                    _ => unreachable!(),
                }
            }
            let original_profile = format!(
                "release-card-state-original-{case}-{}",
                uuid::Uuid::new_v4().simple()
            );
            let replacement_profile = format!(
                "release-card-state-replacement-{case}-{}",
                uuid::Uuid::new_v4().simple()
            );
            let _profiles = PowderProfileEnv::install_profiles(&[
                (&original_profile, original.addr),
                (&replacement_profile, replacement.addr),
            ]);
            let captain = FakeHarnessSession::start(Harness::Codex);
            let crew_session_id = format!("release-card-state-{}", uuid::Uuid::new_v4().simple());
            let registry = dispatch_test_registry(None, &original_profile, &captain.session_id);
            registry
                .record_crew(&captain.session_id, &crew_session_id)
                .unwrap();
            registry
                .bind_crew_context(
                    &captain.session_id,
                    &crew_session_id,
                    "Reject changed current card state",
                    "codex",
                    Some("/tmp/release-card-state"),
                    Some("release-card-state"),
                    PowderWorkBinding {
                        card_id: "thub-powder-control-lifecycle".into(),
                        run_id: "run-authoritative".into(),
                        agent: Some("t-hub".into()),
                        claim_expires_at: Some(100),
                        mutation_intent: None,
                        dispatch_release_recovery: false,
                        state: PowderWorkState::Active,
                    },
                )
                .unwrap();
            let recovery = PendingDispatchRelease {
                crew_session_id,
                project_id: "project-dispatch-attestation".into(),
                connection_profile: original_profile.clone(),
                connection_endpoint_identity: powder::Client::from_profile(&original_profile)
                    .unwrap()
                    .endpoint_identity()
                    .unwrap(),
                repository: "t-hub".into(),
                card_id: "thub-powder-control-lifecycle".into(),
                run_id: "run-authoritative".into(),
                agent: "t-hub".into(),
                operation_id: format!("initial-claim:actor-t-hub:release-card-state:{case}"),
                created_at: 1,
                state: PendingDispatchReleaseState::InFlight,
            };
            registry.prepare_dispatch_release(recovery.clone()).unwrap();
            let mut rebound = registry.projects()[0].clone();
            rebound.powder.as_mut().unwrap().connection_profile = replacement_profile.clone();
            rebound.powder.as_mut().unwrap().repository = "replacement-repository".into();
            registry.upsert_project(rebound).unwrap();
            let (ctx, _) = dispatch_test_context(registry.clone());
            reconcile_powder_leases(&ctx);
            let snapshot = registry.snapshot();
            assert_eq!(
                snapshot.pending_dispatch_releases,
                vec![recovery],
                "{case} must retain the exact frozen recovery"
            );
            assert!(snapshot.pending_dispatch_claims.is_empty());
            assert!(matches!(
                snapshot.captains[0].crew[0].state,
                CrewState::CleanupPending { .. }
            ));
            assert_eq!(
                snapshot.projects[0]
                    .powder
                    .as_ref()
                    .unwrap()
                    .connection_profile,
                replacement_profile
            );
            let original_state = original.finish().unwrap();
            assert_eq!(
                original_state.release_posts, 0,
                "{case} issued a release POST"
            );
            let replacement_state = replacement.finish().unwrap();
            assert_eq!(replacement_state.card_evidence_gets, 0);
            assert_eq!(replacement_state.run_evidence_gets, 0);
            assert_eq!(replacement_state.release_posts, 0);
        }
    }

    #[test]
    fn dispatch_release_prepare_persistence_failure_emits_no_release_post_or_cleanup_mutation() {
        let path = captains_tmp("release-prepare-persist-failure");
        let _ = std::fs::remove_file(&path);
        let registry = powder_lifecycle_registry_with_profile_and_crew(
            Some(path.clone()),
            "prepare-failure-profile",
            "prepare-failure-crew",
        );
        let work = registry.snapshot().captains[0].crew[0]
            .powder_work
            .clone()
            .unwrap();
        let recovery = PendingDispatchRelease {
            crew_session_id: "prepare-failure-crew".into(),
            project_id: "project-powder-lifecycle".into(),
            connection_profile: "prepare-failure-profile".into(),
            connection_endpoint_identity: format!("hmac-sha256:{}", "0".repeat(64)),
            repository: "t-hub".into(),
            card_id: work.card_id,
            run_id: work.run_id,
            agent: work.agent.unwrap(),
            operation_id: "initial-claim:actor-t-hub:prepare-failure".into(),
            created_at: 1,
            state: PendingDispatchReleaseState::Prepared,
        };
        registry.fail_next_persist("injected release prepare persistence failure");
        assert!(registry.prepare_dispatch_release(recovery).is_err());
        let snapshot = registry.snapshot();
        assert!(snapshot.pending_dispatch_releases.is_empty());
        assert!(matches!(
            snapshot.captains[0].crew[0].state,
            CrewState::Active
        ));
        assert!(
            !snapshot.captains[0].crew[0]
                .powder_work
                .as_ref()
                .unwrap()
                .dispatch_release_recovery
        );
        let _ = std::fs::remove_file(path.with_extension("json.bak"));
        let _ = std::fs::remove_file(path);
    }

    #[test]
    fn confirmed_release_never_clears_a_reused_terminal_without_its_exact_transaction_crew() {
        let registry = powder_lifecycle_registry_with_profile_and_crew(
            None,
            "clear-reuse-profile",
            "clear-reuse-crew",
        );
        let work = registry.snapshot().captains[0].crew[0]
            .powder_work
            .clone()
            .unwrap();
        let recovery = PendingDispatchRelease {
            crew_session_id: "clear-reuse-crew".into(),
            project_id: "project-powder-lifecycle".into(),
            connection_profile: "clear-reuse-profile".into(),
            connection_endpoint_identity: format!("hmac-sha256:{}", "0".repeat(64)),
            repository: "t-hub".into(),
            card_id: work.card_id,
            run_id: work.run_id,
            agent: work.agent.unwrap(),
            operation_id: "initial-claim:actor-t-hub:clear-reuse".into(),
            created_at: 1,
            state: PendingDispatchReleaseState::Prepared,
        };
        registry.prepare_dispatch_release(recovery.clone()).unwrap();
        {
            let mut inner = registry.lock();
            let crew = &mut inner.captains[0].crew[0];
            crew.state = CrewState::Active;
            let work = crew.powder_work.as_mut().unwrap();
            work.card_id = "replacement-card".into();
            work.run_id = "replacement-run".into();
            work.agent = Some("replacement-agent".into());
            work.dispatch_release_recovery = false;
        }
        let error = registry
            .clear_confirmed_dispatch_release(&recovery)
            .unwrap_err();
        assert!(error.contains("transaction-owned CleanupPending"));
        let snapshot = registry.snapshot();
        assert_eq!(snapshot.pending_dispatch_releases, vec![recovery]);
        let replacement = &snapshot.captains[0].crew[0];
        assert_eq!(replacement.terminal_id, "clear-reuse-crew");
        assert_eq!(
            replacement.powder_work.as_ref().unwrap().card_id,
            "replacement-card"
        );
    }

    #[test]
    fn dispatch_launch_races_fail_closed_and_roll_back_exact_claim() {
        if !tmux_process_tests_available() {
            eprintln!(
                "dispatch_launch_races_fail_closed_and_roll_back_exact_claim: tmux or node not on PATH - skipping"
            );
            return;
        }
        let shell = dispatch_race_evidence(&["zsh"], 100, 123_456, &[(42, 900), (7, 100)]);
        let accepted = dispatch_race_evidence(
            &[
                "codex",
                "--dangerously-bypass-approvals-and-sandbox",
                "work",
            ],
            200,
            123_456,
            &[(42, 900), (7, 100)],
        );
        let changed_posture = dispatch_race_evidence(
            &["codex", "--sandbox", "workspace-write", "work"],
            200,
            123_456,
            &[(42, 900), (7, 100)],
        );
        let wrapper = dispatch_race_evidence(
            &["sh", "/tmp/codex-wrapper"],
            200,
            123_456,
            &[(42, 900), (7, 100)],
        );
        let changed_ancestry = dispatch_race_evidence(
            &[
                "codex",
                "--dangerously-bypass-approvals-and-sandbox",
                "work",
            ],
            200,
            123_456,
            &[(42, 900), (8, 101), (7, 100)],
        );
        let changed_generation = dispatch_race_evidence(
            &[
                "codex",
                "--dangerously-bypass-approvals-and-sandbox",
                "work",
            ],
            200,
            123_457,
            &[(42, 900), (7, 100)],
        );
        let cases = [
            (
                "provider-exit",
                vec![
                    Ok(shell.clone()),
                    Ok(accepted.clone()),
                    Err(LaunchAttestationError::UnreadableEvidence),
                ],
                "before durable acceptance: provider-native process evidence is unreadable",
            ),
            (
                "posture-change",
                vec![Ok(shell.clone()), Ok(accepted.clone()), Ok(changed_posture)],
                "provider-native permission evidence has the wrong mode",
            ),
            (
                "wrapper-change",
                vec![Ok(shell.clone()), Ok(accepted.clone()), Ok(wrapper)],
                "a wrapper obscures the provider-native foreground process",
            ),
            (
                "ancestry-change",
                vec![
                    Ok(shell.clone()),
                    Ok(accepted.clone()),
                    Ok(changed_ancestry),
                ],
                "provider-native process ancestry changed during launch acceptance",
            ),
            (
                "generation-change",
                vec![
                    Ok(shell.clone()),
                    Ok(accepted.clone()),
                    Ok(changed_generation),
                ],
                "terminal pane generation changed during launch",
            ),
            (
                "post-persistence-exit",
                vec![
                    Ok(shell.clone()),
                    Ok(accepted.clone()),
                    Ok(accepted.clone()),
                    Err(LaunchAttestationError::UnreadableEvidence),
                ],
                "after durable persistence: provider-native process evidence is unreadable",
            ),
        ];

        for (case_name, observations, expected_error) in cases {
            let server = LoopbackPowderServer::start(4);
            let profile_name = format!(
                "dispatch-race-{case_name}-{}",
                uuid::Uuid::new_v4().simple()
            );
            let _profile = PowderProfileEnv::install(&profile_name, server.addr);
            let captain = FakeHarnessSession::start(Harness::Codex);
            let registry = dispatch_test_registry(None, &profile_name, &captain.session_id);
            let (ctx, sink) = dispatch_test_context(registry.clone());
            let mut observations = std::collections::VecDeque::from(observations);
            let mut observer = |_target: &str| {
                observations
                    .pop_front()
                    .expect("dispatch made an unexpected attestation observation")
            };

            let error = dispatch_crew_with_observer(
                &ctx,
                &json!({
                    "captainSessionId": captain.session_id,
                    "cardId": "thub-powder-control-lifecycle",
                    "task": "Reject a launch acceptance race",
                    "harness": "codex",
                    "testHarnessCommand": "sleep 60",
                    "testCodexUnobservedCommand": ":",
                    "testSkipHarnessLiveness": true,
                }),
                None,
                true,
                &mut observer,
            )
            .unwrap_err();

            assert!(error.contains(expected_error), "{case_name}: {error}");
            assert!(error.contains("all side effects were rolled back"));
            assert!(observations.is_empty(), "{case_name}: unused observations");
            let crew_session_id = dispatched_terminal_id(&sink);
            assert_eq!(
                tmux::session_liveness(&tmux_target(&crew_session_id)),
                tmux::SessionLiveness::Gone
            );
            assert!(registry.snapshot().captains[0].crew.is_empty());
            let state = server.finish().unwrap();
            assert_eq!(state.claim_posts, 1);
            assert_eq!(state.release_posts, 1);
            assert_eq!(
                state.release_bodies,
                vec![json!({"run_id": "run-authoritative"})]
            );
        }
    }

